function navigate(route){
  const r = ROUTES[route];
  if(!r){
    // Unknown route — fall back to dashboard rather than throwing.
    console.warn('[navigate] unknown route:', route);
    if(route !== 'dashboard') return navigate('dashboard');
    return;
  }
  // RBAC enforcement: block routes the current role cannot access.
  if(typeof canAccessRoute === 'function' && !canAccessRoute(route)){
    if(typeof toast === 'function'){
      toast('Your role does not have access to that area.', {type:'error', title:'Access denied', duration:4000});
    }
    if(route !== 'dashboard' && canAccessRoute('dashboard')) return navigate('dashboard');
    return;
  }
  APP_STATE.currentRoute = route;
  if(typeof OfflineCore !== 'undefined') OfflineCore.schedulePersist();
  document.querySelectorAll('.nav-item').forEach(n=>n.classList.toggle('active', n.dataset.route===route));
  // Note: we intentionally do NOT auto-expand the active route's group. Every
  // group except Core Services stays collapsed until the user clicks its arrow.
  document.getElementById('crumb-page').textContent = r.title;
  const content = document.getElementById('content');
  content.innerHTML = '';
  r.render(content);
  // Append footer to every page
  if(!content.querySelector('.app-footer')){
    const f = document.createElement('div');
    f.className = 'app-footer';
    f.innerHTML = renderAppFooter();
    content.appendChild(f);
  }
  window.scrollTo(0,0);
}

// Re-render the current route in place without scrolling or resetting state.
// Used after sync drain completes so per-record sync indicators clear.
function rerenderCurrentRoute(){
  const route = APP_STATE.currentRoute;
  if(!route || !ROUTES[route]) return;
  const content = document.getElementById('content');
  if(!content) return;
  const scrollTop = window.scrollY || 0;
  content.innerHTML = '';
  try {
    ROUTES[route].render(content);
    if(!content.querySelector('.app-footer')){
      const f = document.createElement('div');
      f.className = 'app-footer';
      f.innerHTML = renderAppFooter();
      content.appendChild(f);
    }
    window.scrollTo(0, scrollTop);
  } catch(e){
    console.warn('[rerenderCurrentRoute] failed', e);
  }
}

