// ===========================================================================
// UNIVERSAL ACTION HELPERS — wire real behaviour for buttons that previously
// looked interactive but were stubs. These are the single source of truth for
// "Print", "Send via WhatsApp", "Save as draft", row-appenders, etc.
// ===========================================================================

// Print a small formatted document via the browser's print dialog. Uses a
// hidden iframe so we don't disrupt the current page.
function printDocument(title, htmlBody){
  if(typeof document==='undefined' || typeof window==='undefined') return;
  const frame = document.createElement('iframe');
  frame.style.cssText = 'position:fixed;right:0;bottom:0;width:0;height:0;border:0';
  document.body.appendChild(frame);
  const doc = frame.contentDocument || frame.contentWindow.document;
  doc.open();
  doc.write(`<!doctype html><html><head><title>${esc(title)}</title>
    <style>
      body{font-family:Inter,system-ui,sans-serif;color:#2F4A6D;padding:24px;font-size:13px;line-height:1.5}
      h1{font-size:18px;margin:0 0 4px;color:#2F4A6D}
      .sub{color:#6B7C92;font-size:12px;margin-bottom:18px;border-bottom:1px solid #DDE5F0;padding-bottom:12px}
      table{width:100%;border-collapse:collapse;margin:10px 0}
      th,td{padding:6px 8px;border-bottom:1px solid #E8EEF6;text-align:left;font-size:12px}
      th{background:#F4F7FB;font-weight:600;color:#2F4A6D}
      .footer{margin-top:24px;padding-top:12px;border-top:1px solid #DDE5F0;color:#8997AC;font-size:11px}
      .label{color:#6B7C92;font-size:11px;text-transform:uppercase;letter-spacing:0.4px}
      .row{display:flex;justify-content:space-between;margin:4px 0}
      @media print{body{padding:12mm}}
    </style></head><body>${htmlBody}<div class="footer">${esc(title)} · Generated ${new Date().toISOString().slice(0,16).replace('T',' ')} · LabOS by AgoroX</div></body></html>`);
  doc.close();
  setTimeout(()=>{
    try { frame.contentWindow.focus(); frame.contentWindow.print(); }
    catch(e){ /* print blocked; toast still informs */ }
    setTimeout(()=>{ if(frame.parentNode) frame.parentNode.removeChild(frame); }, 1500);
  }, 250);
  if(typeof OfflineCore!=='undefined'){ OfflineCore.record('print', {title}, `Printed: ${title}`); OfflineCore.schedulePersist(); }
  toast(`Print dialog opened for ${title}.`, {type:'info', title:'Print', duration:3500});
}

// Generic print dispatcher used by modal "Print" buttons. Inspects the open
// modal for a title and any visible form fields to build a printable summary.
function genericPrint(kind){
  const modal = document.querySelector('.modal');
  const title = (modal && modal.querySelector('.modal-title')) ? modal.querySelector('.modal-title').textContent.trim() : (kind||'Document');
  const sub = (modal && modal.querySelector('.modal-header .muted-sm')) ? modal.querySelector('.modal-header .muted-sm').textContent.trim() : '';
  const rows = [];
  if(modal){
    modal.querySelectorAll('input[id], textarea[id], select[id]').forEach(el => {
      const labelEl = el.previousElementSibling && el.previousElementSibling.classList && el.previousElementSibling.classList.contains('label') ? el.previousElementSibling : null;
      const label = labelEl ? labelEl.textContent.trim() : el.id;
      const val = (el.type==='checkbox') ? (el.checked?'Yes':'No') : el.value;
      if(val) rows.push({label, val});
    });
  }
  const body = `<h1>${esc(title)}</h1>
    <div class="sub">${esc(sub||kind||'')}</div>
    ${rows.length ? `<table><tr><th>Field</th><th>Value</th></tr>${rows.map(r=>`<tr><td>${esc(r.label)}</td><td>${esc(r.val)}</td></tr>`).join('')}</table>`
      : '<p style="color:#6B7C92">No structured form data on this screen. The production document carries the full record.</p>'}`;
  printDocument(title, body);
}

// Queue a WhatsApp / SMS message via the notifications queue we already built.
// Uses the patient's phone and the current tenant's integration settings.
function sendViaChannel(channel, patient, body, opts){
  opts = opts || {};
  if(!patient){ toast('No recipient selected.', {type:'error', title:'Required'}); return; }
  const t = (typeof currentTenant==='function') ? currentTenant() : null;
  const integ = (t && t.integrations) || {};
  const hasProvider = (channel==='sms'||channel==='whatsapp') ? !!(integ.termii && integ.termii.apiKey)
                    : channel==='email' ? !!(integ.smtp && integ.smtp.host) : true;
  const notes = APP_STATE.notifications || (APP_STATE.notifications = []);
  const id = `MSG-${new Date().getFullYear()}-${String(notes.length+1).padStart(4,'0')}`;
  const recipient = channel==='email' ? (patient.email||'(no email)') : (patient.phone||'(no phone)');
  notes.unshift({
    id, channel, recipient, patientId:patient.id,
    template: opts.template || 'Custom',
    body: body || '',
    status:'queued', sentAt:null, queuedAt:new Date().toISOString(),
    providerReady: hasProvider
  });
  if(typeof OfflineCore!=='undefined'){
    OfflineCore.record('notification.queue', {id, channel, patientId:patient.id}, `Queued ${channel.toUpperCase()} to ${patient.name||patient.id} — ${opts.template||'message'}`);
    OfflineCore.schedulePersist();
  }
  const lbl = channel.toUpperCase();
  if(!hasProvider){
    toast(`Queued, but ${lbl} provider isn't configured yet — set it up in Integrations.`, {type:'warn', title:id, duration:6500});
  } else {
    toast(`Queued ${lbl} → ${recipient}`, {type:'success', title:id, duration:4000});
  }
}

// Save a draft of a modal's current values. Reads any input/textarea/select
// with an id inside the open modal and stores them under APP_STATE.drafts.
function saveAsDraft(kind){
  const modal = document.querySelector('.modal');
  if(!modal){ toast('No active form to save.', {type:'warn'}); return; }
  const fields = {};
  modal.querySelectorAll('input[id], textarea[id], select[id]').forEach(el => {
    if(el.type==='checkbox' || el.type==='radio') fields[el.id] = el.checked;
    else fields[el.id] = el.value;
  });
  const drafts = APP_STATE.drafts || (APP_STATE.drafts = {});
  const list = drafts[kind] || (drafts[kind] = []);
  const draftId = `DRAFT-${kind}-${Date.now().toString(36)}`;
  list.unshift({id:draftId, savedAt:new Date().toISOString(), fields});
  // cap retained drafts per kind to avoid unbounded growth
  if(list.length > 20) list.length = 20;
  if(typeof OfflineCore!=='undefined'){
    OfflineCore.record('draft.save', {kind, draftId, fieldCount:Object.keys(fields).length}, `Draft saved (${kind}, ${Object.keys(fields).length} fields)`);
    OfflineCore.schedulePersist();
  }
  toast(`Draft saved — you can resume from the ${kind} screen.`, {type:'success', title:'Saved', duration:3500});
  closeModal();
}

// Modal-context helpers — used by previously-decorative buttons that live
// inside imaging / DNA / package / etc. detail modals where the order id is
// in window.MODAL_CTX. They resolve the order, then perform the real action.

function _modalCtxOrder(){
  const ctx = window.MODAL_CTX || {};
  if(!ctx.id) return null;
  // try each known worklist by prefix
  const pools = ['imagingOrders','dnaOrders','packageOrders','requests','molecularTests','molecularOrders','histopathCases','microbiologyResults','sequencingRuns','bioinformaticsJobs'];
  for(const k of pools){
    const arr = APP_STATE[k]; if(!arr) continue;
    const hit = arr.find(x=>x.id===ctx.id);
    if(hit) return {pool:k, record:hit};
  }
  return null;
}

function sendCurrentModalToWhatsApp(){
  const found = _modalCtxOrder();
  if(!found){ toast('No order context — open an order first.', {type:'warn'}); return; }
  const o = found.record;
  const patient = (APP_STATE.patients||[]).find(p=>p.id===o.patientId) || {id:o.patientId, name:o.patient||'Patient', phone:o.phone||''};
  const t = currentTenant();
  const lab = t ? t.name : 'your lab';
  const body = `Hello ${patient.name}, your ${o.study||o.test||o.package||'result'} from ${lab} is ready. Please check the patient portal or visit the lab.`;
  sendViaChannel('whatsapp', patient, body, {template:'Result ready'});
}

function exportPurchaseOrdersCsv(){
  const pos = APP_STATE.purchaseOrders || [];
  const header = ['poId','supplier','status','total','issuedAt','expectedAt','items'];
  const escapeCsv = v => { const s = String(v==null?'':v); return /[",\n]/.test(s) ? `"${s.replace(/"/g,'""')}"` : s; };
  const rows = pos.map(p => header.map(h => {
    if(h==='items') return escapeCsv((p.items||[]).length);
    return escapeCsv(p[h]||'');
  }).join(','));
  const csv = [header.join(','), ...rows].join('\n');
  try {
    const blob = new Blob([csv], {type:'text/csv;charset=utf-8;'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `purchase-orders-${new Date().toISOString().slice(0,10)}.csv`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(()=>URL.revokeObjectURL(url), 1000);
  } catch(e){}
  if(typeof OfflineCore!=='undefined'){ OfflineCore.record('po.export', {count:pos.length}, `Exported ${pos.length} POs to CSV`); OfflineCore.schedulePersist(); }
  toast(`Exported ${pos.length} purchase order${pos.length===1?'':'s'} to CSV.`, {type:'success', title:'Export', duration:4000});
}

function toggleManualEntry(){
  // Find the modal's primary form table/area and toggle a "manual-mode" class
  // that callers can react to. Most modals that show this button have a
  // panel/table for the standard flow; we surface a manual textarea instead.
  const modal = document.querySelector('.modal');
  if(!modal){ toast('No active form', {type:'warn'}); return; }
  let area = modal.querySelector('#manual-entry-area');
  if(area){ area.remove(); toast('Returned to guided entry.', {type:'info'}); return; }
  area = document.createElement('div');
  area.id = 'manual-entry-area';
  area.style.cssText = 'margin:14px 0;padding:12px;background:var(--bg-soft);border:1px dashed var(--line);border-radius:6px';
  area.innerHTML = `<label class="label">Manual entry (free-text)</label>
    <textarea class="input" id="manual-entry-text" rows="5" placeholder="Enter values one per line (key: value)…"></textarea>
    <div class="muted-sm" style="margin-top:6px">Manual mode is for offline or unusual workflows — values bypass guided validation.</div>`;
  const body = modal.querySelector('.modal-body') || modal;
  body.insertBefore(area, body.firstChild);
  toast('Switched to manual entry. Type or paste values, then submit.', {type:'info', duration:4500});
}

function openRescheduleFromModal(){
  const found = _modalCtxOrder();
  if(!found){ toast('No order to reschedule.', {type:'warn'}); return; }
  const o = found.record;
  const cur = o.scheduledAt || '';
  const next = prompt(`Reschedule ${o.id} to (YYYY-MM-DD HH:MM):`, cur);
  if(!next || next === cur) return;
  o.scheduledAt = next;
  if(typeof OfflineCore!=='undefined'){
    OfflineCore.record('order.reschedule', {id:o.id, from:cur, to:next}, `${o.id} rescheduled to ${next}`);
    OfflineCore.schedulePersist();
  }
  toast(`${o.id} rescheduled to ${next}.`, {type:'success', title:'Rescheduled'});
  closeModal();
}

function updatePackageProgressFromModal(){
  const found = _modalCtxOrder();
  if(!found){ toast('No package to update.', {type:'warn'}); return; }
  const o = found.record;
  const total = o.totalItems || 0;
  const done = o.completedItems || 0;
  if(done >= total){ toast('All items already complete.', {type:'info'}); return; }
  o.completedItems = Math.min(total, done + 1);
  if(typeof OfflineCore!=='undefined'){
    OfflineCore.record('package.progress', {id:o.id, completed:o.completedItems, total}, `${o.id} progress: ${o.completedItems}/${total}`);
    OfflineCore.schedulePersist();
  }
  toast(`Progress updated: ${o.completedItems}/${total} items complete.`, {type:'success', title:o.id});
  closeModal();
}

