// Populate the inline test-search dropdown for a new invoice line.
function invTestSearch(input){
  const q = (input.value||'').toLowerCase().trim();
  const list = input.parentElement.querySelector('.inv-test-list');
  if(!list) return;

  // Flatten the test catalogue into a searchable array.
  const all = [];
  const cat = APP_STATE.testCatalog || {};
  Object.entries(cat).forEach(([cat_name, tests])=>{
    (tests||[]).forEach(t=>{ if(t && t.code) all.push(t); });
  });

  if(!q){ list.style.display='none'; return; }
  const hits = all.filter(t=>
    (t.name||'').toLowerCase().includes(q) ||
    (t.code||'').toLowerCase().includes(q)
  ).slice(0,10);

  if(!hits.length){
    list.innerHTML=`<li style="padding:8px 12px;color:var(--ink-soft);pointer-events:none">No tests matched "${esc(q)}"</li>`;
    list.style.display='block'; return;
  }
  list.innerHTML = hits.map(t=>{
    const price = getPrice(t.code);
    return `<li data-code="${esc(t.code)}" data-name="${esc(t.name)}" data-price="${price}"
      style="padding:7px 12px;cursor:pointer;display:flex;justify-content:space-between;align-items:center"
      onmousedown="invTestPick(this)"
      onmouseover="this.style.background='var(--bg-soft)'" onmouseout="this.style.background=''">
      <span><b>${esc(t.code)}</b> <span style="color:var(--ink-soft)">${esc(t.name)}</span></span>
      <span style="font-variant-numeric:tabular-nums;color:var(--ink-soft);margin-left:8px">${naira(price)}</span>
    </li>`;
  }).join('');
  list.style.display='block';
}

// Arrow-key navigation + Enter to select in the inline test dropdown.
function invTestKey(evt, input){
  const list = input.parentElement.querySelector('.inv-test-list');
  if(!list || list.style.display==='none') return;
  const items = [...list.querySelectorAll('li[data-code]')];
  if(!items.length) return;
  const cur = list.querySelector('li[data-active="1"]');
  let idx = cur ? items.indexOf(cur) : -1;
  if(evt.key==='ArrowDown'){
    evt.preventDefault();
    if(cur){ cur.removeAttribute('data-active'); cur.style.background=''; }
    idx = Math.min(idx+1, items.length-1);
    items[idx].setAttribute('data-active','1'); items[idx].style.background='var(--bg-soft)';
    items[idx].scrollIntoView({block:'nearest'});
  } else if(evt.key==='ArrowUp'){
    evt.preventDefault();
    if(cur){ cur.removeAttribute('data-active'); cur.style.background=''; }
    idx = Math.max(idx-1, 0);
    items[idx].setAttribute('data-active','1'); items[idx].style.background='var(--bg-soft)';
    items[idx].scrollIntoView({block:'nearest'});
  } else if(evt.key==='Enter' && idx>=0){
    evt.preventDefault();
    items[idx].dispatchEvent(new MouseEvent('mousedown'));
  } else if(evt.key==='Escape'){
    list.style.display='none';
  }
}

// Confirm the selected test: update the row cells and trigger recalculation.
function invTestPick(li){
  const row = li.closest('tr');
  if(!row) return;
  const price = parseFloat(li.dataset.price)||0;
  const code  = li.dataset.code||'';
  const name  = li.dataset.name||'';
  const searchInput = row.querySelector('.inv-test-search');
  const qtyInput    = row.querySelector('.inv-qty');
  const unitCell    = row.querySelector('.inv-unit');
  const amtCell     = row.querySelector('.inv-amt');
  const list        = row.querySelector('.inv-test-list');
  if(searchInput){ searchInput.value = `${code} — ${name}`; }
  if(qtyInput){ qtyInput.dataset.unit = price; qtyInput.disabled = false; qtyInput.value = 1; }
  if(unitCell) unitCell.textContent = price.toLocaleString();
  if(amtCell)  amtCell.textContent  = price.toLocaleString();
  if(list)     list.style.display   = 'none';
  invRecalc();
}

