function submitManageTrial(){
  const t = currentTenant(); if(!t) return;
  const action = $v('mt-action');
  const s = t.subscription;
  if(action==='convert'){
    s.status = 'ACTIVE';
    s.trialEndsAt = null;
    OfflineCore.record('subscription.convert', {tenantId:t.id}, `Trial converted to paid — ${t.name}`);
    toast('Trial converted to paid. Subscription is now ACTIVE.', {type:'success', title:'Converted'});
  } else if(action==='extend'){
    OfflineCore.record('subscription.extend.request', {tenantId:t.id}, `Trial extension requested — ${t.name}`);
    toast('Extension request sent to AgoroX support.', {type:'info', title:'Requested'});
  } else if(action==='cancel'){
    s.status = 'CANCELLED';
    OfflineCore.record('subscription.cancel', {tenantId:t.id}, `Trial cancelled — ${t.name}`);
    toast('Trial cancelled. Account moves to read-only after the trial period.', {type:'warn', title:'Cancelled'});
  }
  OfflineCore.schedulePersist();
  closeModal();
  if(APP_STATE.currentRoute==='subscription') navigate('subscription');
}
function retryPayment(){
  const t = currentTenant(); if(!t || !t.subscription) return;
  const s = t.subscription;
  s.retryAttempts = (s.retryAttempts||0) + 1;
  s.lastRetryAt = new Date().toISOString();
  OfflineCore.record('subscription.retry', {tenantId:t.id, attempt:s.retryAttempts}, `Payment retry #${s.retryAttempts} — ${t.name}`);
  OfflineCore.schedulePersist();
  toast(`Payment retry #${s.retryAttempts} queued. In production this hits the Paystack charge endpoint.`, {type:'info', title:'Retrying'});
}
function payOutstanding(){
  const t = currentTenant(); if(!t || !t.subscription) return;
  const s = t.subscription;
  const integ = (t.integrations && t.integrations.paystack) || {};
  if(!integ.publicKey){
    toast('Set up Paystack in Integrations first to take a real payment.', {type:'warn', title:'Paystack not configured', duration:6000});
    return;
  }
  s.status = 'ACTIVE';
  OfflineCore.record('subscription.settle', {tenantId:t.id}, `Outstanding balance paid — ${t.name}`);
  OfflineCore.schedulePersist();
  toast('Payment received. Account restored to ACTIVE.', {type:'success', title:'Paid'});
  if(APP_STATE.currentRoute==='subscription') navigate('subscription');
}
