function verifyPlatformAuditChain(){
  const rows = APP_STATE.platformAudit || APP_STATE.audit || [];
  // Simulate a hash-chain check: each row's prevHash should equal previous row's hash.
  // Real implementation would re-hash each row server-side.
  let broken = 0;
  for(let i=1;i<rows.length;i++){
    const cur = rows[i], prev = rows[i-1];
    if(cur.prevHash && prev.hash && cur.prevHash !== prev.hash) broken++;
  }
  if(broken === 0){
    toast(`Chain integrity verified — ${rows.length} entries, no breaks.`, {type:'success', title:'Verified ✓', duration:5000});
  } else {
    toast(`Chain integrity FAILED — ${broken} broken link${broken===1?'':'s'} of ${rows.length}. Escalate to security.`, {type:'error', title:'Tamper detected', duration:8000});
  }
  OfflineCore.record('platform.audit.verify', {rows:rows.length, broken}, `Platform audit chain verified — ${broken} breaks`);
  OfflineCore.schedulePersist();
}
function exportPlatformAuditCsv(){
  const rows = APP_STATE.platformAudit || APP_STATE.audit || [];
  const header = ['time','user','action','ip','hash','prevHash'];
  const escapeCsv = v => { const s = String(v==null?'':v); return /[",\n]/.test(s) ? `"${s.replace(/"/g,'""')}"` : s; };
  const lines = [header.join(','), ...rows.map(r => header.map(h => escapeCsv(r[h]||'')).join(','))];
  try {
    const blob = new Blob([lines.join('\n')], {type:'text/csv;charset=utf-8;'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `platform-audit-${new Date().toISOString().slice(0,10)}.csv`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(()=>URL.revokeObjectURL(url), 1000);
  } catch(e){}
  OfflineCore.record('platform.audit.export', {rows:rows.length}, `Platform audit exported (${rows.length} rows)`);
  OfflineCore.schedulePersist();
  toast(`Exported ${rows.length} platform audit entries.`, {type:'success'});
}

// Append a row to a form-builder container. The container holds N child
// elements rendered from a template; this clones the first child and clears
// its values, then adds a remove handler.
function appendFormRow(containerId, templateHtml){  const wrap = document.getElementById(containerId);
  if(!wrap){ toast('Container not found', {type:'error'}); return null; }
  const row = document.createElement('div');
  row.innerHTML = templateHtml.trim();
  const node = row.firstElementChild;
  if(!node) return null;
  // give it a remove affordance if not already present
  if(!node.querySelector('.row-remove')){
    const x = document.createElement('button');
    x.type = 'button';
    x.className = 'btn-link row-remove';
    x.style.cssText = 'position:absolute;top:4px;right:6px;color:#9A1F1F;font-size:11px';
    x.textContent = '× Remove';
    x.onclick = () => node.remove();
    node.style.position = node.style.position || 'relative';
    node.appendChild(x);
  }
  wrap.appendChild(node);
  return node;
}

function chip(status){
  const map = {
    pending:'Pending',
    awaiting_payment:'Awaiting payment',
    collected:'Sample collected',
    progress:'In progress',
    review:'Awaiting review',
    completed:'Completed',
    released:'Released',
    rejected:'Rejected',
    critical:'Critical',
    paid:'Paid',
    unpaid:'Unpaid',
    partial:'Partial'
  };
  return `<span class="status ${status}">${map[status]||status}</span>`;
}

