// State for the Patients page filter controls. Lives outside renderPatients so
// switching pages and coming back preserves the user's filter selection.
const PATIENTS_FILTER_STATE = {
  search:'', gender:'all', category:'all', insurance:'all'
};

function setPatientsFilter(field, value){
  PATIENTS_FILTER_STATE[field] = value;
  // Re-render only the table body to avoid losing input focus on the search box
  const tbody = document.getElementById('patients-tbody');
  const meta  = document.getElementById('patients-meta');
  const filtered = filteredPatients();
  if(meta) meta.textContent = `${filtered.length} of ${APP_STATE.patients.length} patient${APP_STATE.patients.length===1?'':'s'} · Ikeja Main`;
  if(tbody){
    if(filtered.length === 0){
      tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;padding:32px;color:var(--ink-soft)">
        No patients match these filters.
        <a onclick="resetPatientsFilters()" style="color:var(--info-ink);cursor:pointer;margin-left:8px">Clear filters</a>
      </td></tr>`;
    } else {
      tbody.innerHTML = filtered.map(p => patientRow(p)).join('');
    }
  }
}

function resetPatientsFilters(){
  PATIENTS_FILTER_STATE.search = '';
  PATIENTS_FILTER_STATE.gender = 'all';
  PATIENTS_FILTER_STATE.category = 'all';
  PATIENTS_FILTER_STATE.insurance = 'all';
  // Full re-render to refresh the input + selects to their defaults
  navigate('patients');
}

function filteredPatients(){
  const f = PATIENTS_FILTER_STATE;
  const q = (f.search || '').trim().toLowerCase();
  return (APP_STATE.patients || []).filter(p => {
    // Search: name, phone, hospital number, patient ID
    if(q){
      const hay = `${p.name||''} ${p.phone||''} ${p.hospitalNo||''} ${p.id||''}`.toLowerCase();
      if(!hay.includes(q)) return false;
    }
    // Gender exact match (handles missing gender by excluding it)
    if(f.gender !== 'all'){
      if((p.gender || '') !== f.gender) return false;
    }
    // Category: General = not renal, Renal = renal flag true
    if(f.category === 'General' && p.renal) return false;
    if(f.category === 'Renal' && !p.renal) return false;
    // Insurance: NHIS / Self-pay are exact; HMO matches any branded HMO name
    if(f.insurance === 'NHIS' && (p.insurance || '') !== 'NHIS') return false;
    if(f.insurance === 'Self-pay' && (p.insurance || '') !== 'Self-pay') return false;
    if(f.insurance === 'HMO'){
      const ins = p.insurance || '';
      if(ins === 'NHIS' || ins === 'Self-pay' || ins === '') return false;
    }
    return true;
  });
}

// Build a single patient row (extracted so setPatientsFilter can re-render just the tbody)
function patientRow(p){
  return `<tr onclick="openPatientDetail('${esc(p.id)}')">
    <td class="mono">${esc(p.id)}${syncDot(p.id)}</td>
    <td><b>${esc(p.name)}</b><div style="font-size:11px;color:var(--ink-faint)">${esc(p.hospitalNo)}</div></td>
    <td>${esc(p.age||'')} · ${esc((p.gender||'?').charAt(0))}</td>
    <td>${esc(p.phone)}</td>
    <td>${esc(p.insurance)}</td>
    <td>${esc(p.registered)}</td>
    <td>${p.renal?'<span class="pill renal">Renal</span>':'<span class="pill">General</span>'} <span class="pill">${esc(p.bloodGroup||'?')}</span></td>
  </tr>`;
}

