function submitEditPatient(id){
  if(!requireLicensed('edit a patient')) return;
  const p = (APP_STATE.patients||[]).find(x=>x.id===id);
  if(!p){ toast('Patient not found', {type:'error'}); return; }
  const val = k => { const e = document.getElementById(k); return e ? e.value.trim() : undefined; };
  const setIf = (k, v) => { if(v!==undefined) p[k] = v; };
  setIf('name', val('ep-name'));
  setIf('phone', val('ep-phone'));
  setIf('email', val('ep-email'));
  setIf('address', val('ep-address'));
  setIf('bloodGroup', val('ep-blood'));
  setIf('genotype', val('ep-geno'));
  setIf('nextOfKin', val('ep-kin'));
  OfflineCore.record('patient.edit', {id}, `Patient updated — ${p.name}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast('Patient updated.', {type:'success', title:'Saved'});
  if(APP_STATE.currentRoute==='patient-detail' || document.body.innerHTML.includes(p.id)) openPatientDetail(id);
}

