function submitAddReferralPartner(){
  if(!requireLicensed('add a referral partner')) return;
  const name = $v('rp-pname'); if(!name){ toast('Partner name required', {type:'error'}); return; }
  const partner = {
    name, country:$v('rp-pcountry')||'—', specialties:$v('rp-pspec')||'—',
    sla:$v('rp-psla')||'—', courier:$v('rp-pcourier')||'—',
    contact:$v('rp-pcontact')||'—', activeAccessions:0
  };
  APP_STATE.referralPartners = APP_STATE.referralPartners || [];
  APP_STATE.referralPartners.push(partner);
  OfflineCore.record('partner.add', {name}, `Referral partner added: ${name}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`Partner added: ${name}`, {type:'success', title:'Added'});
  if(APP_STATE.currentRoute==='referralPartners' || document.body.innerHTML.includes('Referral partners')) navigate(APP_STATE.currentRoute);
}

