function updateMolMode(val){
  const opt = document.querySelector('#modal-root option[value="'+val+'"]') || event?.target?.selectedOptions?.[0];
  const selected = event.target.selectedOptions[0];
  const mode = selected.dataset.mode;
  const platform = selected.dataset.platform;
  const price = selected.dataset.price;
  const cost = selected.dataset.cost;
  const preview = document.getElementById('mol-route-preview');
  preview.innerHTML = `
    <div style="display:flex;justify-content:space-between"><span class="muted-sm">Mode</span><strong>${mode==='in_house'?'In-house':'Send-out to partner'}</strong></div>
    <div style="display:flex;justify-content:space-between;margin-top:4px"><span class="muted-sm">${mode==='in_house'?'Platform':'Partner'}</span><strong>${platform}</strong></div>
    <div style="display:flex;justify-content:space-between;margin-top:4px"><span class="muted-sm">Patient charged</span><strong>₦${Number(price).toLocaleString('en-NG')}</strong></div>
    ${cost?`<div style="display:flex;justify-content:space-between;margin-top:4px"><span class="muted-sm">Lab cost</span><strong>₦${Number(cost).toLocaleString('en-NG')}</strong></div>
    <div style="display:flex;justify-content:space-between;margin-top:4px;color:#1B6B3A"><span>Margin</span><strong>₦${(Number(price)-Number(cost)).toLocaleString('en-NG')}</strong></div>`:''}
  `;
}

// ---- Molecular Diagnostics slice: create a real molecular order ----
function submitMolecularOrder(){
  if(!requireLicensed('create a molecular order')) return;
  if(pcRequire('mol-patient','patient')) return;
  const patientId = pcPatient('mol-patient')?.id;
  const patient = (APP_STATE.patients||[]).find(p=>p.id===patientId);
  if(!patient){ toast('Select a patient', {type:'error', title:'Required'}); return; }
  const testSel = document.getElementById('mol-test');
  const opt = testSel ? testSel.selectedOptions[0] : null;
  if(!opt){ toast('Select a test', {type:'error', title:'Required'}); return; }
  const mode = opt.dataset.mode;
  const platform = opt.dataset.platform;
  const price = Number(opt.dataset.price) || 0;
  const cost = opt.dataset.cost ? Number(opt.dataset.cost) : null;
  const testName = opt.textContent.split(' · ')[0];
  const priority = $v('mol-priority') || 'Routine';
  const n = (APP_STATE.molecularTests||[]).length + 43;
  const id = `MOL-2026-${String(n).padStart(4,'0')}`;
  const now = new Date();
  const due = new Date(now.getTime() + (mode==='send_out'?14:1)*86400000);
  const order = {
    id, patient:patient.name, patientId:patient.id, test:testName,
    mode, platform: mode==='send_out'?`Partner: ${platform}`:platform,
    received: now.toISOString().slice(0,16).replace('T',' '),
    priority, status: mode==='send_out'?'awaiting_dispatch':'received',
    dueBy: due.toISOString().slice(0,10), amount: price,
    partner: mode==='send_out'?platform:null, partnerAccession:null,
    indication: $v('mol-indication')||'', critical:false,
    ...(cost!=null?{costToLab:cost}:{})
  };
  APP_STATE.molecularTests = APP_STATE.molecularTests || [];
  APP_STATE.molecularTests.unshift(order);
  OfflineCore.record('molecular.order', {id, patientId:patient.id, mode}, `${id} molecular order — ${testName}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`Molecular order created — ${testName} · ${mode==='send_out'?'send-out to '+platform:platform}.`, {type:'success', title:id, duration:5000});
  if(APP_STATE.currentRoute === 'molecular') navigate('molecular');
}

// ---- DNA & Genetics slice: create a real DNA order ----
function addDnaSubject(){
  const wrap = document.getElementById('dna-subjects');
  if(!wrap) return;
  const n = wrap.querySelectorAll('.form-grid').length + 1;
  const row = document.createElement('div');
  row.className = 'form-grid';
  row.style.cssText = 'margin-bottom:10px;padding:10px;background:var(--bg-soft);border-radius:6px;position:relative';
  row.innerHTML = `
    <div class="field"><label>Subject ${n} — full name</label><input id="dna-subject${n}" placeholder="Full legal name as on ID"></div>
    <div class="field"><label>Relationship</label>
      <select><option>Child</option><option>Sibling ${n}</option><option>Alleged father</option><option>Alleged mother</option><option>Applicant</option><option>Self</option><option>—</option></select>
    </div>
    <button type="button" class="btn-link danger" style="position:absolute;top:6px;right:8px;font-size:11px" onclick="this.closest('.form-grid').remove()">Remove</button>`;
  wrap.appendChild(row);
}

function submitDnaOrder(){
  if(!requireLicensed('create a DNA order')) return;
  const testSel = document.getElementById('dna-test-select');
  const testName = testSel && testSel.value && !testSel.value.startsWith('—') ? testSel.value : null;
  const category = $v('dna-category-select') || '';
  const subject1 = ($v('dna-subject1')||'').trim();
  if(!category){ toast('Pick a test category', {type:'error', title:'Required'}); return; }
  if(!testName){ toast('Pick a test', {type:'error', title:'Required'}); return; }
  if(!subject1){ toast('Enter at least subject 1', {type:'error', title:'Required'}); return; }
  const requestedBy = $v('dna-requestedby') || 'Self-referred';
  const priority = ($v('dna-priority')||'Routine').replace(/ \(.*\)| —.*/,'');
  // Legal-grade categories enforce chain of custody.
  const legalGrade = /legal|immigration|forensic/i.test(category);
  const n = (APP_STATE.dnaOrders||[]).length + 190;
  const id = `DNA-2026-${String(n).padStart(5,'0')}`;
  const order = {
    id, patient: subject1, primarySubject:null, test:testName, code:'DNA-NEW',
    category, status:'awaiting_collection', chainOfCustody:legalGrade, legalGrade,
    priority, requestedBy, requestedAt:new Date().toISOString().slice(0,16).replace('T',' '),
    collectedAt:null, shippedAt:null, resultedAt:null, amount:0, paid:'unpaid',
    samples:[{label:`Subject 1 · ${subject1}`, collected:null}],
    clinical: $v('dna-clinical')||''
  };
  APP_STATE.dnaOrders = APP_STATE.dnaOrders || [];
  APP_STATE.dnaOrders.unshift(order);
  OfflineCore.record('dna.order', {id, category, legalGrade}, `${id} DNA order — ${testName}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`DNA order created${legalGrade?' (legal-grade, chain-of-custody enforced)':''}. Routed to cashier and DNA collection officer.`, {type:'success', title:id, duration:5000});
  if(APP_STATE.currentRoute === 'dna') navigate('dna');
}

