// Show/hide the recurrence section when Dialysis is selected.
function aptTypeChange(){
  const type = (document.getElementById('apt-type')||{}).value || '';
  const sec  = document.getElementById('apt-recurrence-section');
  if(sec) sec.style.display = type === 'Dialysis session' ? '' : 'none';
  // Auto-set sensible duration defaults per type.
  const dur = document.getElementById('apt-duration');
  if(!dur) return;
  const durationMap = {
    'Routine phlebotomy':'15 min','Fasting blood collection':'15 min',
    'ECG (Electrocardiogram)':'15 min','Report collection / result pickup':'15 min',
    'NDLEA / drug screening':'15 min','Swab / culture collection':'15 min',
    'Timed sample (2hr PP / GTT)':'2 hrs',
    'Dialysis session':'4 hrs','Physiotherapy':'45 min',
    'Endoscopy':'1 hr','MRI':'1 hr','CT Scan':'45 min',
    'Annual / executive health check':'2 hrs','Corporate group screening':'Full day',
    'Pre-employment / fitness-for-work medical':'2 hrs',
  };
  if(durationMap[type]) dur.value = durationMap[type];
}

function submitAppointment(statusArg){
  if(!requireLicensed('book an appointment')) return;
  if(pcRequire('apt-patient','patient')) return;
  const patient = pcPatient('apt-patient');
  const type = $v('apt-type');
  if(!type){ toast('Select an appointment type',{type:'error',title:'Required'}); return; }
  const date = $v('apt-date');
  if(!date){ toast('Select a date',{type:'error',title:'Required'}); return; }
  const appts=APP_STATE.appointments||(APP_STATE.appointments=[]);
  const id=`APT-2026-${String(appts.length+43).padStart(4,'0')}`;
  const status = statusArg || 'scheduled';
  appts.unshift({
    id,
    patient: patient.name, patientId: patient.id,
    type,
    priority: $v('apt-priority') || 'Routine',
    duration: $v('apt-duration') || '30 min',
    provider: $v('apt-provider') || 'TBA',
    referringDoctor: $v('apt-referring'),
    centre: $v('apt-centre'),
    room: $v('apt-room'),
    date, time: $v('apt-time'),
    insurance: $v('apt-insurance') || 'Self-pay',
    remindVia: $v('apt-remind') || 'SMS',
    notes: $v('apt-notes'),
    recurrence: $v('apt-recur-freq') || null,
    recurrenceEnd: $v('apt-recur-end') || null,
    status
  });
  OfflineCore.record('appointment.book',{id,status},`${id} ${type} booked — ${patient.name}`);
  OfflineCore.schedulePersist();
  closeModal();
  const label = status === 'confirmed' ? 'confirmed' : 'booked';
  toast(`Appointment ${id} ${label}.`,{type:'success',title:id,duration:4500});
  if(APP_STATE.currentRoute==='appointments') navigate('appointments');
}

const NOT_STATUS = {delivered:'completed', queued:'pending', failed:'cancelled', sent:'progress'};
/* ==========================================================
   QUALITY CONTROL — Levey-Jennings charts (ISO 15189 / CLIA)
   ========================================================== */
function renderQualityControl(root){
  const analytes = window.QC_ANALYTES || [];
  const runs     = window.QC_RUNS     || {};
  const qc       = window.QC;

  const summaryCards = analytes.map(a => {
    const pts = (runs[a.code] || []).slice(0,30);
    if(!pts.length) return '';
    const ev  = qc.evaluate([...pts].reverse());
    const cv  = qc.cv(pts);
    const bias= qc.bias(pts, a.target);
    const statusColor = ev.status==='reject'?'#9A1F1F':ev.status==='warning'?'#C77B14':'#1F7A4D';
    const statusLabel = ev.status==='reject'?'⛔ REJECT':ev.status==='warning'?'⚠ WARNING':'✓ In control';
    const latestZ = pts[0] ? pts[0].z : null;
    return `
      <div class="card" style="cursor:pointer;border-left:4px solid ${statusColor}" onclick="renderQcDetail(document.getElementById('content'),'${esc(a.code)}')">
        <div style="display:flex;justify-content:space-between;align-items:flex-start">
          <div>
            <div style="font-weight:600;font-size:14px">${esc(a.name)}</div>
            <div class="muted-sm">${esc(a.instrument)} · ${esc(a.level)}</div>
            <div class="muted-sm" style="margin-top:2px">Lot: ${esc(a.lot)}</div>
          </div>
          <span style="font-size:12px;font-weight:600;color:${statusColor};background:${statusColor}18;padding:3px 10px;border-radius:20px">${statusLabel}</span>
        </div>
        <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-top:14px;font-size:12px;text-align:center">
          <div style="background:var(--bg-soft);border-radius:6px;padding:8px">
            <div style="font-weight:700;font-size:16px">${a.target} ${a.unit}</div><div class="muted-sm">Target</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:8px">
            <div style="font-weight:700;font-size:16px">${cv !== null ? cv+'%' : '—'}</div><div class="muted-sm">%CV</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:8px">
            <div style="font-weight:700;font-size:16px;color:${Math.abs(bias||0)>3?'#C77B14':'inherit'}">${bias !== null ? (bias>0?'+':'')+bias+'%' : '—'}</div><div class="muted-sm">Bias</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:8px">
            <div style="font-weight:700;font-size:16px;color:${Math.abs(latestZ||0)>2?statusColor:'inherit'}">${latestZ !== null ? (latestZ>0?'+':'')+latestZ : '—'}</div><div class="muted-sm">Latest z</div></div>
        </div>
        ${ev.violations.length ? `<div class="alert-banner ${ev.status==='reject'?'danger':'warn'}" style="margin-top:10px;padding:8px 12px">
          <span class="icon">${ev.status==='reject'?'⛔':'⚠'}</span>
          <div style="font-size:12px"><b>${ev.violations.length} violation${ev.violations.length>1?'s':''}</b>: ${ev.violations.map(v=>v.rule).join(', ')} — ${ev.violations[0].description}</div>
        </div>` : ''}
      </div>`;
  }).join('');

  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title">Quality Control</div>
        <div class="page-subtitle">${analytes.length} analytes · Westgard multi-rule · ISO 15189 compliant</div>
      </div>
      <div class="actions">
        <button class="btn primary" onclick="openQcRun()">+ Log QC run</button>
      </div>
    </div>
    <div class="alert-banner info" style="margin-bottom:20px">
      <span class="icon">ℹ</span>
      <div style="font-size:12.5px">Westgard rules applied: <b>1₂s</b> (warning), <b>1₃s / 2₂s / R₄s / 4₁s / 10ₓ</b> (reject), <b>7T</b> (trend warning).
      A rejected QC run blocks patient result release until the root cause is resolved and QC is re-run within spec.</div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:16px">
      ${summaryCards}
    </div>`;
}

function renderQcDetail(root, code){
  const analyte = (window.QC_ANALYTES||[]).find(a=>a.code===code);
  if(!analyte){ navigate('qualityControl'); return; }
  const pts30 = ((window.QC_RUNS||{})[code]||[]).slice(0,30);
  const eval30 = window.QC.evaluate([...pts30].reverse());
  const pts    = [...pts30].reverse(); // chronological
  APP_STATE.currentRoute = 'qualityControl';

  // SVG Levey-Jennings chart
  const W=640, H=200, PAD_L=52, PAD_R=16, PAD_T=20, PAD_B=32;
  const CW=W-PAD_L-PAD_R, CH=H-PAD_T-PAD_B;
  const n=pts.length;
  const xScale=(i)=>PAD_L+i*(CW/(n-1||1));
  const yScale=(z)=>PAD_T+CH/2 - (z/4)*CH; // ±4 SD range
  // Grid lines
  const gridLines = [-3,-2,-1,0,1,2,3].map(sd=>{
    const y=yScale(sd);
    const color=Math.abs(sd)===3?'#9A1F1F30':Math.abs(sd)===2?'#C77B1430':'#88888822';
    const lbl=sd===0?'Mean':sd>0?`+${sd}SD`:`${sd}SD`;
    return `<line x1="${PAD_L}" y1="${y}" x2="${W-PAD_R}" y2="${y}" stroke="${color}" stroke-width="${sd===0?1.5:1}"/>
            <text x="${PAD_L-4}" y="${y+4}" text-anchor="end" font-size="9" fill="#888">${lbl}</text>`;
  }).join('');
  // Data points and connecting line
  const path=pts.map((p,i)=>`${i===0?'M':'L'}${xScale(i).toFixed(1)},${yScale(p.z).toFixed(1)}`).join(' ');
  const dotColor=(p)=>{
    if(Math.abs(p.z)>3) return '#9A1F1F';
    if(Math.abs(p.z)>2) return '#C77B14';
    return '#1F7A4D';
  };
  const dots=pts.map((p,i)=>`<circle cx="${xScale(i).toFixed(1)}" cy="${yScale(p.z).toFixed(1)}" r="4"
    fill="${dotColor(p)}" stroke="#fff" stroke-width="1.5"
    title="${esc(p.date)}: ${p.result} ${analyte.unit} (z=${p.z})"/>`).join('');
  const xLabels=pts.filter((_,i)=>i%5===0||i===pts.length-1)
    .map((p,j,arr)=>{ const i=pts.indexOf(p);
      return `<text x="${xScale(i).toFixed(1)}" y="${H-4}" text-anchor="middle" font-size="9" fill="#888">${p.date.slice(5)}</text>`; }).join('');

  const chart=`<svg viewBox="0 0 ${W} ${H}" style="width:100%;height:auto;overflow:visible">
    <rect width="${W}" height="${H}" fill="none"/>
    ${gridLines}
    <path d="${path}" fill="none" stroke="#2F4A6D" stroke-width="1.5"/>
    ${dots}
    ${xLabels}
  </svg>`;

  const runsTable=pts30.slice(0,10).map(p=>{
    const statusColor=Math.abs(p.z)>3?'#9A1F1F':Math.abs(p.z)>2?'#C77B14':'#1F7A4D';
    return `<tr>
      <td>${p.date} ${p.time}</td>
      <td style="font-variant-numeric:tabular-nums;text-align:right;font-weight:600">${p.result} ${analyte.unit}</td>
      <td style="text-align:right;color:${statusColor};font-weight:600">${p.z>0?'+':''}${p.z}</td>
      <td>${esc(p.operator)}</td>
      <td><span style="color:${statusColor}">${Math.abs(p.z)>3?'⛔ REJECT':Math.abs(p.z)>2?'⚠ Warn':'✓ OK'}</span></td>
    </tr>`;
  }).join('');

  root.innerHTML = `
    <div class="page-header">
      <div>
        <a class="muted-sm" style="cursor:pointer" onclick="navigate('qualityControl')">← Quality Control</a>
        <div class="page-title" style="margin-top:4px">${esc(analyte.name)} — Levey-Jennings Chart</div>
        <div class="page-subtitle">${esc(analyte.instrument)} · Lot ${esc(analyte.lot)} · Target ${analyte.target} ${analyte.unit} ± ${analyte.sd}</div>
      </div>
      <div class="actions"><button class="btn primary" onclick="openQcRun('${esc(code)}')">+ Log run</button></div>
    </div>
    ${eval30.violations.length ? `<div class="alert-banner ${eval30.status==='reject'?'danger':'warn'}" style="margin-bottom:16px">
      <span class="icon">${eval30.status==='reject'?'⛔':'⚠'}</span>
      <div><b>${eval30.violations.length} Westgard violation${eval30.violations.length>1?'s':''} in last 30 runs.</b>
        <ul style="margin:6px 0 0;padding-left:16px;font-size:12.5px">${eval30.violations.slice(0,4).map(v=>`<li>${v.rule}: ${v.description}</li>`).join('')}</ul>
      </div>
    </div>` : `<div class="alert-banner success" style="margin-bottom:16px"><span class="icon">✓</span><div>All Westgard rules within specification for the last 30 runs.</div></div>`}
    <div class="card" style="margin-bottom:16px">${chart}</div>
    <div class="card">
      <div class="card-section-title">Recent runs (last 10)</div>
      <table class="table" style="font-size:12px">
        <thead><tr><th>Date / time</th><th style="text-align:right">Result</th><th style="text-align:right">z-score</th><th>Operator</th><th>Status</th></tr></thead>
        <tbody>${runsTable}</tbody>
      </table>
    </div>`;
}

function openQcRun(prefillCode){
  const analytes = window.QC_ANALYTES || [];
  const opts = analytes.map(a=>`<option value="${esc(a.code)}" ${a.code===prefillCode?'selected':''}>${esc(a.name)} (${esc(a.instrument)})</option>`).join('');
  document.getElementById('modal-root').innerHTML = `
    <div class="modal-backdrop" onclick="closeModal()"></div>
    <div class="modal" style="max-width:480px" role="dialog" aria-modal="true" aria-labelledby="qcr-title">
      <div class="modal-header">
        <div><div id="qcr-title" class="modal-title">Log QC run</div><div class="muted-sm">Record an instrument quality-control result</div></div>
        <button class="modal-close" onclick="closeModal()" aria-label="Close">×</button>
      </div>
      <div class="modal-body">
        <div class="form-grid">
          <div class="field" style="grid-column:span 2">
            <label>Analyte / instrument<span class="req">*</span></label>
            <select id="qcr-analyte" class="input">${opts}</select>
          </div>
          <div class="field"><label>Result<span class="req">*</span></label><input id="qcr-result" type="number" step="0.01" class="input" placeholder="Enter measured value" autofocus></div>
          <div class="field"><label>Unit</label><input id="qcr-unit" class="input" value="${analytes[0]?analytes[0].unit:''}" readonly style="background:var(--bg-soft)"></div>
          <div class="field" style="grid-column:span 2"><label>Operator<span class="req">*</span></label>
            <select id="qcr-operator" class="input">
              <option>Ngozi Adebola</option><option>Kelechi Eze</option><option>Sadia Adamu</option><option>Tope Ajayi</option>
            </select>
          </div>
        </div>
        <div id="qcr-preview" class="muted-sm" style="margin-top:8px;font-size:11px">Enter a result to preview the z-score before submitting.</div>
      </div>
      <div class="modal-footer">
        <button class="btn" onclick="closeModal()">Cancel</button>
        <button class="btn primary" onclick="submitQcRun()">Log run</button>
      </div>
    </div>`;
  // Wire analyte change to update unit
  const sel=document.getElementById('qcr-analyte');
  const unitFld=document.getElementById('qcr-unit');
  if(sel && unitFld){
    sel.addEventListener('change',()=>{
      const a=(window.QC_ANALYTES||[]).find(x=>x.code===sel.value);
      if(a && unitFld) unitFld.value=a.unit;
    });
  }
  // Live z-score preview
  const resultFld=document.getElementById('qcr-result');
  if(resultFld){
    resultFld.addEventListener('input',()=>{
      const a=(window.QC_ANALYTES||[]).find(x=>x.code===sel.value);
      const v=parseFloat(resultFld.value);
      const preview=document.getElementById('qcr-preview');
      if(a && !isNaN(v) && preview){
        const z=((v-a.target)/a.sd).toFixed(2);
        const warn=Math.abs(z)>3?'⛔ REJECT':Math.abs(z)>2?'⚠ Warning':'✓ In control';
        const col=Math.abs(z)>3?'#9A1F1F':Math.abs(z)>2?'#C77B14':'#1F7A4D';
        preview.innerHTML=`z-score: <b style="color:${col}">${z>0?'+':''}${z} — ${warn}</b> &nbsp;(target ${a.target}, SD ${a.sd})`;
      }
    });
  }
}

function submitQcRun(){
  const code  = $v('qcr-analyte');
  const result= parseFloat($v('qcr-result'));
  const operator = $v('qcr-operator') || 'Lab Scientist';
  if(!code){ toast('Select an analyte', {type:'error'}); return; }
  if(isNaN(result)){ toast('Enter the QC result', {type:'error'}); return; }
  const out = window.QC.submitRun(code, result, operator);
  if(!out){ toast('Analyte not found', {type:'error'}); return; }
  closeModal();
  const { run, evaluation } = out;
  if(evaluation.status === 'reject'){
    toast(`QC REJECTED — ${evaluation.violations.map(v=>v.rule).join(', ')}. Do not release patient results until QC is within spec.`,
      {type:'error', title:`${code} QC REJECT`, duration:9000});
  } else if(evaluation.status === 'warning'){
    toast(`QC warning — ${evaluation.violations[0].rule}. Monitor closely; patient results may proceed with pathologist awareness.`,
      {type:'warn', title:`${code} QC warning`, duration:6000});
  } else {
    toast(`QC run logged — z=${run.z>0?'+':''}${run.z}. All Westgard rules in spec.`, {type:'success', title:`${code} QC OK`});
  }
  navigate('qualityControl');
}

