function submitDsar(){
  if(pcRequire('dsar-patient','patient')) return;
  const patient = pcPatient('dsar-patient');
  const type  = $v('dsar-type');
  const notes = $v('dsar-notes');
  if(!APP_STATE.dsarRequests) APP_STATE.dsarRequests = [];
  const record = window.NDPR.submitDsar(type, patient.id, notes);
  closeModal();
  toast(`DSAR ${record.id} logged. Response due by ${record.dueAt.slice(0,10)}.`, {type:'success', title:'DSAR logged', duration:5000});
  navigate('privacy');
}

function processDsar(id){
  const d = (APP_STATE.dsarRequests||[]).find(x=>x.id===id);
  if(!d) return;
  const patient = (APP_STATE.patients||[]).find(p=>p.id===d.patientId);
  if(d.type==='access'||d.type==='portability'){
    // Generate and offer the export
    const data = window.NDPR.exportPatientData(d.patientId);
    if(!data){ toast('Patient data not found', {type:'error'}); return; }
    const json = JSON.stringify(data, null, 2);
    const blob = new Blob([json], {type:'application/json'});
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href=url; a.download=`${d.patientId}-data-export-${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a); a.click(); a.remove();
    setTimeout(()=>URL.revokeObjectURL(url),1000);
    d.status='completed'; d.completedAt=new Date().toISOString();
    OfflineCore.schedulePersist();
    toast(`Data export for ${patient?.name||d.patientId} downloaded. Mark as completed.`, {type:'success', duration:5000});
  } else if(d.type==='deletion'){
    if(!confirm(`Mark patient ${patient?.name||d.patientId} for deletion? This will flag their records for removal. Server-side enforcement required.`)) return;
    window.NDPR.markForDeletion(d.patientId, id);
    toast(`Patient marked for deletion. Records will be purged by labos-api on next scheduled sweep.`, {type:'warn', title:'Deletion queued', duration:7000});
  } else {
    d.status='processing'; d.completedAt=null;
    OfflineCore.schedulePersist();
    toast(`DSAR ${id} marked as processing. Complete the action and update the status manually.`, {type:'info', duration:5000});
  }
  navigate('privacy');
}

/* ==========================================================
   NOTIFICATION BELL PANEL
   Slide-in tray from the topbar bell — shows recent
   notifications with unread badges and quick actions.
   ========================================================== */

// Returns notifications enriched with an .unread flag.
// In a real system "read" state lives on the server; here we
// track it in APP_STATE.notifReadIds (a Set persisted via OfflineCore).
function _notifList(){
  if(!APP_STATE._notifReadIds) APP_STATE._notifReadIds = new Set();
  return (APP_STATE.notifications||[]).map(n=>({
    ...n,
    unread: !APP_STATE._notifReadIds.has(n.id)
  }));
}

function _unreadCount(){
  return _notifList().filter(n=>n.unread).length;
}

// Keep the topbar bell badge in sync after any read/write change.
function refreshNotifBadge(){
  const btn = document.getElementById('notif-bell-btn');
  if(!btn) return;
  const count = _unreadCount();
  // Remove old badge if present
  const old = btn.querySelector('.badge');
  if(old) old.remove();
  if(count > 0){
    const badge = document.createElement('span');
    badge.className = 'badge';
    badge.setAttribute('aria-label', count + ' unread notifications');
    badge.textContent = count > 9 ? '9+' : count;
    btn.appendChild(badge);
  }
  // Also toggle the .dot visibility
  const dot = document.getElementById('notif-dot');
  if(dot) dot.style.display = count > 0 ? '' : 'none';
}

function toggleNotifPanel(){
  const panel = document.getElementById('notif-panel');
  if(!panel) return;
  const isOpen = panel.style.display !== 'none';
  if(isOpen){
    closeNotifPanel();
  } else {
    renderNotifPanel();
    panel.style.display = 'flex';
    // Close when clicking outside
    setTimeout(()=>{
      document.addEventListener('mousedown', _notifPanelOutsideClick, {once:true});
    }, 0);
  }
}

function closeNotifPanel(){
  const panel = document.getElementById('notif-panel');
  if(panel) panel.style.display = 'none';
  document.removeEventListener('mousedown', _notifPanelOutsideClick);
}

function _notifPanelOutsideClick(e){
  const panel = document.getElementById('notif-panel');
  const bell  = document.getElementById('notif-bell-btn');
  if(panel && !panel.contains(e.target) && bell && !bell.contains(e.target)){
    closeNotifPanel();
  }
}

function renderNotifPanel(){
  const panel = document.getElementById('notif-panel');
  if(!panel) return;

  const items = _notifList().slice(0,20); // show at most 20 in the tray
  const unread = items.filter(n=>n.unread).length;

  const channelIcon = ch => ({
    SMS:      '📱',
    WhatsApp: '💬',
    Email:    '✉️',
    System:   '🔔'
  }[ch] || '🔔');

  const statusColor = s => ({
    delivered: '#1F7A4D',
    queued:    '#2F4A6D',
    failed:    '#9A1F1F',
    sent:      '#1F7A4D'
  }[s] || '#6B7787');

  const timeAgo = ts => {
    if(!ts) return 'Pending';
    const diff = Date.now() - new Date(ts).getTime();
    const m = Math.floor(diff / 60000);
    if(m < 1)  return 'Just now';
    if(m < 60) return `${m}m ago`;
    const h = Math.floor(m/60);
    if(h < 24) return `${h}h ago`;
    return new Date(ts).toLocaleDateString('en-GB',{day:'numeric',month:'short'});
  };

  panel.innerHTML = `
    <div class="notif-panel-header">
      <div class="notif-panel-title">
        Notifications
        ${unread > 0 ? `<span style="font-size:11px;font-weight:600;color:var(--accent);margin-left:6px">${unread} new</span>` : ''}
      </div>
      <div class="notif-panel-actions">
        ${unread > 0 ? `<button class="btn-sm" onclick="markAllNotifsRead()" style="font-size:11px">Mark all read</button>` : ''}
        <button class="icon-btn" onclick="closeNotifPanel()" aria-label="Close notifications" style="padding:2px">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
    </div>
    <div class="notif-panel-body">
      ${items.length === 0
        ? `<div class="notif-empty">
             <div style="font-size:28px;margin-bottom:8px">🔔</div>
             <div style="font-size:13px;font-weight:600">No notifications yet</div>
             <div class="muted-sm" style="margin-top:4px;font-size:12px">Notifications for patients, results, and billing will appear here.</div>
           </div>`
        : items.map(n => `
            <div class="notif-item${n.unread?' unread':''}"
              onclick="markNotifRead('${esc(n.id)}');navigate('notifications');closeNotifPanel()">
              <div class="notif-item-dot"></div>
              <div class="notif-item-body">
                <div class="notif-item-title">${channelIcon(n.channel)} ${esc(n.template||n.channel)}</div>
                <div class="notif-item-body-text">${esc(n.body||'')}</div>
                <div class="notif-item-meta">
                  <span>${esc(n.recipient||'')}</span>
                  <span style="margin:0 4px">·</span>
                  <span style="color:${statusColor(n.status)}">${esc(n.status||'')}</span>
                  <span style="margin:0 4px">·</span>
                  <span>${timeAgo(n.sentAt)}</span>
                </div>
              </div>
            </div>`).join('')}
    </div>
    <div class="notif-panel-footer">
      <button class="btn" style="width:100%;font-size:12px"
        onclick="navigate('notifications');closeNotifPanel()">
        View all notifications →
      </button>
    </div>
  `;
}

function markNotifRead(id){
  if(!APP_STATE._notifReadIds) APP_STATE._notifReadIds = new Set();
  APP_STATE._notifReadIds.add(id);
  refreshNotifBadge();
  // Re-render the panel if still open
  const panel = document.getElementById('notif-panel');
  if(panel && panel.style.display !== 'none') renderNotifPanel();
}

function markAllNotifsRead(){
  if(!APP_STATE._notifReadIds) APP_STATE._notifReadIds = new Set();
  (APP_STATE.notifications||[]).forEach(n => APP_STATE._notifReadIds.add(n.id));
  refreshNotifBadge();
  const panel = document.getElementById('notif-panel');
  if(panel && panel.style.display !== 'none') renderNotifPanel();
}

function renderNotifications(root){
  const notes = APP_STATE.notifications || [];
  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title" style="display:flex;align-items:center;gap:10px">${sectionIcon('notifications',24)} Notifications Engine</div>
        <div class="page-subtitle">SMS, WhatsApp, email and in-app messaging · delivery queue</div>
      </div>
      <div class="actions">
        <button class="btn" onclick="navigate('integrations')">Integrations…</button>
        <button class="btn primary" onclick="openComposeNotification()">+ Compose</button>
      </div>
    </div>
    <div class="stats-grid">
      <div class="stat-card"><div class="stat-label">Sent (period)</div><div class="stat-value">${notes.length}</div></div>
      <div class="stat-card"><div class="stat-label">Delivered</div><div class="stat-value" style="color:#1B6B3A">${notes.filter(n=>n.status==='delivered').length}</div></div>
      <div class="stat-card"><div class="stat-label">Queued</div><div class="stat-value" style="color:#8A5A00">${notes.filter(n=>n.status==='queued').length}</div></div>
      <div class="stat-card"><div class="stat-label">Failed</div><div class="stat-value" style="color:#9A1F1F">${notes.filter(n=>n.status==='failed').length}</div></div>
    </div>
    <div class="panel" style="margin-top:16px">
      <div class="panel-header"><div class="panel-title">Delivery queue</div><span class="pill">${notes.length} messages</span></div>
      <div class="panel-body flush">
        <table>
          <thead><tr><th>Ref</th><th>Channel</th><th>Recipient</th><th>Template</th><th>Message</th><th>Status</th><th>Sent</th></tr></thead>
          <tbody>
            ${notes.map(n=>`<tr>
              <td class="mono"><b>${esc(n.id)}</b></td>
              <td><span class="pill-soft">${esc(n.channel)}</span></td>
              <td>${esc(n.recipient)}</td>
              <td>${esc(n.template)}</td>
              <td class="muted-sm" style="max-width:240px">${esc(n.body)}</td>
              <td><span class="status ${NOT_STATUS[n.status]||'pending'}">${esc(n.status)}</span></td>
              <td class="muted-sm">${esc(n.sentAt||'—')}</td>
            </tr>`).join('')}
          </tbody>
        </table>
      </div>
    </div>`;
}

// ===========================================================================
// COMPOSE NOTIFICATION — patient recipient + channel + template
// Pushes a real record into APP_STATE.notifications with status='queued'.
// Live dispatch (Termii API call, SMTP send) is the *production wiring* step
// that lives server-side; the queue + outbox entry is fully functional here.
// ===========================================================================

const NOTIF_TEMPLATES = {
  result_ready:     {label:'Result ready',        body:'Hello {{name}}, your test results from {{lab}} are ready. View them at {{link}} or visit the lab to collect.'},
  appointment:      {label:'Appointment reminder', body:'Hello {{name}}, this is a reminder for your appointment at {{lab}} on {{date}} at {{time}}.'},
  payment_received: {label:'Payment received',    body:'Hello {{name}}, we have received your payment of {{amount}} for {{service}}. Reference: {{ref}}. Thank you.'},
  critical_alert:   {label:'Critical-value call', body:'Hello {{name}}, please contact {{lab}} immediately regarding an important result. Phone: {{phone}}.'},
  custom:           {label:'Custom message',      body:''}
};

function openComposeNotification(){
  if(!requireLicensed('send a notification')) return;
  const t = currentTenant();
  const integ = (t && t.integrations) || {};
  const termiiOn = !!(integ.termii && integ.termii.apiKey);
  const smtpOn   = !!(integ.smtp && integ.smtp.host);
  document.getElementById('modal-root').innerHTML = `
    <div class="modal-backdrop" onclick="closeModal()"></div>
    <div class="modal" style="max-width:620px">
      <div class="modal-header">
        <div><div class="modal-title">Compose notification</div><div class="muted-sm">Queue an SMS, WhatsApp, or email to a patient</div></div>
        <button class="modal-close" onclick="closeModal()">×</button>
      </div>
      <div class="modal-body">
        <label class="label">Recipient (patient)</label>
        ${patientComboHtml('cn-patient', {placeholder:'Type name, phone or hospital number…', hint:'Search for the patient you want to notify.'})}
        <div id="cn-recipient-preview" class="muted-sm" style="margin-top:4px"></div>

        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:14px">
          <div>
            <label class="label">Channel</label>
            <select class="input" id="cn-channel" onchange="composeChannelChanged()">
              <option value="sms"      ${termiiOn?'':'disabled'}>SMS${termiiOn?'':' — set up Termii first'}</option>
              <option value="whatsapp" ${termiiOn?'':'disabled'}>WhatsApp${termiiOn?'':' — set up Termii first'}</option>
              <option value="email"    ${smtpOn?'':'disabled'}>Email${smtpOn?'':' — set up SMTP first'}</option>
              <option value="in_app">In-app only</option>
            </select>
          </div>
          <div>
            <label class="label">Template</label>
            <select class="input" id="cn-template" onchange="composeTemplateChanged()">
              ${Object.entries(NOTIF_TEMPLATES).map(([k,v])=>`<option value="${k}">${esc(v.label)}</option>`).join('')}
            </select>
          </div>
        </div>

        <label class="label" style="margin-top:14px">Message body</label>
        <textarea class="input" id="cn-body" rows="5" placeholder="Type the message…">${esc(NOTIF_TEMPLATES.result_ready.body)}</textarea>
        <div class="muted-sm" style="margin-top:4px">Use <code>{{name}}</code>, <code>{{lab}}</code>, <code>{{date}}</code>, <code>{{time}}</code>, <code>{{amount}}</code>, <code>{{ref}}</code>, <code>{{link}}</code>, <code>{{phone}}</code> — substituted at send time.</div>

        <div class="alert-banner info" style="margin-top:14px;display:flex;gap:10px;align-items:flex-start">
          ${sectionIcon('notifications',16)}
          <div style="flex:1;font-size:12.5px"><b>How dispatch works.</b> The message is added to the delivery queue with status <b>queued</b>. In production, the LabOS dispatcher polls the queue and calls the configured provider (Termii for SMS/WhatsApp, SMTP for email). If a provider isn't configured for the selected channel, the queue entry stays <b>queued</b> until you finish setup in <a onclick="closeModal();navigate('integrations')" style="cursor:pointer;text-decoration:underline">Integrations</a>.</div>
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn" onclick="closeModal()">Cancel</button>
        <button class="btn primary" onclick="submitComposeNotification()">Queue message</button>
      </div>
    </div>`;
  composePreviewRecipient();
}

function composePreviewRecipient(){
  const p  = pcPatient('cn-patient');
  const ch = (document.getElementById('cn-channel')||{}).value || 'sms';
  const el = document.getElementById('cn-recipient-preview');
  if(!el) return;
  if(!p){ el.textContent = ''; return; }
  const dest = ch==='email' ? (p.email||'(no email on file)') : (p.phone||'(no phone on file)');
  el.textContent = `Will deliver to: ${dest}`;
}
function composeChannelChanged(){ composePreviewRecipient(); }
function composeTemplateChanged(){
  const key = document.getElementById('cn-template').value;
  const tpl = NOTIF_TEMPLATES[key];
  if(tpl) document.getElementById('cn-body').value = tpl.body;
}

function submitComposeNotification(){
  if(!requireLicensed('send a notification')) return;
  if(pcRequire('cn-patient','recipient')) return;
  const patient = pcPatient('cn-patient');
  const channel = $v('cn-channel') || 'in_app';
  const templateKey = $v('cn-template') || 'custom';
  const body = ($v('cn-body')||'').trim();
  if(!body){ toast('Message body is empty', {type:'error', title:'Required'}); return; }
  const t = currentTenant();
  const integ = (t && t.integrations) || {};
  const hasProvider = (channel==='sms'||channel==='whatsapp') ? !!(integ.termii && integ.termii.apiKey)
                    : channel==='email' ? !!(integ.smtp && integ.smtp.host)
                    : true;
  // Substitute the template variables we can fill from patient + tenant data.
  const lab = t ? t.name : 'your lab';
  const phone = t ? (t.phoneNumbers && t.phoneNumbers[0]) || '' : '';
  const filled = body
    .replace(/\{\{name\}\}/g, patient.name||'')
    .replace(/\{\{lab\}\}/g, lab)
    .replace(/\{\{phone\}\}/g, phone)
    .replace(/\{\{date\}\}/g, new Date().toISOString().slice(0,10))
    .replace(/\{\{time\}\}/g, new Date().toTimeString().slice(0,5))
    .replace(/\{\{link\}\}/g, 'https://patient.labos.africa/r/'+(patient.id||''))
    .replace(/\{\{amount\}\}/g, '—').replace(/\{\{ref\}\}/g, '—').replace(/\{\{service\}\}/g,'—');
  const recipient = channel==='email' ? (patient.email||'(no email)') : (patient.phone||'(no phone)');
  const notes = APP_STATE.notifications || (APP_STATE.notifications = []);
  const id = `MSG-${new Date().getFullYear()}-${String(notes.length+1).padStart(4,'0')}`;
  const record = {
    id, channel, recipient, patientId:patient.id,
    template: NOTIF_TEMPLATES[templateKey]?.label || 'Custom',
    body: filled,
    status: 'queued',
    sentAt: null,
    queuedAt: new Date().toISOString(),
    providerReady: hasProvider // dispatcher uses this to decide whether to attempt send
  };
  notes.unshift(record);
  OfflineCore.record('notification.queue', {id, channel, patientId:patient.id}, `Queued ${channel.toUpperCase()} to ${patient.name} — ${(NOTIF_TEMPLATES[templateKey]?.label||'message')}`);
  OfflineCore.schedulePersist();
  if(typeof refreshNotifBadge === 'function') refreshNotifBadge();
  closeModal();
  if(!hasProvider){
    toast(`Queued, but ${channel.toUpperCase()} provider isn't configured yet — set it up in Integrations to dispatch.`, {type:'warn', title:id, duration:6500});
  } else {
    toast(`Queued for dispatch via ${channel.toUpperCase()} → ${recipient}`, {type:'success', title:id, duration:4500});
  }
  if(APP_STATE.currentRoute==='notifications') navigate('notifications');
}

// ===========================================================================
// INTEGRATIONS — per-tenant credential setup for Termii / Paystack / NHIS /
// HL7 / SMTP. Credentials persist to t.integrations and the offline outbox.
// Frontend NEVER attempts live API calls with these — that's the production
// dispatcher's job server-side. The screen makes it explicit what's wired vs
// what still needs configuring.
// ===========================================================================

const INTEGRATIONS = [
  { key:'termii', title:'Termii — SMS & WhatsApp', icon:'notifications',
    blurb:'Termii powers SMS, voice and WhatsApp dispatch for African networks. Required for appointment reminders, result-ready alerts and critical-value calls.',
    fields:[
      {k:'apiKey',           label:'Termii API key',       type:'password', placeholder:'TLxxxxxxxxxxxxxxxx'},
      {k:'smsSenderId',      label:'SMS Sender ID',        type:'text',     placeholder:'YOURLAB', help:'11 chars max · register with Termii first'},
      {k:'whatsappFrom',     label:'WhatsApp business no.',type:'text',     placeholder:'+234 …'}
    ]},
  { key:'paystack', title:'Paystack — Payments', icon:'pricing',
    blurb:'Paystack handles card, bank transfer and USSD payments in Naira. Used for invoice payment links and POS card capture.',
    fields:[
      {k:'publicKey', label:'Paystack public key', type:'text',     placeholder:'pk_live_xxx or pk_test_xxx'},
      {k:'secretKey', label:'Paystack secret key', type:'password', placeholder:'sk_live_xxx or sk_test_xxx'},
      {k:'callbackUrl', label:'Callback URL',      type:'text',     placeholder:'https://yourlab.labos.africa/paystack/callback'}
    ]},
  { key:'nhis', title:'NHIS Portal — Insurance', icon:'subscription',
    blurb:'Connect to the National Health Insurance Authority portal for HMO claim submission, eligibility checks and authorisation codes.',
    fields:[
      {k:'providerId', label:'NHIA Provider ID',  type:'text',     placeholder:'NHIA/LAGOS/000000'},
      {k:'hmoCode',    label:'Default HMO code',  type:'text',     placeholder:'e.g. HYG / HEALTHCARE INTL'},
      {k:'portalUser', label:'Portal username',   type:'text',     placeholder:'lab-admin@yourlab.ng'},
      {k:'portalPass', label:'Portal password',   type:'password', placeholder:''}
    ]},
  { key:'hl7', title:'Auto-analyser HL7 bridge', icon:'devices',
    blurb:'LIS↔analyser interface. LabOS listens on a TCP/MLLP port for ORU^R01 result messages from your haematology / chemistry / immunoassay analysers, and sends ACKs.',
    fields:[
      {k:'host', label:'Listener host (interface)', type:'text', placeholder:'0.0.0.0'},
      {k:'port', label:'TCP / MLLP port',           type:'text', placeholder:'2575'},
      {k:'ackMode', label:'ACK mode',               type:'select', options:['AL (always)','NE (never)','SU (success only)','ER (error only)']},
      {k:'encoding', label:'Encoding',              type:'select', options:['UTF-8','ISO-8859-1','ASCII']}
    ]},
  { key:'smtp', title:'Email (SMTP)', icon:'notifications',
    blurb:'Outbound email for result notifications, invoices and patient correspondence. Use your lab\u2019s SMTP, Gmail, or a transactional provider (SendGrid, Mailgun).',
    fields:[
      {k:'host',   label:'SMTP host', type:'text',     placeholder:'smtp.gmail.com / smtp.sendgrid.net'},
      {k:'port',   label:'Port',      type:'text',     placeholder:'587'},
      {k:'user',   label:'Username',  type:'text',     placeholder:'noreply@yourlab.ng'},
      {k:'pass',   label:'Password',  type:'password', placeholder:''},
      {k:'fromAddress', label:'From address', type:'text', placeholder:'Your Lab <noreply@yourlab.ng>'},
      {k:'tls',    label:'TLS',       type:'select',   options:['STARTTLS (587)','TLS (465)','None']}
    ]}
];

function integrationStatus(intKey){
  const t = currentTenant();
  const v = t && t.integrations && t.integrations[intKey];
  if(!v) return 'unconfigured';
  // any required-looking field present = configured
  const filled = Object.values(v).filter(x => x && String(x).trim()).length;
  return filled >= 2 ? 'configured' : 'partial';
}

function renderIntegrations(root){
  const t = currentTenant();
  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title" style="display:flex;align-items:center;gap:10px">${sectionIcon('devices', 24)} Integrations</div>
        <div class="page-subtitle">Per-laboratory credentials for SMS / WhatsApp / Email / Payments / NHIS / HL7 analysers</div>
      </div>
      <div class="actions"><button class="btn" onclick="navigate('notifications')">← Back to Notifications</button></div>
    </div>

    <div class="alert-banner info" style="margin-bottom:16px;display:flex;gap:10px;align-items:flex-start">
      ${sectionIcon('audit',16)}
      <div style="flex:1;font-size:13px"><b>Where these credentials live.</b> They are stored against <i>${esc((t&&t.name)||'this laboratory')}</i> only and used by the LabOS production dispatcher (server-side) to send messages, take payments, submit NHIS claims and receive HL7 results. The frontend never makes live API calls with these keys.</div>
    </div>

    ${INTEGRATIONS.map(integ => {
      const cur = (t && t.integrations && t.integrations[integ.key]) || {};
      const status = integrationStatus(integ.key);
      const statusLabel = {configured:'Configured', partial:'Partial', unconfigured:'Not configured'}[status];
      const statusCls = {configured:'completed', partial:'review', unconfigured:'pending'}[status];
      return `
      <div class="card" id="int-${integ.key}" style="margin-bottom:16px">
        <div style="display:flex;align-items:flex-start;gap:14px;padding:18px;border-bottom:1px solid var(--line-soft)">
          <div style="width:36px;height:36px;background:var(--bg-soft);border-radius:6px;display:flex;align-items:center;justify-content:center;flex-shrink:0">${sectionIcon(integ.icon,18)}</div>
          <div style="flex:1">
            <div style="display:flex;align-items:center;gap:10px"><h3 style="margin:0;font-size:15px">${esc(integ.title)}</h3><span class="status ${statusCls}">${statusLabel}</span></div>
            <div class="muted-sm" style="margin-top:4px">${esc(integ.blurb)}</div>
          </div>
        </div>
        <div style="padding:18px">
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">
            ${integ.fields.map(f => {
              const val = cur[f.k] || '';
              if(f.type === 'select'){
                return `<div><label class="label">${esc(f.label)}</label>
                  <select class="input" id="int-${integ.key}-${f.k}">
                    ${f.options.map(o=>`<option ${o===val?'selected':''}>${esc(o)}</option>`).join('')}
                  </select></div>`;
              }
              const t2 = f.type==='password' ? 'password' : 'text';
              const hint = f.help ? `<div class="muted-sm" style="margin-top:4px">${esc(f.help)}</div>` : '';
              return `<div><label class="label">${esc(f.label)}</label>
                <input class="input" type="${t2}" id="int-${integ.key}-${f.k}" value="${esc(val)}" placeholder="${esc(f.placeholder||'')}"/>
                ${hint}</div>`;
            }).join('')}
          </div>
          <div style="margin-top:14px;display:flex;gap:8px;align-items:center;justify-content:flex-end">
            <button class="btn-sm" onclick="testIntegration('${integ.key}')">Test connection</button>
            <button class="btn-sm primary" onclick="saveTenantIntegration('${integ.key}')">Save ${esc(integ.title.split(' ')[0])} settings</button>
          </div>
        </div>
      </div>`;
    }).join('')}
  `;
  _modalA11y();
  _modalA11y();
  _modalA11y();
  _modalA11y();
}

function saveTenantIntegration(intKey){
  if(!requireLicensed('save integration settings')) return;
  const integ = INTEGRATIONS.find(i=>i.key===intKey);
  if(!integ) return;
  const t = currentTenant();
  if(!t) return;
  t.integrations = t.integrations || {};
  const data = {};
  for(const f of integ.fields){
    const el = document.getElementById(`int-${intKey}-${f.k}`);
    if(el) data[f.k] = el.value;
  }
  t.integrations[intKey] = data;
  OfflineCore.record('tenant.integration.save', {tenantId:t.id, integration:intKey}, `${integ.title} settings saved for ${t.name}`);
  OfflineCore.schedulePersist();
  toast(`${integ.title} settings saved.`, {type:'success', title:'Saved', duration:4000});
  // re-render to refresh status pills
  if(APP_STATE.currentRoute==='integrations') navigate('integrations');
}

function testIntegration(intKey){
  const integ = INTEGRATIONS.find(i=>i.key===intKey);
  const status = integrationStatus(intKey);
  if(status === 'unconfigured'){
    toast(`Fill in the ${integ.title} fields first, then Save.`, {type:'warn', title:'Not configured yet'});
    return;
  }
  toast(`In production, this opens a real connection test against ${integ.title}. (Server-side dispatcher action — not run from the browser.)`, {type:'info', title:'Production wiring', duration:6000});
}
// devices, the signed licence, session policy, RLS posture, backup schedule.
