function submitAddBranch(){
  if(!requireLicensed('add a branch')) return;
  if(enforceCentreLimit('add a branch')) return; // plan hard limit
  const name = $v('ab-name'); if(!name){ toast('Branch name required', {type:'error'}); return; }
  const t = currentTenant();
  t.branches = t.branches || [];
  const id = `BR-${String(t.branches.length+1).padStart(3,'0')}`;
  t.branches.push({
    id, name, type:$v('ab-type')||'Collection centre',
    code:$v('ab-code')||id, address:$v('ab-address')||'—',
    phone:$v('ab-phone')||'—', manager:$v('ab-mgr')||'—',
    addedAt:new Date().toISOString()
  });
  OfflineCore.record('branch.add', {id, name, tenantId:t.id}, `Branch added: ${name}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`Branch added: ${name}`, {type:'success', title:id});
  if(APP_STATE.currentRoute==='settings' || APP_STATE.currentRoute==='centres') navigate(APP_STATE.currentRoute);
}

