// Analyte reference table — drives the real result-entry workspace. Each test
// code maps to its constituent analytes with unit + reference range, so the
// Clinical Laboratory slice can compute H/L/critical flags automatically as a
// scientist enters values. Ranges are typical adult values; a production build
// would make these tenant-configurable and sex/age-specific.
const ANALYTE_PANELS = {
  FBC: { name:'Full Blood Count', specimen:'EDTA whole blood', analytes:[
    {key:'hb',   name:'Haemoglobin',        unit:'g/dL',   low:11.5, high:16.5},
    {key:'wbc',  name:'White Blood Cells',  unit:'×10⁹/L', low:4.0,  high:11.0},
    {key:'plt',  name:'Platelets',          unit:'×10⁹/L', low:150,  high:400},
    {key:'neut', name:'Neutrophils',        unit:'%',      low:40,   high:75},
    {key:'lymph',name:'Lymphocytes',        unit:'%',      low:20,   high:45},
    {key:'eos',  name:'Eosinophils',        unit:'%',      low:1,    high:6},
    {key:'mcv',  name:'MCV',                unit:'fL',     low:80,   high:100},
    {key:'mch',  name:'MCH',                unit:'pg',     low:27,   high:32}
  ]},
  KFT: { name:'Kidney Function', specimen:'Serum', analytes:[
    {key:'ure',  name:'Urea',               unit:'mmol/L', low:2.5,  high:7.8},
    {key:'cre',  name:'Creatinine',         unit:'µmol/L', low:62,   high:106},
    {key:'na',   name:'Sodium',             unit:'mmol/L', low:135,  high:145},
    {key:'k',    name:'Potassium',          unit:'mmol/L', low:3.5,  high:5.1, critLow:2.8, critHigh:6.2},
    {key:'cl',   name:'Chloride',           unit:'mmol/L', low:98,   high:107},
    {key:'egfr', name:'eGFR',               unit:'mL/min', low:90,   high:200}
  ]},
  LFT: { name:'Liver Function', specimen:'Serum', analytes:[
    {key:'tbil', name:'Total Bilirubin',    unit:'µmol/L', low:3,    high:21},
    {key:'alt',  name:'ALT',                unit:'U/L',    low:7,    high:56},
    {key:'ast',  name:'AST',                unit:'U/L',    low:10,   high:40},
    {key:'alp',  name:'ALP',                unit:'U/L',    low:44,   high:147},
    {key:'alb',  name:'Albumin',            unit:'g/L',    low:35,   high:50},
    {key:'tp',   name:'Total Protein',      unit:'g/L',    low:64,   high:83}
  ]},
  LIPP: { name:'Lipid Profile', specimen:'Serum (fasting)', analytes:[
    {key:'tc',   name:'Total Cholesterol',  unit:'mmol/L', low:0,    high:5.2},
    {key:'hdl',  name:'HDL Cholesterol',    unit:'mmol/L', low:1.0,  high:2.5},
    {key:'ldl',  name:'LDL Cholesterol',    unit:'mmol/L', low:0,    high:3.4},
    {key:'tg',   name:'Triglycerides',      unit:'mmol/L', low:0,    high:1.7}
  ]},
  FBS: { name:'Fasting Blood Sugar', specimen:'Fluoride oxalate', analytes:[
    {key:'glu',  name:'Glucose (fasting)',  unit:'mmol/L', low:3.9,  high:5.5, critLow:2.5, critHigh:25}
  ]},
  ELY: { name:'Electrolytes', specimen:'Serum', analytes:[
    {key:'na',   name:'Sodium',             unit:'mmol/L', low:135,  high:145, critLow:120, critHigh:160},
    {key:'k',    name:'Potassium',          unit:'mmol/L', low:3.5,  high:5.1, critLow:2.8, critHigh:6.2},
    {key:'cl',   name:'Chloride',           unit:'mmol/L', low:98,   high:107},
    {key:'hco3', name:'Bicarbonate',        unit:'mmol/L', low:22,   high:29}
  ]},
  CRE: { name:'Creatinine', specimen:'Serum', analytes:[
    {key:'cre',  name:'Creatinine',         unit:'µmol/L', low:62,   high:106, critHigh:500}
  ]},
  HBA: { name:'HbA1c', specimen:'EDTA whole blood', analytes:[
    {key:'hba1c',name:'HbA1c',              unit:'%',      low:4.0,  high:5.6}
  ]}
};

// Resolve the analyte definition for a test code (falls back to a generic
// single-value analyte for codes we don't have a detailed panel for, so result
// entry still works for every test).
function analytesForCode(code){
  const p = ANALYTE_PANELS[code];
  if(p) return p;
  return { name: code, specimen:'—', analytes:[ {key:'val', name:code, unit:'', low:null, high:null} ] };
}

// Compute a flag for a numeric value against a reference range.
// Returns 'CRIT' | 'H' | 'L' | 'N' | '' (empty when no value / non-numeric).
function flagFor(value, a){
  if(value === '' || value == null) return '';
  const n = Number(value);
  if(!isFinite(n)) return '';
  if(a.critLow != null && n <= a.critLow) return 'CRIT';
  if(a.critHigh != null && n >= a.critHigh) return 'CRIT';
  if(a.low != null && n < a.low) return 'L';
  if(a.high != null && n > a.high) return 'H';
  return 'N';
}

// Specimen-tube mapping (used by phlebotomy)
const TUBE_FOR_SPECIMEN = {
  'EDTA whole blood':         {tube:'EDTA (purple-top)',     volume:'3 ml', colour:'#7C4DBA'},
  'EDTA plasma':              {tube:'EDTA (purple-top)',     volume:'3 ml', colour:'#7C4DBA'},
  'Serum':                    {tube:'Plain / SST (red/gold)',volume:'5 ml', colour:'#C9302C'},
  'Citrate plasma':           {tube:'Citrate (light-blue)',  volume:'2.7 ml',colour:'#3B7DD8'},
  'Fluoride plasma':          {tube:'Fluoride (grey-top)',   volume:'2 ml', colour:'#6B7280'},
  'Sodium heparin whole blood':{tube:'Heparin (green-top)',  volume:'4 ml', colour:'#2F7A36'},
  'BACTEC bottle':            {tube:'Aerobic + anaerobic culture bottles', volume:'10 ml × 2', colour:'#1A4D5E'}
};

function findTest(code){
  for(const tests of Object.values(APP_STATE.testCatalog)){
    const t = tests.find(x=>x.code===code);
    if(t) return t;
  }
  return null;
}

// Returns the effective price for a test, applying tenant override if present
function getPrice(code){
  const tid = S().activeTenantId;
  const overrides = (APP_STATE.tenantPricing && APP_STATE.tenantPricing[tid]) || {};
  if(overrides[code] !== undefined) return overrides[code];
  const t = findTest(code);
  return t ? t.price : 0;
}

// Returns true if this test has a tenant-specific override
function hasPriceOverride(code){
  const tid = S().activeTenantId;
  const overrides = (APP_STATE.tenantPricing && APP_STATE.tenantPricing[tid]) || {};
  return overrides[code] !== undefined;
}

// Set / clear a tenant override
function setTenantPrice(code, price){
  const tid = S().activeTenantId;
  if(!APP_STATE.tenantPricing) APP_STATE.tenantPricing = {};
  if(!APP_STATE.tenantPricing[tid]) APP_STATE.tenantPricing[tid] = {};
  if(price === null || price === '' || price === undefined){
    delete APP_STATE.tenantPricing[tid][code];
  } else {
    APP_STATE.tenantPricing[tid][code] = Number(price);
  }
  if(typeof OfflineCore !== 'undefined'){
    OfflineCore.schedulePersist();
    OfflineCore.record('pricing.set', {tenantId:tid, code, price}, `Pricing: ${code} → ${price === null ? 'baseline' : '₦'+price}`);
  }
}


/* ==========================================================
   PATIENT COMBOBOX ENGINE — shared across all modals
   All patient-selection fields use these helpers so the
   combobox logic is written once and applied everywhere.
   State lives in window.PC_STATE keyed by fieldId.
   ========================================================== */

function patientComboHtml(fieldId, opts){
  // opts: { placeholder, hint, prefillId }
  opts = opts || {};
  const prefill = opts.prefillId
    ? (APP_STATE.patients||[]).find(p=>p.id===opts.prefillId) : null;
  const initLabel = prefill ? prefill.name+' — '+prefill.id : '';
  const initId    = prefill ? prefill.id : null;
  if(!window.PC_STATE) window.PC_STATE = {};
  window.PC_STATE[fieldId] = { patientId: initId, patientLabel: initLabel, filterFn: opts.filterFn||null };
  const tick = initId
    ? `<span class="pc-tick" style="position:absolute;right:8px;top:50%;transform:translateY(-50%);color:var(--success-ink);font-size:14px;pointer-events:none">✓</span>` : '';
  const hintHtml = initId
    ? `<span style="color:var(--success-ink)">✓ ${esc(initLabel)}</span>`
    : (opts.hint || 'Type name, phone or hospital number to search.');
  return `<div style="position:relative" id="pc-wrap-${esc(fieldId)}">
    <input
      class="input"
      id="pc-input-${esc(fieldId)}"
      role="combobox"
      autocomplete="off"
      aria-autocomplete="list"
      aria-expanded="false"
      aria-controls="pc-list-${esc(fieldId)}"
      aria-haspopup="listbox"
      placeholder="${esc(opts.placeholder || 'Search or select patient…')}"
      value="${esc(initLabel)}"
      style="padding-right:28px"
      oninput="pcSearch('${esc(fieldId)}',this.value)"
      onfocus="pcSearch('${esc(fieldId)}',this.value)"
      onkeydown="pcKey('${esc(fieldId)}',event)"
    />${tick}
    <ul id="pc-list-${esc(fieldId)}" role="listbox" aria-label="Patient suggestions"
      style="display:none;position:absolute;top:100%;left:0;right:0;z-index:9999;margin:0;padding:4px 0;list-style:none;background:var(--card-bg,#fff);border:1px solid var(--line);border-radius:6px;box-shadow:0 4px 16px rgba(0,0,0,.10);max-height:220px;overflow-y:auto;font-size:13px">
    </ul>
  </div>
  <div id="pc-hint-${esc(fieldId)}" class="muted-sm" style="margin-top:4px;font-size:11px">${hintHtml}</div>`;
}

function pcSearch(fieldId, query){
  const list  = document.getElementById('pc-list-'+fieldId);
  const hint  = document.getElementById('pc-hint-'+fieldId);
  if(!list) return;
  if(!window.PC_STATE) window.PC_STATE = {};
  const state = window.PC_STATE[fieldId] || (window.PC_STATE[fieldId]={patientId:null,patientLabel:''});
  const q = (query||'').toLowerCase().trim();

  if(!q){
    state.patientId = null; state.patientLabel = '';
    list.style.display = 'none';
    const inp = document.getElementById('pc-input-'+fieldId);
    if(inp) inp.setAttribute('aria-expanded','false');
    if(hint) hint.innerHTML = 'Type name, phone or hospital number to search.';
    return;
  }
  // If query exactly matches the confirmed label, keep selection and hide dropdown.
  if(state.patientLabel && query === state.patientLabel){
    list.style.display = 'none';
    const inp = document.getElementById('pc-input-'+fieldId);
    if(inp) inp.setAttribute('aria-expanded','false');
    return;
  }
  // User is editing — clear the stale selection.
  if(state.patientId && query !== state.patientLabel){
    state.patientId = null; state.patientLabel = '';
    if(hint) hint.innerHTML = 'Select a patient from the list…';
  }
  const FILTERS = { renal: p => !!p.renal };
  const filterFn = state.filterFn && FILTERS[state.filterFn];
  const matches = (APP_STATE.patients||[]).filter(p=>{
    if(filterFn && !filterFn(p)) return false;
    return (p.name||'').toLowerCase().includes(q)
        || (p.id||'').toLowerCase().includes(q)
        || (p.phone||'').toLowerCase().includes(q);
  }).slice(0,12);

  if(!matches.length){
    list.innerHTML = `<li style="padding:10px 14px;color:var(--ink-soft);pointer-events:none">No patients matched. <a onclick="closeModal();setTimeout(()=>openModal('register-patient'),50)" style="color:var(--accent);cursor:pointer">Register a new patient?</a></li>`;
    list.style.display = 'block'; return;
  }
  list.innerHTML = matches.map(p=>{
    const age = p.dob ? Math.floor((Date.now()-new Date(p.dob))/31557600000) : null;
    const meta = [p.id, age!=null?age+'y':null, p.gender, p.phone].filter(Boolean).join(' · ');
    const label = p.name+' — '+p.id;
    return `<li role="option" aria-selected="false" data-pid="${esc(p.id)}" data-label="${esc(label)}"
      tabindex="-1"
      style="padding:8px 14px;cursor:pointer;display:flex;flex-direction:column;gap:1px"
      onmousedown="pcSelect('${esc(fieldId)}','${esc(p.id)}','${esc(label)}')"
      onmouseover="this.style.background='var(--bg-soft)'"
      onmouseout="this.style.background=''">
      <span style="font-weight:500">${esc(p.name)}</span>
      <span style="font-size:11px;color:var(--ink-soft)">${esc(meta)}</span>
    </li>`;
  }).join('');
  list.style.display = 'block';
  const inp2 = document.getElementById('pc-input-'+fieldId);
  if(inp2) inp2.setAttribute('aria-expanded','true');
}

function pcKey(fieldId, evt){
  const list = document.getElementById('pc-list-'+fieldId);
  if(!list || list.style.display==='none') return;
  const items = [...list.querySelectorAll('li[data-pid]')];
  if(!items.length) return;
  const cur = list.querySelector('li[data-active="1"]');
  let idx = cur ? items.indexOf(cur) : -1;
  if(evt.key==='ArrowDown'){
    evt.preventDefault();
    if(cur) cur.removeAttribute('data-active'); cur && (cur.style.background='');
    idx = Math.min(idx+1,items.length-1);
    items[idx].setAttribute('data-active','1'); items[idx].style.background='var(--bg-soft)';
    items[idx].scrollIntoView({block:'nearest'});
  } else if(evt.key==='ArrowUp'){
    evt.preventDefault();
    if(cur) cur.removeAttribute('data-active'); cur && (cur.style.background='');
    idx = Math.max(idx-1,0);
    items[idx].setAttribute('data-active','1'); items[idx].style.background='var(--bg-soft)';
    items[idx].scrollIntoView({block:'nearest'});
  } else if(evt.key==='Enter' && idx>=0){
    evt.preventDefault();
    pcSelect(fieldId, items[idx].dataset.pid, items[idx].dataset.label);
  } else if(evt.key==='Escape'){
    list.style.display='none';
  }
}

function pcSelect(fieldId, pid, label){
  if(!window.PC_STATE) window.PC_STATE = {};
  window.PC_STATE[fieldId] = { patientId:pid, patientLabel:label };
  const input = document.getElementById('pc-input-'+fieldId);
  const list  = document.getElementById('pc-list-'+fieldId);
  const hint  = document.getElementById('pc-hint-'+fieldId);
  const wrap  = document.getElementById('pc-wrap-'+fieldId);
  if(input){ input.value = label; input.setAttribute('aria-expanded','false'); }
  if(list){
    list.style.display = 'none';
    // Mark the selected option
    [...list.querySelectorAll('[role="option"]')].forEach(li => {
      li.setAttribute('aria-selected', li.dataset.pid === pid ? 'true' : 'false');
    });
  }
  if(hint)  hint.innerHTML = `<span style="color:var(--success-ink)">✓ ${esc(label)}</span>`;
  if(wrap){
    let tick = wrap.querySelector('.pc-tick');
    if(!tick){ tick=document.createElement('span'); tick.className='pc-tick';
      tick.setAttribute('style','position:absolute;right:8px;top:50%;transform:translateY(-50%);color:var(--success-ink);font-size:14px;pointer-events:none');
      tick.setAttribute('aria-hidden','true');
      wrap.appendChild(tick); }
    tick.textContent='✓';
  }
}

// Returns the patient object for fieldId, or null if nothing selected.
// Submit handlers call this instead of APP_STATE.patients.find($v(fieldId)).
function pcPatient(fieldId){
  const st = window.PC_STATE && window.PC_STATE[fieldId];
  if(!st || !st.patientId) return null;
  return (APP_STATE.patients||[]).find(p=>p.id===st.patientId)||null;
}

// Validates the combobox selection; shows a toast and focuses the input if
// nothing is selected. Returns true if blocked, false if OK.
function pcRequire(fieldId, label){
  const p = pcPatient(fieldId);
  if(p) return false;
  const input = document.getElementById('pc-input-'+fieldId);
  if(input){ input.focus(); input.style.borderColor='#9A1F1F'; setTimeout(()=>input.style.borderColor='',3000); }
  toast(`Select a ${label||'patient'} before submitting`, {type:'error', title:'Patient required'});
  return true; // blocked
}

// Open the new test request modal, optionally pre-filling a patient.
// Used by the patient detail page "+ New test request" button so the
// clinician doesn't have to re-search for a patient they're already viewing.
function openNewRequest(patientId){
  if(patientId) window._rxPrefillPatientId = patientId;
  // Reset selected tests for a fresh request but preserve other RX_STATE.
  if(!window.RX_STATE) window.RX_STATE = {};
  RX_STATE.selected  = new Set(['FBC','LFT']);
  RX_STATE.search    = '';
  RX_STATE.priority  = 'Routine';
  RX_STATE.expanded  = new Set(['Hematology','Chemical Pathology']);
  openModal('new-request');
}

function rxPatientSearch(query){
  const list  = document.getElementById('rx-patient-list');
  const hint  = document.getElementById('rx-patient-hint');
  if(!list) return;

  const q = (query||'').toLowerCase().trim();

  // If the user clears the field, deselect the patient.
  if(!q){
    RX_STATE.patientId    = null;
    RX_STATE.patientLabel = '';
    list.style.display = 'none';
    if(hint) hint.innerHTML = 'Start typing to search by name, phone, or hospital number.';
    return;
  }

  // If they're editing the box but the value still matches the confirmed label,
  // keep the selection but still show the dropdown in case they want to change.
  if(RX_STATE.patientLabel && query === RX_STATE.patientLabel){
    // Selection still valid — just re-render confirmation state.
    list.style.display = 'none';
    return;
  }

  // Clear a stale selection while the user is actively searching.
  if(RX_STATE.patientId && query !== RX_STATE.patientLabel){
    RX_STATE.patientId    = null;
    RX_STATE.patientLabel = '';
    if(hint) hint.innerHTML = 'Select a patient from the list…';
  }

  const patients = APP_STATE.patients || [];
  const matches = patients.filter(p =>{
    const name  = (p.name||'').toLowerCase();
    const pid   = (p.id||'').toLowerCase();
    const phone = (p.phone||'').toLowerCase();
    return name.includes(q) || pid.includes(q) || phone.includes(q);
  }).slice(0, 12); // cap at 12 results for readability

  if(!matches.length){
    list.innerHTML = `<li style="padding:10px 14px;color:var(--ink-soft);pointer-events:none">No patients matched. <a onclick="closeModal();setTimeout(()=>openModal('register-patient'),50)" style="color:var(--accent);cursor:pointer">Register a new patient?</a></li>`;
    list.style.display = 'block';
    return;
  }

  list.innerHTML = matches.map((p, idx) => {
    const age = p.dob ? Math.floor((Date.now() - new Date(p.dob))/ 31557600000) : null;
    const meta = [p.id, age != null ? age+'y' : null, p.gender, p.phone].filter(Boolean).join(' · ');
    return `<li
      role="option"
      data-pid="${esc(p.id)}"
      data-label="${esc(p.name + ' — ' + p.id)}"
      tabindex="-1"
      style="padding:8px 14px;cursor:pointer;display:flex;flex-direction:column;gap:1px;border-radius:0"
      onmousedown="rxSelectPatient('${esc(p.id)}','${esc(p.name)} — ${esc(p.id)}')"
      onmouseover="rxPatientListHover(this)"
    >
      <span style="font-weight:500">${esc(p.name)}</span>
      <span style="font-size:11px;color:var(--ink-soft)">${esc(meta)}</span>
    </li>`;
  }).join('');
  list.style.display = 'block';
}

// Highlight an item on mouseover (also used by keyboard nav).
function rxPatientListHover(el){
  const list = document.getElementById('rx-patient-list');
  if(!list) return;
  [...list.querySelectorAll('li')].forEach(li => li.style.background='');
  el.style.background = 'var(--bg-soft)';
}

// Keyboard navigation: Arrow ↓/↑ move through results; Enter selects; Escape closes.
function rxPatientKey(evt){
  const list = document.getElementById('rx-patient-list');
  if(!list || list.style.display === 'none') return;
  const items = [...list.querySelectorAll('li[data-pid]')];
  if(!items.length) return;
  const active = list.querySelector('li[style*="var(--bg-soft)"]');
  let idx = active ? items.indexOf(active) : -1;
  if(evt.key === 'ArrowDown'){
    evt.preventDefault();
    idx = Math.min(idx + 1, items.length - 1);
    items.forEach(li => li.style.background='');
    items[idx].style.background = 'var(--bg-soft)';
    items[idx].scrollIntoView({block:'nearest'});
  } else if(evt.key === 'ArrowUp'){
    evt.preventDefault();
    idx = Math.max(idx - 1, 0);
    items.forEach(li => li.style.background='');
    items[idx].style.background = 'var(--bg-soft)';
    items[idx].scrollIntoView({block:'nearest'});
  } else if(evt.key === 'Enter' && idx >= 0){
    evt.preventDefault();
    const chosen = items[idx];
    rxSelectPatient(chosen.dataset.pid, chosen.dataset.label);
  } else if(evt.key === 'Escape'){
    list.style.display = 'none';
  }
}

// Confirm the selected patient, update the input and hint, and close the dropdown.
function rxSelectPatient(pid, label){
  RX_STATE.patientId    = pid;
  RX_STATE.patientLabel = label;
  const input = document.getElementById('rx-patient-input');
  const list  = document.getElementById('rx-patient-list');
  const hint  = document.getElementById('rx-patient-hint');
  if(input) input.value = label;
  if(list)  list.style.display = 'none';
  if(hint)  hint.innerHTML = `<span style="color:var(--success-ink)">✓ ${esc(label)}</span>`;
  // Re-render the wrap to show the green tick without a full modal re-render.
  const wrap = document.getElementById('rx-patient-wrap');
  if(wrap){
    let tick = wrap.querySelector('span[style*="pointer-events:none"]');
    if(!tick){
      tick = document.createElement('span');
      tick.setAttribute('style','position:absolute;right:8px;top:50%;transform:translateY(-50%);color:var(--success-ink);font-size:14px;pointer-events:none');
      wrap.appendChild(tick);
    }
    tick.textContent = '✓';
  }
}

function rxToggle(code){
  if(RX_STATE.selected.has(code)) RX_STATE.selected.delete(code);
  else RX_STATE.selected.add(code);
  // Re-render in place
  document.querySelector('.modal').outerHTML = '<div class="modal">'+renderNewRequestModal()+'</div>';
}
function rxAddPanel(codes){
  codes.forEach(c=>RX_STATE.selected.add(c));
  document.querySelector('.modal').outerHTML = '<div class="modal">'+renderNewRequestModal()+'</div>';
}
function rxClear(){
  RX_STATE.selected.clear();
  document.querySelector('.modal').outerHTML = '<div class="modal">'+renderNewRequestModal()+'</div>';
}
function rxToggleCategory(cat){
  if(RX_STATE.expanded.has(cat)) RX_STATE.expanded.delete(cat);
  else RX_STATE.expanded.add(cat);
  document.querySelector('.modal').outerHTML = '<div class="modal">'+renderNewRequestModal()+'</div>';
}
function rxSearch(val){
  RX_STATE.search = val.toLowerCase();
  // Re-render the catalog area only (keep search input focus)
  const el = document.getElementById('rx-catalog');
  if(el) el.innerHTML = renderRxCatalog();
  const sb = document.getElementById('rx-sidebar');
  if(sb) sb.innerHTML = renderRxSidebar();
}

function renderRxCatalog(){
  const q = RX_STATE.search;
  let html = '';
  for(const [cat, tests] of Object.entries(APP_STATE.testCatalog)){
    // Filter by search
    const visible = q
      ? tests.filter(t => t.name.toLowerCase().includes(q) || t.code.toLowerCase().includes(q))
      : tests;
    if(q && visible.length === 0) continue;
    // When searching, force expand all matching categories
    const isOpen = q ? true : RX_STATE.expanded.has(cat);
    const selectedInCat = tests.filter(t=>RX_STATE.selected.has(t.code)).length;

    html += `<div class="rx-cat ${isOpen?'open':''}">
      <div class="rx-cat-header" onclick="${q?'':"rxToggleCategory('"+cat.replace(/'/g,"'")+"')"}">
        <span class="rx-chev">›</span>
        <span class="rx-cat-name">${cat}</span>
        <span class="rx-cat-count">${visible.length}${selectedInCat?' · <b>'+selectedInCat+' selected</b>':''}</span>
      </div>
      <div class="rx-cat-body">
        ${visible.map(t=>{
          const sel = RX_STATE.selected.has(t.code);
          const flags = [];
          if(t.fasting) flags.push('<span class="rx-flag fasting">Fasting</span>');
          if(t.sendOut) flags.push('<span class="rx-flag sendout">Send-out</span>');
          if(t.renal) flags.push('<span class="rx-flag renal">Renal</span>');
          if(t.criticalCallback) flags.push('<span class="rx-flag critical">Critical callback</span>');
          return `<label class="rx-test ${sel?'sel':''}" onclick="event.preventDefault();rxToggle('${t.code}')">
            <input type="checkbox" ${sel?'checked':''} onclick="event.stopPropagation();rxToggle('${t.code}')"/>
            <div class="rx-test-info">
              <div class="rx-test-name">${t.name}</div>
              <div class="rx-test-meta">${t.code} · ${t.turnaround} · ${t.specimen}${flags.length?' &nbsp; '+flags.join(' '):''}</div>
            </div>
            <div class="rx-test-price">${naira(getPrice(t.code))}${hasPriceOverride(t.code)?' <span style="font-size:9px;color:var(--ink-faint);font-weight:400" title="Your laboratory price">·custom</span>':''}</div>
          </label>`;
        }).join('')}
      </div>
    </div>`;
  }
  if(html==='') html = '<div style="padding:30px;text-align:center;color:var(--ink-soft);font-size:13px">No tests match "<b>'+q+'</b>"</div>';
  return html;
}

function renderRxSidebar(){
  const selected = [...RX_STATE.selected].map(findTest).filter(Boolean);
  const total = selected.reduce((s,t)=>s+getPrice(t.code),0);
  const tubesNeeded = {};
  let anyFasting = false, anySendOut = false, anyCritical = false;
  for(const t of selected){
    const tube = TUBE_FOR_SPECIMEN[t.specimen];
    const key = tube ? tube.tube : t.specimen;
    if(!tubesNeeded[key]) tubesNeeded[key] = {count:0, tests:[], colour:tube?tube.colour:'#6B7280', volume:tube?tube.volume:''};
    tubesNeeded[key].count++;
    tubesNeeded[key].tests.push(t.code);
    if(t.fasting) anyFasting = true;
    if(t.sendOut) anySendOut = true;
    if(t.criticalCallback) anyCritical = true;
  }

  let banners = '';
  if(anyFasting) banners += '<div class="rx-banner fasting">⏱ Patient must fast 8–12h before sample collection</div>';
  if(anySendOut) banners += '<div class="rx-banner sendout">📦 Some tests are send-outs · TAT depends on partner lab</div>';
  if(anyCritical) banners += '<div class="rx-banner critical">⚠ Critical-callback tests · phone-call protocol on abnormal results</div>';

  return `
    <div class="rx-sb-section">
      <div class="rx-sb-title">Selected tests <span class="rx-sb-count">${selected.length}</span></div>
      ${selected.length===0 ? '<div class="rx-sb-empty">No tests selected yet. Search or pick from a panel.</div>' : ''}
      ${selected.map(t=>`
        <div class="rx-sb-item">
          <div>
            <div class="rx-sb-name">${t.name}</div>
            <div class="rx-sb-code">${t.code} · ${t.turnaround}</div>
          </div>
          <div class="rx-sb-right">
            <span class="rx-sb-price">${naira(getPrice(t.code))}</span>
            <button class="rx-sb-remove" onclick="rxToggle('${t.code}')">×</button>
          </div>
        </div>
      `).join('')}
    </div>
    ${selected.length ? `
    <div class="rx-sb-section">
      <div class="rx-sb-title">Specimen tubes required</div>
      ${Object.entries(tubesNeeded).map(([tube,info])=>`
        <div class="rx-tube">
          <span class="rx-tube-dot" style="background:${info.colour}"></span>
          <div style="flex:1">
            <div style="font-size:12px;font-weight:500">${info.count} × ${tube}</div>
            <div style="font-size:10px;color:var(--ink-soft)">${info.volume?info.volume+' · ':''}for ${info.tests.join(', ')}</div>
          </div>
        </div>
      `).join('')}
    </div>` : ''}
    ${banners ? '<div class="rx-sb-section">'+banners+'</div>' : ''}
    <div class="rx-sb-total">
      <span>Total</span>
      <strong>${naira(total)}</strong>
    </div>
  `;
}

function renderNewRequestModal(){
  return `
    <div class="modal-header"><div class="modal-title">New test request</div><button class="close-btn" onclick="closeModal()">×</button></div>
    <div class="modal-body" style="padding:0;display:grid;grid-template-columns:1fr 340px;gap:0;overflow:hidden">
      <div style="padding:20px 24px;overflow-y:auto;border-right:1px solid var(--line)">

        <div class="section-divider"><span class="label">Patient &amp; clinician</span><div class="line"></div></div>
        <div class="form-grid">
          <div class="field" style="grid-column:span 2">
            <label>Search or select patient<span class="req">*</span></label>
            <div style="position:relative" id="rx-patient-wrap">
              <input
                id="rx-patient-input"
                autocomplete="off"
                placeholder="Type name, phone or hospital number…"
                oninput="rxPatientSearch(this.value)"
                onfocus="rxPatientSearch(this.value)"
                onkeydown="rxPatientKey(event)"
                value="${RX_STATE.patientLabel||''}"
                style="padding-right:28px"
              />
              ${RX_STATE.patientId
                ? `<span style="position:absolute;right:8px;top:50%;transform:translateY(-50%);color:var(--success-ink);font-size:14px;pointer-events:none">✓</span>`
                : ''}
              <ul id="rx-patient-list" role="listbox" style="display:none;position:absolute;top:100%;left:0;right:0;z-index:9999;margin:0;padding:4px 0;list-style:none;background:var(--card-bg,#fff);border:1px solid var(--line);border-radius:6px;box-shadow:0 4px 16px rgba(0,0,0,0.10);max-height:220px;overflow-y:auto;font-size:13px"></ul>
            </div>
            <div id="rx-patient-hint" class="muted-sm" style="margin-top:4px;font-size:11px">
              ${RX_STATE.patientId
                ? `<span style="color:var(--success-ink)">✓ ${esc(RX_STATE.patientLabel)}</span>`
                : 'Start typing to search by name, phone, or hospital number. Walk-in patients can be registered first.'}
            </div>
          </div>
          <div class="field"><label>Requesting clinician</label><input id="rx-clinician" value="Dr. Adekunle Smith"></div>
          <div class="field"><label>Priority</label><select id="rx-priority" onchange="RX_STATE.priority=this.value"><option ${RX_STATE.priority==='Routine'?'selected':''}>Routine</option><option ${RX_STATE.priority==='Urgent'?'selected':''}>Urgent</option><option ${RX_STATE.priority==='Critical'?'selected':''}>Critical</option></select></div>
          <div class="field" style="grid-column:span 2"><label>Clinical history / indication</label><input id="rx-indication" placeholder="e.g. Anaemia workup; lethargy × 2 weeks"></div>
        </div>

        <div class="section-divider" style="margin-top:18px"><span class="label">Common panels</span><div class="line"></div></div>
        <div class="rx-panels">
          ${COMMON_PANELS.map(p=>`<button class="rx-panel-chip" onclick="rxAddPanel(${JSON.stringify(p.codes).replace(/"/g,'&quot;')})">+ ${p.label}</button>`).join('')}
        </div>

        <div class="section-divider" style="margin-top:18px"><span class="label">Test catalogue · 267 tests across 18 categories</span><div class="line"></div></div>
        <div class="rx-searchbar">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
          <input type="text" placeholder="Search by test name or code…" value="${RX_STATE.search}" oninput="rxSearch(this.value)" autofocus>
          ${RX_STATE.search?`<button class="rx-clear" onclick="rxSearch('');document.querySelector('.rx-searchbar input').value=''">Clear</button>`:''}
        </div>

        <div id="rx-catalog">${renderRxCatalog()}</div>

      </div>
      <div style="background:var(--bg-soft);padding:20px;overflow-y:auto" id="rx-sidebar">
        ${renderRxSidebar()}
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn" onclick="closeModal()">Cancel</button>
      <button class="btn" onclick="rxClear()">Clear all</button>
      <button class="btn" onclick="saveAsDraft(\'modal\')">Save as draft</button>
      <button class="btn primary" onclick="submitNewRequest()">Create &amp; send to cashier</button>
    </div>
  `;
}

