function sectionIcon(key, size){
  const s = size || 22;
  const path = SECTION_ICONS[key];
  if(!path) return '';
  return `<svg width="${s}" height="${s}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">${path}</svg>`;
}

const HELP_ARTICLES = {
  'getting-started': [
    {id:'gs-1', title:'Welcome to LabOS', read:'3 min', body:`
      <h2>What LabOS does for your laboratory</h2>
      <p>LabOS is a complete laboratory information management system (LIMS) built for clinical labs in Nigeria and across Africa. It handles patient registration, test ordering, sample tracking, results entry and validation, report release, billing, inventory, and specialty workflows like renal, histopathology, DNA &amp; genetics, and health packages.</p>
      <h2>Who uses LabOS</h2>
      <ul>
        <li><b>Lab directors and pathologists</b> — sign off reports, validate critical results, oversee operations</li>
        <li><b>Medical laboratory scientists</b> — enter and review results, manage QC</li>
        <li><b>Front-desk officers</b> — register patients, create requests, take payments</li>
        <li><b>Cashiers</b> — process invoices, reconcile Paystack and cash payments</li>
        <li><b>Nurses and phlebotomists</b> — collect samples, mark chain of custody, capture vitals</li>
        <li><b>Inventory officers</b> — track reagents, kits and consumables</li>
        <li><b>Tenant administrators</b> — manage staff, branches, subscription, pricing</li>
      </ul>
      <div class="tip"><b>Tip:</b> Each user only sees the modules and actions their role permits. The Staff &amp; Roles page (admin only) controls who can do what — a 13-role × 12-permission matrix.</div>
    `},
    {id:'gs-2', title:'Your first day: a 15-minute walkthrough', read:'15 min', body:`
      <h2>Step 1 — Register a patient</h2>
      <p>From the sidebar, click <code>Patients → + Register patient</code>. Fill in name, date of birth, sex and phone number. The hospital number is auto-generated in the format <code>PT-2026-NNNN</code>. If the patient uses NHIS or an HMO, capture the policy number now.</p>
      <h2>Step 2 — Create a test request</h2>
      <p>Click <code>+ New test request</code> from any page. Search for the patient, select the requesting clinician and priority, then pick tests from the catalogue — 267 tests grouped into 18 categories. Use the <b>common-panels</b> chips (Antenatal, Diabetes Workup, etc.) for one-tap selection. The sidebar shows which specimen tubes phlebotomy will need.</p>
      <h2>Step 3 — Collect samples</h2>
      <p>The request moves to <b>Sample tracking</b>. Phlebotomy scans the barcode on each tube, records collection time and any condition notes (haemolysis, lipaemia, etc.). Samples then route to the appropriate bench.</p>
      <h2>Step 4 — Enter results</h2>
      <p>From <b>Results management</b>, the assigned scientist enters numerical results. The system flags High (H), Low (L) and Critical (CRIT) values against age- and sex-specific reference ranges. Two-person validation is required for critical-callback tests (troponin, MTB/Rif, paracetamol level, etc.).</p>
      <h2>Step 5 — Release the report</h2>
      <p>The pathologist or lab director clicks <code>Release report</code>. A two-factor confirmation seals the report; PDF copies are generated, watermarked, and either downloaded, emailed via SendGrid, or sent over WhatsApp. The patient invoice updates to <code>Paid · Report ready</code>.</p>
    `},
    {id:'gs-3', title:'Setting up two-factor authentication', read:'4 min', body:`
      <h2>Why 2FA is required</h2>
      <p>LabOS handles regulated health information. Two-factor authentication is required on every account that can release a report, modify staff permissions, or access billing.</p>
      <h2>Supported methods</h2>
      <ul>
        <li><b>Authenticator app</b> (Google Authenticator, Authy, 1Password) — recommended</li>
        <li><b>SMS to a Nigerian phone number</b> — fallback option, requires Termii</li>
        <li><b>Hardware key (FIDO2/WebAuthn)</b> — Yubikey or similar, available on Enterprise</li>
      </ul>
      <h2>Setting it up</h2>
      <ol>
        <li>Click your name in the bottom-left of the sidebar</li>
        <li>Choose <b>Security &amp; sign-in</b></li>
        <li>Tap <b>Set up 2FA</b> and scan the QR code with your authenticator app</li>
        <li>Enter the 6-digit code to confirm. Save the 10 recovery codes somewhere safe — you will need them if you lose your device.</li>
      </ol>
      <div class="warn"><b>Warning:</b> Once 2FA is enabled, you cannot remove it without re-entering it. If you lose both your device and your recovery codes, an admin must reset your account.</div>
    `},
    {id:'gs-4', title:'Understanding plans & entitlements', read:'5 min', body:`
      <h2>The four LabOS plans</h2>
      <table style="width:100%;border-collapse:collapse;font-size:13px;margin-bottom:12px">
        <thead><tr style="background:var(--bg-soft)"><th style="padding:8px;text-align:left">Plan</th><th style="padding:8px;text-align:right">Annual</th><th style="padding:8px;text-align:center">Centres</th><th style="padding:8px;text-align:center">Staff</th><th style="padding:8px;text-align:center">Patients/mo</th></tr></thead>
        <tbody>
          <tr><td style="padding:8px"><b>CoreCare</b></td><td style="padding:8px;text-align:right">₦180,000</td><td style="padding:8px;text-align:center">1</td><td style="padding:8px;text-align:center">10</td><td style="padding:8px;text-align:center">1,500</td></tr>
          <tr style="background:var(--bg-soft)"><td style="padding:8px"><b>Standard</b></td><td style="padding:8px;text-align:right">₦540,000</td><td style="padding:8px;text-align:center">3</td><td style="padding:8px;text-align:center">25</td><td style="padding:8px;text-align:center">5,000</td></tr>
          <tr><td style="padding:8px"><b>Professional</b> ⭐</td><td style="padding:8px;text-align:right">₦1,080,000</td><td style="padding:8px;text-align:center">10</td><td style="padding:8px;text-align:center">60</td><td style="padding:8px;text-align:center">20,000</td></tr>
          <tr style="background:var(--bg-soft)"><td style="padding:8px"><b>Enterprise</b></td><td style="padding:8px;text-align:right">₦2,880,000</td><td style="padding:8px;text-align:center">∞</td><td style="padding:8px;text-align:center">∞</td><td style="padding:8px;text-align:center">∞</td></tr>
        </tbody>
      </table>
      <h2>What each plan unlocks</h2>
      <ul>
        <li><b>CoreCare</b> — Core lab workflows plus Hematology, Microbiology, Immunology, and Clinical Health Packages. Ideal for independent single-location labs.</li>
        <li><b>Standard</b> — Everything in CoreCare, plus Renal &amp; Dialysis, Histopathology, and Toxicology. For established diagnostic centres with specialty services.</li>
        <li><b>Professional</b> — Everything in Standard, plus Molecular Diagnostics, Imaging (Ultrasound, Radiology, ECG, Echo), BiobankOS, Advanced Analytics, and API access (25k calls/month).</li>
        <li><b>Enterprise</b> — Every module including CT Scan, MRI, DNA &amp; Genetics, Research &amp; Genomics, white-label branding, and a dedicated database instance.</li>
      </ul>
      <h2>Centre limits are enforced</h2>
      <p>LabOS hard-enforces the centre limit for your plan. Professional plans cannot exceed 10 centres — adding an 11th requires upgrading to Enterprise or purchasing an Additional Centre Slot add-on (₦180,000/centre/year, up to 5 extra).</p>
      <h2>Upgrading mid-period</h2>
      <p>Upgrades are immediate — the price difference is prorated and charged via Paystack. Downgrades take effect at your next renewal so you keep full features until then.</p>
      <h2>Add-on fees</h2>
      <p>Optional add-ons include SMS/WhatsApp bundles, extra device slots, patient volume overage charges, white-label branding (Professional), disaster recovery backup, and support SLA upgrades. All available from <b>Subscription → Add-ons</b>.</p>
    `},
    {id:'gs-5', title:'Navigating the sidebar', read:'3 min', body:`
      <h2>How the sidebar is organised</h2>
      <p>The sidebar is grouped into three sections:</p>
      <ul>
        <li><b>Workspace</b> — your day-to-day clinical workflows: Dashboard, Patients, Test requests, Sample tracking, Results, Renal, Histopathology, Molecular, Imaging, DNA &amp; Genetics, Health Packages</li>
        <li><b>Operations</b> — Billing, Inventory, Analytics</li>
        <li><b>Administration</b> — Staff &amp; Roles, Tenant profile, Audit log, Pricing, Subscription, Settings (admin-only)</li>
      </ul>
      <h2>Active centre switcher</h2>
      <p>If your laboratory has multiple branches, the Active centre dropdown near the top of the sidebar lets you switch between them. Data is scoped per-centre by default but admins can run cross-branch reports.</p>
      <div class="tip"><b>Tip:</b> On smaller screens or mobile, the sidebar collapses into a slide-out drawer. Tap the hamburger icon in the topbar to open it.</div>
    `},
    {id:'gs-6', title:'Using the catalogue search', read:'3 min', body:`
      <h2>The dashboard search hero</h2>
      <p>At the top of the Dashboard, a large search box lets you search across 402 catalogue items: 267 lab tests + 66 imaging studies + 39 DNA tests + 30 health packages.</p>
      <h2>What you can type</h2>
      <ul>
        <li><b>Test code</b> — e.g. <code>FBC</code>, <code>BRCA</code>, <code>HBA</code></li>
        <li><b>Test name</b> — e.g. <code>full blood count</code>, <code>chest x-ray</code></li>
        <li><b>Patient-friendly terms (aliases)</b> — type <code>sickle cell</code> and find Haemoglobin Electrophoresis; type <code>sugar</code> and find FBS, RBS, HbA1c, OGTT</li>
        <li><b>Category names</b> — e.g. <code>hematology</code>, <code>microbiology</code></li>
      </ul>
      <h2>The keyboard command palette</h2>
      <p>Press <code>Ctrl+K</code> (or <code>⌘K</code> on Mac) anywhere in LabOS to open the global command palette. It searches pages, patients, requests, imaging orders, and the full catalogue. Pressing <code>/</code> on its own also opens it when you're not typing in a field.</p>
    `},
    {id:'gs-7', title:'Multi-tenant and multi-centre essentials', read:'4 min', body:`
      <h2>Tenant vs centre</h2>
      <p>A <b>tenant</b> is your laboratory organisation as a legal entity. A <b>centre</b> is a physical branch within that tenant. For example, Vitalis Diagnostics (tenant) might have three centres: Ikeja Main, Lekki Branch, and Abuja Wuse 2.</p>
      <h2>Data scoping</h2>
      <p>Most clinical data — patients, samples, requests — is scoped to the centre that created it. Patients can be referred between centres of the same tenant. Inventory is centre-specific by default but can be marked as a shared central store.</p>
      <h2>Cross-centre permissions</h2>
      <p>Staff are assigned to one or more centres. Lab directors and tenant admins see all centres in a single consolidated view. The Active centre switcher in the sidebar lets these users hop between branches.</p>
    `},
    {id:'gs-8', title:"Where to get help when you're stuck", read:'2 min', body:`
      <h2>In-app help</h2>
      <p>This Help &amp; Documentation section has 79 articles across 10 categories. Use the search box at the top to find articles by keyword.</p>
      <h2>Live chat (WhatsApp)</h2>
      <p>Message us on WhatsApp at <code>+234 803 412 9684</code>. We respond Mon–Fri, 8 AM – 6 PM WAT. Median first-response time is 4 minutes.</p>
      <h2>Email and phone</h2>
      <ul>
        <li>Email: <code>support@agorox.africa</code> — response within 8 hours</li>
        <li>Phone: <code>+234 803 412 9684</code> — Mon–Fri 8 AM – 6 PM WAT</li>
        <li>Submit a ticket from <b>Help &amp; Documentation → New ticket</b> — tracked and SLA-bound</li>
      </ul>
    `}
  ],

  'patients': [
    {id:'pt-1', title:'Registering a patient — required vs optional fields', read:'4 min', body:`
      <h2>What you must capture</h2>
      <ul>
        <li><b>Full name</b> — Nigerian convention is Surname-First-Middle, e.g. <i>Adeyemi James Olu</i>. Use the patient's NIN or passport spelling if available.</li>
        <li><b>Date of birth</b> — used to compute age for reference ranges. Age in years alone is acceptable if DOB is unknown.</li>
        <li><b>Sex</b> — biological sex; required for sex-specific reference ranges (haemoglobin, PSA, hCG)</li>
        <li><b>Phone number</b> — international format <code>+234 ...</code> recommended for SMS and WhatsApp delivery</li>
      </ul>
      <h2>What you should also capture</h2>
      <p>Hospital number, address, next of kin, blood group, genotype, allergies, NHIS or HMO policy number, occupation, nationality. These accelerate later visits and help with insurance claims.</p>
      <div class="tip"><b>Tip:</b> The patient ID (<code>PT-2026-NNNN</code>) is auto-generated and unique across your tenant. The hospital number is your internal reference and can be edited if your lab uses a separate numbering scheme.</div>
    `},
    {id:'pt-2', title:'Finding existing patients quickly', read:'3 min', body:`
      <h2>The patient search</h2>
      <p>On the Patients page, the search box matches against name, phone, hospital number, NHIS number, and email. Matching is fuzzy — typos and partial words still find the patient.</p>
      <h2>From anywhere</h2>
      <p>Use <code>Ctrl+K</code> (or <code>⌘K</code>) and start typing the patient's name. Patients appear at the top of the results, grouped by type.</p>
      <h2>By phone</h2>
      <p>Strip spaces and parentheses; LabOS normalises numbers. <code>+234 803 555 1234</code> and <code>08035551234</code> both match.</p>
    `},
    {id:'pt-3', title:'Merging duplicate patient records', read:'5 min', body:`
      <h2>Why duplicates happen</h2>
      <p>Patients sometimes get registered twice — different spellings, missing middle name, transposed digits in the phone number. LabOS provides a controlled merge so you don't lose history.</p>
      <h2>Performing a merge</h2>
      <ol>
        <li>Open the patient you want to <b>keep</b> (the surviving record)</li>
        <li>Click <code>Actions → Merge duplicate into this record</code></li>
        <li>Search for the duplicate by ID or name</li>
        <li>Review the side-by-side diff — confirm which fields keep which value</li>
        <li>Click <b>Merge</b> — all requests, results, vitals, invoices, and audit log entries from the duplicate are reassigned to the surviving record</li>
      </ol>
      <div class="warn"><b>Warning:</b> Merges are recorded in the audit log but cannot be undone. Only TENANT_ADMIN and LAB_DIRECTOR roles can perform merges.</div>
    `},
    {id:'pt-4', title:'Renal and chronic-disease tags', read:'3 min', body:`
      <h2>Tagging chronic patients</h2>
      <p>Patients with chronic conditions (CKD, diabetes, hypertension, sickle cell disease, HIV-positive on ART) can be tagged at the patient record level. Tags surface in Dashboard widgets, drive scheduling reminders, and unlock specialty modules like Renal &amp; Dialysis.</p>
      <h2>The renal tag specifically</h2>
      <p>Setting <code>renal: true</code> on a patient routes them to the Renal &amp; Dialysis module, where their dialysis sessions, dry weight tracking, vascular access notes, and renal panel results are aggregated into a longitudinal view.</p>
    `},
    {id:'pt-5', title:'Capturing vital signs', read:'3 min', body:`
      <h2>When to capture vitals</h2>
      <p>Capture vitals during patient triage at front-desk, before dialysis sessions, and on admission. The Capture vitals modal records: systolic and diastolic BP, heart rate, temperature, SpO₂, respiratory rate, weight, height (BMI is auto-computed), and a pain score.</p>
      <h2>Critical thresholds</h2>
      <p>LabOS flags critical vitals automatically:</p>
      <ul>
        <li>BP &lt; 90/60 or &gt; 180/110 mmHg</li>
        <li>SpO₂ &lt; 92%</li>
        <li>Temperature &gt; 39 °C or &lt; 35 °C</li>
        <li>Heart rate &lt; 45 or &gt; 130 bpm</li>
      </ul>
      <p>A critical vital triggers an alert to the on-call clinician and is recorded with a red flag in the patient's history.</p>
    `},
    {id:'pt-6', title:'Patient privacy and access controls', read:'4 min', body:`
      <h2>Who can see a patient record</h2>
      <p>Every authenticated user in your tenant can search and view basic biodata (name, age, sex). Sensitive fields (HIV status, mental health diagnoses, STI panels, paternity results) are protected by role:</p>
      <ul>
        <li>HIV results: clinical roles only (LAB_DIRECTOR, PATHOLOGIST, MED_LAB_SCIENTIST)</li>
        <li>Mental health: only specifically-authorised users (configured per-patient)</li>
        <li>STI / confidential panels: requesting clinician + lab director</li>
        <li>Paternity results: requesting party only (named on consent form)</li>
      </ul>
      <h2>Audit log</h2>
      <p>Every view of a sensitive field is logged with user, timestamp, and reason. The audit log is hash-chained — tampering is detectable.</p>
    `}
  ],

  'workflow': [
    {id:'wf-1', title:'The 7-stage test request workflow', read:'5 min', body:`
      <h2>How a request flows from order to report</h2>
      <ol>
        <li><b>Drafted</b> — created by front-desk; not yet billed</li>
        <li><b>Awaiting payment</b> — invoice raised; patient at cashier</li>
        <li><b>Sample pending</b> — paid; routed to phlebotomy</li>
        <li><b>Sample collected</b> — tubes drawn and labelled; en route to bench</li>
        <li><b>In progress</b> — analysis underway by med-lab scientist</li>
        <li><b>Awaiting validation</b> — results entered; pending second-person review</li>
        <li><b>Released</b> — pathologist signed off; report delivered</li>
      </ol>
      <div class="tip"><b>Tip:</b> The Dashboard turnaround widget tracks each stage's median time. If a category consistently overshoots its target TAT, the analytics page flags it as a bottleneck.</div>
    `},
    {id:'wf-2', title:'Handling critical results', read:'6 min', body:`
      <h2>The critical-result protocol</h2>
      <p>When a test flagged as <b>critical-callback</b> returns a critical value, LabOS triggers an immediate protocol:</p>
      <ol>
        <li>The result is locked from release until the protocol completes</li>
        <li>A WhatsApp message and SMS are sent to the requesting clinician (Termii fallback if WhatsApp fails)</li>
        <li>The receiving scientist must phone the clinician and log: name of person spoken to, time, and read-back confirmation</li>
        <li>The pathologist on call is notified for sign-off</li>
        <li>The audit log records each step with timestamps</li>
      </ol>
      <h2>Tests in this protocol</h2>
      <p>Troponin I/T, MTB/Rif PCR, CSF analysis, paracetamol level, salicylate level, GeneXpert TB PCR, positive blood culture, MRSA, critical electrolytes (K &lt; 2.5 or &gt; 6.5 mmol/L), glucose &lt; 2.5 or &gt; 25 mmol/L. The pathologist can mark any other result as critical from the results screen.</p>
    `},
    {id:'wf-3', title:'Creating a test request — the new-request modal', read:'4 min', body:`
      <h2>Opening the modal</h2>
      <p>Click <b>+ New test request</b> from the topbar, the Dashboard, or any patient detail page. Press <code>Ctrl+K</code> and type "new request" if you prefer keyboards.</p>
      <h2>Selecting tests</h2>
      <p>Browse 267 tests across 18 categories in the left pane. Each category is collapsible. Click a test to add it to the cart on the right; the cart totals the price (using your tenant's pricing) and lists which specimen tubes will be needed.</p>
      <h2>Common-panel chips</h2>
      <p>Above the catalogue, one-tap chips select the most-ordered bundles: <b>Antenatal Booking</b>, <b>Diabetes Workup</b>, <b>Renal Function</b>, <b>Liver Function</b>, <b>Thyroid</b>, <b>Lipid Profile</b>, <b>Pre-Marital Screen</b>, <b>Fertility</b>. These add 4–10 tests at once.</p>
      <h2>Priority</h2>
      <p>Routine, Urgent (+50% fee, prioritised in queue), or STAT (+100% fee, immediate processing). Choose carefully — STAT skips ahead of other patients' samples.</p>
    `},
    {id:'wf-4', title:'Sample collection and chain of custody', read:'5 min', body:`
      <h2>Phlebotomy workflow</h2>
      <p>After a request is paid, it appears in the Sample Tracking queue. The phlebotomist:</p>
      <ol>
        <li>Greets and identifies the patient (read-back: name + DOB)</li>
        <li>Scans the patient's wristband or hospital card</li>
        <li>Prints tube labels — LabOS prints exactly the tubes needed for the requested tests (EDTA, lithium heparin, serum separator, citrate, fluoride, urine, stool)</li>
        <li>Collects each tube and scans its barcode at the moment of draw</li>
        <li>Records any condition notes (haemolysis, lipaemia, clotted) and the time of last meal if fasting was required</li>
      </ol>
      <h2>Chain of custody</h2>
      <p>For legal-grade tests (paternity DNA, immigration DNA, chain-of-custody drug screens) the collector must be a designated DNA/Toxicology officer, the patient must present photo ID, and the sample is sealed in a tamper-evident envelope with a unique seal number recorded in LabOS.</p>
    `},
    {id:'wf-5', title:'Entering numerical results', read:'4 min', body:`
      <h2>The result-entry screen</h2>
      <p>From Results management, open a request and click <b>Enter results</b>. The screen shows each analyte with its reference range pre-populated for the patient's age and sex. Type the value or paste from your analyser.</p>
      <h2>Flags</h2>
      <p>LabOS auto-flags each value:</p>
      <ul>
        <li><b>Normal</b> — within reference range (no flag)</li>
        <li><b>H / L</b> — above / below reference range</li>
        <li><b>HH / LL</b> — beyond panic-value thresholds</li>
        <li><b>CRIT</b> — meets critical-callback criteria; locks until protocol completes</li>
      </ul>
      <h2>Comments and delta-check</h2>
      <p>Each result accepts a free-text comment. If the patient has a previous result for the same test in the last 30 days and the new value differs by &gt; 30%, LabOS shows a <b>delta-check warning</b> prompting you to verify before saving.</p>
    `},
    {id:'wf-6', title:'Two-person validation', read:'3 min', body:`
      <h2>What two-person validation means</h2>
      <p>For critical or high-stakes tests, a second user must independently review and approve the result before release. The validator must be at least at MED_LAB_SCIENTIST level; the original entry-person cannot self-validate.</p>
      <h2>How it works in practice</h2>
      <ol>
        <li>Scientist A enters and saves the result. Status moves to <b>Awaiting validation</b>.</li>
        <li>Scientist B opens Results management → Awaiting validation. They see the result and the original sample condition note.</li>
        <li>Scientist B either approves (status → Awaiting release) or rejects with reason (status → Re-run required).</li>
      </ol>
    `},
    {id:'wf-7', title:'Rerunning a sample', read:'3 min', body:`
      <h2>When to rerun</h2>
      <ul>
        <li>QC outside acceptable range for the batch</li>
        <li>Delta-check fail without a clinical explanation</li>
        <li>Validator rejects the entered result</li>
        <li>Sample condition issue (haemolysis, lipaemia) discovered after analysis</li>
      </ul>
      <h2>The rerun action</h2>
      <p>Click <b>Rerun</b> on the result. Pick a reason from the dropdown — this is mandatory and shows on the audit log. The original value is preserved (struck through) and a new entry is started. Reruns within 24 hours are at no extra charge to the patient.</p>
    `},
    {id:'wf-8', title:'Report release and signing', read:'5 min', body:`
      <h2>The release process</h2>
      <p>After validation, the pathologist or lab director opens the report preview, reviews the values and comments, and clicks <b>Release report</b>. A 2FA prompt confirms — once approved, the report is sealed and the patient is notified.</p>
      <h2>Delivery channels</h2>
      <ul>
        <li><b>Patient portal link</b> — every report gets a unique QR-code-protected URL valid for 6 months</li>
        <li><b>WhatsApp</b> — sent automatically if the patient consented at registration</li>
        <li><b>SMS</b> — via Termii, with a link to the portal</li>
        <li><b>Email</b> — via SendGrid, with PDF attached</li>
        <li><b>Print</b> — for patients who prefer paper</li>
      </ul>
      <h2>Amending after release</h2>
      <p>A released report cannot be edited. To correct an error, issue an <b>Amended report</b> — this creates a new versioned PDF flagged "AMENDED" with both the old and new value, and is automatically sent to anyone who received the original.</p>
    `},
    {id:'wf-9', title:'Working with sample rejections', read:'3 min', body:`
      <h2>Reasons a sample is rejected</h2>
      <ul>
        <li><b>Haemolysed</b> — interferes with K, LDH, AST, several enzymes</li>
        <li><b>Lipaemic</b> — interferes with photometric assays</li>
        <li><b>Clotted</b> — EDTA tube clotted before analysis</li>
        <li><b>Wrong tube</b> — e.g. EDTA blood sent for serum chemistry</li>
        <li><b>Insufficient volume</b> — &lt; minimum required for the requested tests</li>
        <li><b>Unlabelled / mislabelled</b> — patient identity cannot be confirmed</li>
        <li><b>Delay beyond stability window</b> — e.g. K analysed &gt; 4 hours after collection</li>
      </ul>
      <h2>The rejection workflow</h2>
      <p>The receiving scientist rejects the sample with a reason. The patient is notified (with apology) and asked to come for re-collection. Re-collection within 48 hours is free.</p>
    `},
    {id:'wf-10', title:'TAT (turnaround time) targets', read:'3 min', body:`
      <h2>Default targets</h2>
      <p>LabOS ships with sensible TAT defaults per test:</p>
      <ul>
        <li><b>FBC, urinalysis, electrolytes</b> — 2 hours</li>
        <li><b>Routine chemistry, lipid, LFT, KFT</b> — 4 hours</li>
        <li><b>Hormones, tumour markers, serology</b> — 24 hours</li>
        <li><b>Microbiology cultures</b> — 48–72 hours</li>
        <li><b>Histopathology (small specimen)</b> — 5–7 days</li>
        <li><b>Histopathology (complex / IHC)</b> — 10–14 days</li>
      </ul>
      <p>STAT requests have a 1-hour target across the board.</p>
      <h2>Tracking performance</h2>
      <p>The Analytics page shows median, p90 and p99 TAT for each test category over the last 30 days. Persistent overshoots flag as bottlenecks.</p>
    `},
    {id:'wf-11', title:'Bulk operations on a queue', read:'3 min', body:`
      <h2>Selecting multiple items</h2>
      <p>In Sample Tracking, Results management, and Billing, you can select multiple rows with the checkbox column or by holding Shift and clicking a range. The action bar appears at the top with bulk actions.</p>
      <h2>Available bulk actions</h2>
      <ul>
        <li><b>Sample Tracking</b> — bulk receive (mark as arrived at bench), bulk reject with same reason</li>
        <li><b>Results management</b> — bulk validate (only if you have permission for every test), bulk re-print labels</li>
        <li><b>Billing</b> — bulk send reminder SMS, bulk export to claim submission</li>
      </ul>
    `},
    {id:'wf-12', title:'The audit trail for every request', read:'3 min', body:`
      <h2>What is recorded</h2>
      <p>Every action on a request is recorded with user, timestamp, IP, and (where applicable) the previous value. The trail is hash-chained — any tampering breaks the chain and is flagged.</p>
      <h2>Viewing the trail</h2>
      <p>Open any request and click <b>Audit trail</b>. Filter by user, action type, or date. Export to CSV for offline review or court submission. The audit trail is read-only and cannot be edited or deleted by any user, including tenant admins.</p>
    `}
  ],

  'renal': [
    {id:'rn-1', title:'Setting up a renal patient', read:'4 min', body:`
      <h2>Marking a patient as renal</h2>
      <p>On the patient record, toggle <b>Renal patient</b> in the Clinical section. This unlocks the Renal &amp; Dialysis module for that patient and adds a Renal tag to their record.</p>
      <h2>Renal baseline</h2>
      <p>Capture: CKD stage (1–5), aetiology (diabetic nephropathy, hypertensive, glomerulonephritis, polycystic kidney disease, etc.), vascular access type (AV fistula / AV graft / tunnelled CVC), date of access creation, dry weight, target post-dialysis weight, dialysis schedule (MWF or T-Th-Sat), and nephrologist of record.</p>
    `},
    {id:'rn-2', title:'Logging a dialysis session', read:'5 min', body:`
      <h2>Starting a session</h2>
      <p>From the Renal module, click <b>+ New dialysis session</b>. Select the patient — the form pre-fills with their dry weight, access, dialysate composition, and prescription. Capture pre-dialysis vitals (BP, HR, temp, weight).</p>
      <h2>During the session</h2>
      <p>Record at 30-minute intervals: BP, blood flow rate (Qb), dialysate flow rate (Qd), UF rate, anticoagulation, symptoms (cramps, hypotension, vomiting). Any abnormal vital flags to the on-floor nurse station.</p>
      <h2>Closing the session</h2>
      <p>Record post-dialysis vitals and weight. Compute Kt/V if a urea was drawn. Note access condition, complications, and next session date.</p>
    `},
    {id:'rn-3', title:'Dry weight management', read:'3 min', body:`
      <h2>Why dry weight matters</h2>
      <p>Dry weight is the target post-dialysis weight at which the patient is normovolaemic. Setting it too high leaves the patient fluid-overloaded and hypertensive; too low causes intradialytic hypotension and cramping.</p>
      <h2>Adjusting dry weight</h2>
      <p>The nephrologist reviews dry weight at least monthly. From the patient's renal record, click <b>Adjust dry weight</b>, enter the new target and the clinical reason (hypertension despite UF, persistent cramps, oedema). The change is logged.</p>
    `},
    {id:'rn-4', title:'Vascular access tracking', read:'3 min', body:`
      <h2>Access types</h2>
      <ul>
        <li><b>AV fistula</b> — gold standard; native vein anastomosed to artery, matures over 6–12 weeks</li>
        <li><b>AV graft</b> — synthetic conduit; ready faster but higher infection rate</li>
        <li><b>Tunnelled CVC</b> — central venous catheter; bridge access while fistula matures</li>
        <li><b>Non-tunnelled CVC</b> — emergency access only; replace within 7 days</li>
      </ul>
      <h2>Access surveillance</h2>
      <p>LabOS prompts for access flow (Qa) measurement monthly for grafts, quarterly for fistulae. Flow &lt; 600 mL/min for a graft or &lt; 500 for a fistula flags a referral to the access team.</p>
    `},
    {id:'rn-5', title:'Renal panel and adequacy', read:'4 min', body:`
      <h2>Monthly renal panel</h2>
      <p>For every dialysis patient, monthly: urea (pre and post for Kt/V), creatinine, sodium, potassium, calcium, phosphate, albumin, PTH, ferritin, transferrin saturation, FBC, HBsAg / anti-HCV / HIV (every 6 months).</p>
      <h2>Adequacy targets</h2>
      <ul>
        <li><b>spKt/V ≥ 1.2</b> per session — minimum acceptable</li>
        <li><b>URR ≥ 65%</b> — urea reduction ratio</li>
        <li><b>Phosphate</b> 3.5–5.5 mg/dL</li>
        <li><b>Corrected calcium</b> 8.4–9.5 mg/dL</li>
        <li><b>PTH</b> 150–600 pg/mL</li>
        <li><b>Hb</b> 10–12 g/dL (avoid &gt; 13)</li>
      </ul>
    `}
  ],

  'histopath': [
    {id:'hp-1', title:'The histopathology workflow', read:'5 min', body:`
      <h2>From specimen to report</h2>
      <ol>
        <li><b>Receipt</b> — specimen logged, accession number assigned, clinical summary captured</li>
        <li><b>Gross examination</b> — measurements, description, blocks selected and labelled</li>
        <li><b>Processing</b> — overnight tissue processor: dehydration, clearing, paraffin infiltration</li>
        <li><b>Embedding</b> — blocks oriented and embedded in paraffin</li>
        <li><b>Microtomy</b> — 4 µm sections cut, mounted on slides</li>
        <li><b>Staining</b> — H&amp;E standard; special stains and IHC as ordered</li>
        <li><b>Microscopy</b> — pathologist reviews slides and dictates report</li>
        <li><b>Reporting &amp; sign-off</b> — report typed, reviewed, and signed</li>
      </ol>
    `},
    {id:'hp-2', title:'Gross examination — what to capture', read:'5 min', body:`
      <h2>Required elements</h2>
      <ul>
        <li><b>Specimen description</b> — what was received (e.g. "right breast lump excision")</li>
        <li><b>Measurements</b> — three dimensions in cm</li>
        <li><b>Weight</b> — for solid organ specimens</li>
        <li><b>External features</b> — colour, consistency, any visible lesions</li>
        <li><b>Cut surface</b> — appearance after sectioning</li>
        <li><b>Block summary</b> — how many blocks, what each represents (tumour centre, periphery, margins, nipple-areolar complex, etc.)</li>
        <li><b>Inking scheme</b> — colour code for margins (e.g. blue = superior, black = deep)</li>
      </ul>
      <h2>Photographing the specimen</h2>
      <p>For tumours and complex resections, attach photographs to the gross examination. LabOS supports up to 10 images per case, stored at full resolution.</p>
    `},
    {id:'hp-3', title:'Ordering immunohistochemistry (IHC)', read:'5 min', body:`
      <h2>When to order IHC</h2>
      <p>IHC is used to:</p>
      <ul>
        <li>Subtype tumours (e.g. lymphoma B vs T, sarcoma differentiation)</li>
        <li>Identify site of origin in metastatic disease (CK7/CK20 panel, TTF-1, etc.)</li>
        <li>Determine treatment-predictive markers (ER, PR, HER2 for breast)</li>
        <li>Confirm specific diagnoses (e.g. CD117 for GIST, S-100 for melanoma)</li>
      </ul>
      <h2>Ordering from the case</h2>
      <p>Within the histopath case, click <b>Order IHC</b>. Browse the panel library or pick individual markers. The system tracks block, slide, and antibody clone per marker. Standard turnaround for IHC: 3 working days after order.</p>
    `},
    {id:'hp-4', title:'Renal biopsy and immunofluorescence', read:'5 min', body:`
      <h2>The renal IF panel</h2>
      <p>Renal biopsies require an immunofluorescence panel done on frozen tissue: IgG, IgA, IgM, C3, C1q, kappa, lambda, and fibrinogen. LabOS automatically orders this panel when a specimen labelled "renal biopsy" is received.</p>
      <h2>Reporting framework</h2>
      <p>The renal biopsy report follows: light microscopy → immunofluorescence → electron microscopy (if sent out) → integrated diagnosis. Each section has a structured template prompting glomerular, tubular, interstitial, and vascular descriptions.</p>
    `},
    {id:'hp-5', title:'Cytology — FNA and fluids', read:'4 min', body:`
      <h2>Fine needle aspiration (FNA)</h2>
      <p>FNA cytology is logged separately from histopath cases. Capture: site, aspirator, number of passes, smear preparation (air-dried for MGG, alcohol-fixed for Pap). Rapid on-site evaluation (ROSE) is recommended where available.</p>
      <h2>Body fluids</h2>
      <p>Pleural, peritoneal, pericardial, CSF, and synovial fluids. Capture: volume, appearance, cell count, differential, cytospin findings. For malignancy workup, cell block preparation enables subsequent IHC.</p>
    `},
    {id:'hp-6', title:'Pap smear reporting (Bethesda 2014)', read:'4 min', body:`
      <h2>The Bethesda system</h2>
      <p>Pap smears are reported using Bethesda 2014 categories: NILM, ASC-US, LSIL, ASC-H, HSIL, AGC, AIS, invasive carcinoma. LabOS provides a structured form matching the system.</p>
      <h2>Adequacy</h2>
      <p>Every Pap report includes an adequacy statement: <i>Satisfactory for evaluation</i> or <i>Unsatisfactory</i> with reason (obscuring blood, inflammation, scant cellularity).</p>
      <h2>HPV co-testing</h2>
      <p>For women ≥ 30, HPV genotyping (high-risk types) is reflexed automatically on ASC-US Paps and offered for primary screening on Professional and Enterprise plans.</p>
    `},
    {id:'hp-7', title:'Sign-off and the synoptic report', read:'4 min', body:`
      <h2>What "sign-off" means</h2>
      <p>The consultant pathologist reviews the slides, refines the report, and locks it with a 2FA confirmation. Only after sign-off can the report be released to the clinician.</p>
      <h2>Synoptic reports for cancer</h2>
      <p>For breast, prostate, colon, lung, and renal cancers, LabOS uses synoptic templates aligned with the College of American Pathologists (CAP) cancer protocols. These structured reports capture all required data points (tumour size, grade, margins, lymphovascular invasion, lymph node status, AJCC stage) for cancer registry reporting.</p>
    `},
    {id:'hp-8', title:'Frozen sections', read:'3 min', body:`
      <h2>Indications</h2>
      <p>Intraoperative frozen sections are used to: assess margin status during cancer resection, confirm presence of pathology in a biopsy, identify lymph node metastasis (sentinel node).</p>
      <h2>Workflow</h2>
      <p>The surgeon notifies the lab 30 minutes ahead. Specimen arrives fresh (not in formalin). Cryostat sections at 5 µm, rapid H&amp;E (~3 minutes), microscopic review by pathologist, verbal report to OR within 20 minutes of receipt. Final permanent sections follow.</p>
      <div class="tip"><b>Tip:</b> Frozen section accuracy is &gt; 95% but should always be confirmed by permanent sections before definitive treatment.</div>
    `},
    {id:'hp-9', title:'External consultation and case discussion', read:'3 min', body:`
      <h2>When to seek consultation</h2>
      <p>Rare tumours, unusual presentations, or cases where definitive diagnosis affects major treatment decisions warrant a second opinion. LabOS supports digital case sharing with consultant pathologists locally or internationally.</p>
      <h2>The consultation flow</h2>
      <ol>
        <li>From the case, click <b>Request consultation</b></li>
        <li>Choose your preferred consultant from your tenant's contact list</li>
        <li>Upload high-resolution slide images and select the relevant blocks</li>
        <li>The consultant receives an encrypted link and can respond within the platform</li>
        <li>The consultation note is appended to the final report</li>
      </ol>
    `}
  ],

  'molecular': [
    {id:'mol-1', title:'Molecular testing — what we offer', read:'4 min', body:`
      <h2>In-house molecular tests</h2>
      <ul>
        <li><b>SARS-CoV-2 RT-PCR</b> — same-day or next-day</li>
        <li><b>MTB/Rif (GeneXpert)</b> — TB and rifampicin resistance, ~2 hours</li>
        <li><b>HIV viral load</b> — RT-PCR quantitative</li>
        <li><b>HBV DNA quantitative</b></li>
        <li><b>HCV RNA quantitative + genotype</b></li>
        <li><b>HPV high-risk genotyping</b></li>
        <li><b>STI multiplex PCR</b> — Chlamydia, Gonorrhoea, Trichomonas, Mycoplasma genitalium</li>
        <li><b>Sickle cell PCR confirmation</b> — for HPLC-ambiguous cases</li>
      </ul>
      <h2>Send-out tests</h2>
      <p>BRCA1/2 sequencing, hereditary cancer panels, pharmacogenomics, ancestry, NIPT, karyotyping — see the DNA &amp; Genetics module for the full list and turnaround times.</p>
    `},
    {id:'mol-2', title:'Ordering a PCR test', read:'3 min', body:`
      <h2>Sample requirements</h2>
      <p>Each PCR test has specific sample requirements. The new-request modal will only allow ordering if your sample collection matches:</p>
      <ul>
        <li><b>Viral load (HIV, HBV, HCV)</b> — EDTA whole blood, processed within 6 hours</li>
        <li><b>SARS-CoV-2</b> — nasopharyngeal swab in viral transport medium</li>
        <li><b>MTB/Rif</b> — sputum (3+ mL), or biopsy in saline</li>
        <li><b>STI multiplex</b> — endocervical swab (female), first-catch urine (male)</li>
      </ul>
    `},
    {id:'mol-3', title:'Send-out tests and partner labs', read:'5 min', body:`
      <h2>Why send-outs</h2>
      <p>Some tests require equipment and expertise that aren't economical for every lab to maintain. LabOS partners with reference labs in South Africa, the UK, and the US:</p>
      <ul>
        <li><b>SYNLAB SA (Pretoria)</b> — BRCA, hereditary cancer panels, karyotype</li>
        <li><b>Lancet South Africa</b> — pharmacogenomics, ancestry, nutrigenomics</li>
        <li><b>Lancet Nigeria</b> — NIPT prenatal, Lynch syndrome</li>
        <li><b>Cellmark UK</b> — UK Home Office immigration DNA</li>
        <li><b>DNA Diagnostics Centre (US)</b> — AABB-accredited immigration DNA (USA)</li>
        <li><b>Innovative Genomics (UK)</b> — PGD/PGS for IVF embryos</li>
      </ul>
      <h2>The send-out workflow</h2>
      <p>LabOS handles the logistics: shipping label, DHL pickup, partner-lab order form, sample tracking, and automated result upload when the partner reports back. You see one unified report at the end.</p>
    `},
    {id:'mol-4', title:'IDSR notification for notifiable diseases', read:'5 min', body:`
      <h2>What IDSR requires</h2>
      <p>The Nigeria Centre for Disease Control (NCDC) operates the Integrated Disease Surveillance and Response (IDSR) system. Labs must notify NCDC within 24 hours of confirming any of the priority diseases (cholera, Lassa fever, yellow fever, measles, polio, monkeypox, COVID-19, Ebola, etc.).</p>
      <h2>Automated notification</h2>
      <p>When LabOS detects a notifiable result (e.g. positive Lassa PCR, confirmed cholera culture), it:</p>
      <ol>
        <li>Tags the result with a red <b>NOTIFIABLE</b> banner</li>
        <li>Pre-fills the IDSR-002 form with patient demographics, clinical details, and lab findings</li>
        <li>Notifies the designated DSNO (Disease Surveillance Officer) by SMS and email</li>
        <li>Once the DSNO confirms submission, files the case ID and submission timestamp in the audit log</li>
      </ol>
    `},
    {id:'mol-5', title:'Quality control for PCR', read:'4 min', body:`
      <h2>Internal controls</h2>
      <p>Every PCR run must include: a no-template control (NTC) to detect contamination, a positive control to verify reagent integrity, and an internal sample control (housekeeping gene amplification) to detect inhibition.</p>
      <h2>External QC</h2>
      <p>Participate in at least two external QA schemes per year. LabOS supports the WHO HIV viral-load EQA and the QCMD molecular panel. Results are uploaded automatically.</p>
    `},
    {id:'mol-6', title:'Reporting viral load — what to include', read:'3 min', body:`
      <h2>Required reporting elements</h2>
      <ul>
        <li>Sample type (plasma/serum)</li>
        <li>Collection and run dates</li>
        <li>Assay name and version (e.g. Roche cobas HIV-1 v2.0)</li>
        <li>Quantitative value in copies/mL and log10</li>
        <li>Lower limit of detection (LOD) and lower limit of quantification (LOQ)</li>
        <li>Result interpretation: <b>Undetectable</b> (&lt; LOD), <b>Detected, not quantifiable</b> (between LOD and LOQ), or numeric</li>
        <li>Comparison to previous result if available (delta)</li>
      </ul>
    `},
    {id:'mol-7', title:'GeneXpert TB testing — practical guide', read:'4 min', body:`
      <h2>Sample types</h2>
      <p>Sputum (best yield), bronchoalveolar lavage, pleural fluid, CSF, lymph node aspirate, biopsy in saline. Stool can be processed for paediatric TB.</p>
      <h2>Results</h2>
      <ul>
        <li><b>MTB DETECTED, Rif sensitive</b> — start standard 6-month regimen</li>
        <li><b>MTB DETECTED, Rif resistant</b> — refer for MDR-TB workup immediately</li>
        <li><b>MTB DETECTED, Rif indeterminate</b> — repeat or send for line probe assay</li>
        <li><b>MTB NOT DETECTED</b> — does not exclude TB; clinical correlation needed</li>
        <li><b>Error / Invalid</b> — sample issue; repeat with new sample</li>
      </ul>
      <p>Both positive results and Rif resistance are <b>notifiable</b> — IDSR auto-notification fires.</p>
    `}
  ],

  'billing': [
    {id:'bl-1', title:'Setting up Paystack for your laboratory', read:'5 min', body:`
      <h2>Why Paystack is the sole payment provider</h2>
      <p>LabOS uses Paystack exclusively for online card and bank transfer payments. Paystack is PCI-DSS Level 1 certified, supports all major Nigerian cards and banks, and offers same-day settlement to your business account.</p>
      <h2>Connecting your Paystack account</h2>
      <ol>
        <li>Create or sign in to your Paystack business account at <code>dashboard.paystack.com</code></li>
        <li>Under <b>Settings → API Keys &amp; Webhooks</b>, copy your <b>live secret key</b> and <b>live public key</b></li>
        <li>In LabOS, go to <code>Settings → Integrations → Paystack</code> and paste both keys</li>
        <li>Click <b>Test connection</b> — a ₦100 test charge will be made and immediately refunded</li>
        <li>Configure your webhook URL: <code>https://[your-tenant].labos.africa/webhooks/paystack</code></li>
      </ol>
      <h2>Settlement schedule</h2>
      <p>Paystack settles funds to your bank account on a T+1 schedule (next business day) for cards, and same-day for direct bank transfers. The Billing module shows expected vs. actual settlements.</p>
    `},
    {id:'bl-2', title:'NHIS and HMO claim submission', read:'7 min', body:`
      <h2>Setting up insurance providers</h2>
      <p>From <code>Settings → Insurance providers</code>, add each NHIS-accredited HMO your lab accepts. For each provider, capture: NHIS code, contact email, claim submission method (portal/email), settlement terms.</p>
      <h2>Capturing insurance at registration</h2>
      <p>When registering a patient, choose <b>Payment method: NHIS</b> or <b>Payment method: HMO</b>, then select the HMO from the dropdown. Enter the policy number — LabOS will validate format and flag expired or suspended policies if the provider offers an API.</p>
      <h2>Submitting claims</h2>
      <p>Bundle paid claims weekly or daily from the <b>Billing → Claims</b> screen. Each batch generates a PDF claim form and a CSV manifest. Track each claim through: <code>Submitted → Acknowledged → Adjudicated → Paid</code> or <code>Rejected</code> (with reason code).</p>
    `},
    {id:'bl-3', title:'Cash, transfer, and POS reconciliation', read:'4 min', body:`
      <h2>Cash payments</h2>
      <p>From the invoice, choose <b>Payment method: Cash</b>, enter the amount received, and the till drawer balance updates. End-of-day, the cashier counts and confirms the till against the LabOS expected total. Any variance is logged with reason.</p>
      <h2>Bank transfer</h2>
      <p>Patients can transfer directly to your business account. Mark the invoice as <b>Awaiting confirmation</b> with the transfer reference. The accountant matches against the bank statement during end-of-day reconciliation.</p>
      <h2>POS machine</h2>
      <p>If your POS isn't Paystack-integrated, record the slip reference manually. We strongly recommend Paystack POS terminals which auto-link transactions to invoices.</p>
    `},
    {id:'bl-4', title:'Refunds and discount codes', read:'4 min', body:`
      <h2>Issuing a refund</h2>
      <p>On a paid invoice, click <b>Refund</b>. Choose full or partial. For Paystack payments, the refund is initiated via API and reaches the patient's card in 5–7 business days. For cash refunds, the cashier dispenses cash and the system records the disbursement.</p>
      <h2>Discount codes</h2>
      <p>From <code>Settings → Pricing → Discount codes</code>, create codes for promotions, corporate clients, or staff. Each code can be: percentage off, fixed amount off, valid for specific tests only, time-limited, single-use or unlimited.</p>
    `},
    {id:'bl-5', title:'Corporate billing for packages', read:'4 min', body:`
      <h2>How corporate billing works</h2>
      <p>For pre-employment medicals, executive checks, and corporate wellness packages, the sponsor (employer) is billed monthly rather than the patient at point-of-service. Each corporate account has a credit limit and standard payment terms (typically Net 30).</p>
      <h2>Setting up a corporate account</h2>
      <p>From <code>Billing → Corporate accounts</code>, add the company. Capture: legal name, TIN, billing contact, credit limit, payment terms, agreed price list (can override standard pricing for that account).</p>
      <h2>Monthly invoicing</h2>
      <p>On the 1st of each month, LabOS generates a single consolidated invoice per corporate account, itemising every package booked that month. The invoice is emailed automatically and tracked through Submitted → Acknowledged → Paid.</p>
    `},
    {id:'bl-6', title:'End-of-day reconciliation', read:'5 min', body:`
      <h2>The reconciliation flow</h2>
      <ol>
        <li>At end of shift, the cashier clicks <b>Reconcile till</b></li>
        <li>LabOS shows the expected balance: opening + cash receipts − cash refunds</li>
        <li>The cashier counts the till and enters the actual amount</li>
        <li>Variance (if any) is logged with reason: "miscount", "till short", "overage"</li>
        <li>Cash is bagged with a deposit slip; reference number recorded</li>
      </ol>
      <h2>Daily summary</h2>
      <p>The Daily Summary report rolls up: cash collected, Paystack collected, transfers received, refunds issued, NHIS/HMO accruals, and variances. Available as PDF for management review.</p>
    `},
    {id:'bl-7', title:'Outstanding invoices and patient debt', read:'3 min', body:`
      <h2>Tracking unpaid invoices</h2>
      <p>The Billing dashboard's <b>Aged receivables</b> widget shows: current, 30 days, 60 days, 90+ days. Older debt has lower recovery likelihood, so the system suggests reminders or write-off.</p>
      <h2>Reminder cadence</h2>
      <p>For self-pay patients, reminders are sent automatically: SMS at 7 days, SMS + email at 14, escalating language at 30 and 60. After 90 days, the invoice is flagged for manual review.</p>
    `},
    {id:'bl-8', title:'Tax invoicing and VAT', read:'3 min', body:`
      <h2>FIRS-compliant invoicing</h2>
      <p>If your laboratory is VAT-registered, LabOS issues FIRS-compliant tax invoices showing: your TIN, the patient's TIN (if provided), VAT at the current rate (7.5%) calculated per line, and the total inclusive of VAT.</p>
      <h2>VAT exemption</h2>
      <p>Medical services are partially VAT-exempt. The LabOS catalogue is pre-tagged with the VAT applicability of each test, but you should verify with your accountant for your specific operations.</p>
    `},
    {id:'bl-9', title:'Payment plans for expensive tests', read:'3 min', body:`
      <h2>When to offer a payment plan</h2>
      <p>For high-cost tests (BRCA, NIPT, hereditary cancer panels, premium wellness packages), patients sometimes need to spread the cost. LabOS supports up to 3-month plans on amounts ≥ ₦100,000.</p>
      <h2>Setting up a plan</h2>
      <p>On the invoice, click <b>Convert to payment plan</b>. Choose 2-month or 3-month split; LabOS schedules the instalments and sends Paystack mandate links. Service can begin after the first instalment is paid.</p>
    `},
    {id:'bl-10', title:'Exporting financial data for accountants', read:'3 min', body:`
      <h2>Standard exports</h2>
      <p>From <b>Billing → Exports</b>, you can generate:</p>
      <ul>
        <li><b>Sales register</b> — all invoices in a date range, CSV or Excel</li>
        <li><b>Receipt register</b> — all payments received, by method</li>
        <li><b>NHIS / HMO claims register</b> — claims submitted and their status</li>
        <li><b>VAT return support</b> — pre-formatted for FIRS submission</li>
        <li><b>General ledger journal</b> — debits and credits ready for import into Sage, QuickBooks, or Xero</li>
      </ul>
    `}
  ],

  'gateway': [
    {id:'gw-1', title:'What is the LabOS Instrument Gateway?', read:'4 min', body:`
      <h2>The problem it solves</h2>
      <p>Laboratory analyzers produce results electronically, but most labs still have a technician manually re-typing those results into the LIMS. This is slow, error-prone, and a major source of transcription errors — one of the most common causes of patient harm in laboratory medicine.</p>
      <p>The LabOS Instrument Gateway eliminates manual result entry entirely. It is a small Windows application that sits on the PC connected to your analyzer, receives results automatically the moment the analyzer produces them, and pushes them directly into LabOS.</p>
      <h2>How it works</h2>
      <ol>
        <li>The analyzer completes a test run and sends the result over its serial cable or network connection</li>
        <li>The Gateway receives the raw message (in ASTM or HL7 format), parses it, and extracts the patient and result data</li>
        <li>The result is matched to the correct patient request in LabOS (by barcode, sample ID, or accession number)</li>
        <li>The result is validated against reference ranges and checked for critical values</li>
        <li>The result appears in the LabOS Clinical Laboratory screen ready for scientist review and release</li>
      </ol>
      <h2>What it runs on</h2>
      <p>The Gateway is a Windows desktop application. It runs on the same PC that is physically connected to the analyzer — typically a Windows 10 or 11 PC. No internet connection is required to receive results; the Gateway stores them locally and syncs to LabOS when connectivity is available.</p>
      <div class="tip"><b>One Gateway per analyzer group.</b> You only need one Gateway installation per PC, even if that PC is connected to multiple analyzers. The Gateway manages all connections from a single dashboard.</div>
    `},
    {id:'gw-2', title:'Installing the LabOS Instrument Gateway', read:'3 min', body:`
      <h2>Requirements</h2>
      <ul>
        <li>Windows 10 or Windows 11 (64-bit)</li>
        <li>The PC must be physically connected to the analyzer (via RS-232 serial cable, USB-to-serial adapter, or network cable)</li>
        <li>Internet access for syncing results to LabOS (offline collection still works without it)</li>
        <li>At least 200 MB free disk space</li>
      </ul>
      <h2>Installation steps</h2>
      <ol>
        <li>Download the installer <b>LabOS Instrument Gateway Setup.exe</b> from your LabOS administrator (AgoroX Technologies)</li>
        <li>Double-click the installer file</li>
        <li>If Windows SmartScreen shows a warning, click <b>More info → Run anyway</b> (the app is signed by AgoroX Technologies)</li>
        <li>Click <b>Next</b> through the setup wizard and choose your installation folder</li>
        <li>Click <b>Install</b> and wait for it to complete</li>
        <li>Click <b>Finish</b> — the Gateway opens automatically</li>
      </ol>
      <p>The Gateway creates a desktop shortcut (<b>LabOS Gateway</b>) and a system tray icon. It runs in the background automatically when Windows starts.</p>
      <h2>First-time configuration</h2>
      <p>After installing, go to <b>Settings</b> in the Gateway and enter:</p>
      <ul>
        <li>Your LabOS API URL (provided by AgoroX Technologies)</li>
        <li>Your API key (the anon public key from your Supabase project)</li>
        <li>Your Laboratory ID (the tenant ID assigned to your lab)</li>
      </ul>
      <p>Then click <b>Test connection</b> to confirm the Gateway can reach LabOS, and <b>Save settings</b>.</p>
    `},
    {id:'gw-3', title:'Connecting an analyzer to the Gateway', read:'5 min', body:`
      <h2>Supported connection types</h2>
      <ul>
        <li><b>RS-232 Serial</b> — the most common for African labs. The analyzer connects via a 9-pin serial cable (or USB-to-serial adapter). You need to know the COM port number (e.g. COM3) and the baud rate (usually 9600 or 19200 — check your analyzer's manual).</li>
        <li><b>TCP/IP Network</b> — modern analyzers connect via Ethernet. You need the analyzer's IP address and port number.</li>
        <li><b>File watch</b> — some analyzers export results to a folder as text or CSV files. The Gateway monitors the folder and imports files automatically.</li>
      </ul>
      <h2>How to add an analyzer</h2>
      <ol>
        <li>Open the Gateway and click <b>Settings</b></li>
        <li>Scroll to <b>Add analyzer</b></li>
        <li>Enter the analyzer name, vendor, and model</li>
        <li>Select the protocol (<b>ASTM</b> for most African lab analyzers; <b>HL7</b> for modern Roche and Siemens instruments)</li>
        <li>Select the connection type and fill in the connection details</li>
        <li>Click <b>Add analyzer</b></li>
        <li>Go to the <b>Analyzers</b> screen and click <b>Connect</b> next to the new analyzer</li>
      </ol>
      <h2>Finding your COM port</h2>
      <p>On the Windows PC, right-click the Start button → <b>Device Manager</b> → expand <b>Ports (COM &amp; LPT)</b>. You will see the COM port number next to the serial or USB-serial device. Common numbers are COM3, COM4, or COM5.</p>
      <div class="tip"><b>Tip:</b> If you are not sure of your baud rate, try 9600 first. Most Mindray and Sysmex analyzers use 9600 or 19200.</div>
    `},
    {id:'gw-4', title:'Supported analyzers and protocols', read:'4 min', body:`
      <h2>ASTM protocol analyzers</h2>
      <p>ASTM E1381/E1394 (also called LIS1-A2/LIS2-A2) is the most widely used protocol in Nigerian and African laboratories. It is used by:</p>
      <ul>
        <li><b>Mindray</b> — BC-3000, BC-5000, BC-5800 (hematology); BS-120, BS-200, BS-380 (chemistry)</li>
        <li><b>Sysmex</b> — KX-21, XP-300, XN-series (hematology)</li>
        <li><b>Erba</b> — XL-200, XL-640 (chemistry)</li>
        <li><b>Dirui</b> — CS-series (chemistry and hematology)</li>
        <li>Most coagulation, urinalysis, and immunology analyzers</li>
      </ul>
      <h2>HL7 protocol analyzers</h2>
      <p>HL7 v2.x is used by higher-end network-connected analyzers, typically:</p>
      <ul>
        <li><b>Roche</b> — Cobas c-series, e-series (chemistry and immunoassay)</li>
        <li><b>Siemens Healthineers</b> — Dimension, Atellica series</li>
        <li><b>Abbott</b> — Architect series</li>
      </ul>
      <h2>Not sure which protocol your analyzer uses?</h2>
      <p>Check the analyzer's LIS connectivity manual or call the vendor's technical support. Ask: "Does this analyzer support ASTM LIS interface or HL7?" Almost all analyzers sold in Nigeria support ASTM; HL7 is common on newer instruments purchased from 2018 onwards.</p>
      <div class="tip"><b>Generic drivers available.</b> If your specific model is not listed, the Generic ASTM Driver works with any ASTM-compliant analyzer. Select it when adding the analyzer and configure the COM port settings manually.</div>
    `},
    {id:'gw-5', title:'How result matching works', read:'4 min', body:`
      <h2>The matching problem</h2>
      <p>When an analyzer sends a result, it identifies the sample by its own internal sample ID — which may or may not match the patient request number in LabOS. The Gateway's Sample Matching Engine bridges this gap.</p>
      <h2>Matching priority order</h2>
      <p>The engine tries four methods in sequence, stopping at the first match:</p>
      <ol>
        <li><b>Barcode</b> — if the sample tube was barcoded and the barcode was scanned at collection, the Gateway matches by barcode. This is the most reliable method and the one we recommend.</li>
        <li><b>Sample ID</b> — the analyzer's internal sample sequence number. Works if your lab uses a consistent numbering scheme that matches LabOS.</li>
        <li><b>Accession number</b> — the order/accession number from the test request. Works on analyzers that receive the worklist from LabOS (bi-directional interfaces).</li>
        <li><b>Patient ID</b> — the patient's hospital number or ID. Least precise — may match multiple requests for the same patient.</li>
      </ol>
      <h2>What happens when no match is found</h2>
      <p>Results that cannot be matched are held in the <b>Pending</b> queue on the Gateway Dashboard and in LabOS under Instrument Gateway → Sample Matching. A lab scientist can manually match them by searching for the patient and linking the result.</p>
      <div class="tip"><b>Best practice:</b> Always print and scan barcoded labels on sample tubes. This makes the matching process automatic and eliminates the need for manual intervention.</div>
    `},
    {id:'gw-6', title:'Offline operation and syncing', read:'3 min', body:`
      <h2>Working offline</h2>
      <p>The Gateway stores all received results in a local SQLite database on the PC. This means results are never lost even if the internet connection drops during a shift. The analyzer-to-Gateway connection is completely local — it does not need the internet.</p>
      <h2>Syncing to LabOS</h2>
      <p>When internet connectivity is available, the Gateway automatically syncs pending results to LabOS every 30 seconds (configurable in Settings). You can also trigger an immediate sync by clicking <b>Sync now</b> on the Gateway dashboard.</p>
      <h2>Monitoring sync status</h2>
      <p>The bottom-left of the Gateway shows the sync status:</p>
      <ul>
        <li><b>Sync active</b> (green dot) — connected to LabOS and syncing normally</li>
        <li><b>Not syncing</b> (grey dot) — no LabOS URL configured in Settings</li>
        <li><b>Sync error</b> (amber dot) — connection to LabOS failed; check your internet and the LabOS URL in Settings</li>
      </ul>
      <p>The pending count on the Dashboard shows how many results are waiting to be synced. This should normally be zero or close to zero during working hours when internet is available.</p>
    `}
  ],

  'admin': [
    {id:'ad-1', title:'Adding and managing staff', read:'4 min', body:`
      <h2>Inviting staff to your laboratory</h2>
      <p>From <code>Staff &amp; Roles</code>, click <b>+ Invite staff</b>. Enter the email address and pick a role. The new staff member receives an email with a setup link that expires in 7 days. They will be guided through password creation and 2FA setup on first login.</p>
      <h2>The role hierarchy</h2>
      <ul>
        <li><b>TENANT_ADMIN</b> — full access, including billing and staff management</li>
        <li><b>LAB_DIRECTOR</b> — full clinical and operational access, can release any report</li>
        <li><b>PATHOLOGIST</b> — clinical workflows, can sign off histopathology/cytology</li>
        <li><b>RENAL_SPECIALIST</b> — renal &amp; dialysis module access</li>
        <li><b>MED_LAB_SCIENTIST</b> — result entry, basic QC</li>
        <li><b>NURSE</b> / <b>PHLEBOTOMIST</b> — sample collection, dialysis sessions, vitals</li>
        <li><b>FRONT_DESK</b> — patient registration, request creation</li>
        <li><b>CASHIER</b> — invoicing, Paystack reconciliation</li>
        <li><b>INVENTORY_OFFICER</b> — reagents and consumables</li>
        <li><b>ACCOUNTANT</b> — read-only access to billing and analytics</li>
        <li><b>DNA_OFFICER</b> — chain-of-custody DNA &amp; toxicology collections</li>
        <li><b>RADIOGRAPHER</b> — imaging study acquisition</li>
      </ul>
      <div class="tip"><b>Tip:</b> The 13 × 12 permission matrix in Staff &amp; Roles lets you fine-tune any role's exact actions, beyond these presets.</div>
    `},
    {id:'ad-2', title:'Managing your subscription', read:'4 min', body:`
      <h2>Your plan and entitlements</h2>
      <p>LabOS is billed annually only. Your current plan, renewal date, and usage meters are visible from <code>Subscription &amp; Billing</code>. Each plan has limits on centres, staff, patients-per-month, and storage. When you approach 75% of a limit, you'll see a yellow indicator; at 90% it turns red.</p>
      <h2>Changing your plan</h2>
      <p>Click <b>Change plan</b>. Upgrades take effect immediately — the price difference is prorated against your remaining period and charged via Paystack. Downgrades take effect at your next annual renewal so you keep full features for the period you've already paid.</p>
      <h2>Cancellation</h2>
      <p>You can cancel auto-renewal at any time. Your laboratory continues to function until the end of your paid period. After that, your data is retained for 90 days in case you return — after 90 days it's permanently deleted in line with NDPR.</p>
    `},
    {id:'ad-3', title:'Configuring branches and centres', read:'4 min', body:`
      <h2>Adding a new branch</h2>
      <p>From <code>Tenant profile → Centres</code>, click <b>+ Add centre</b>. Capture: name, address, GPS coordinates, phone, head of branch, operating hours. The centre appears in the Active centre switcher immediately.</p>
      <h2>Centre-specific settings</h2>
      <p>Each centre can have its own: opening hours, holiday calendar, branch-specific phone number for the patient portal, default radiologist on duty, and (on Enterprise) its own branding.</p>
      <h2>Plan limits</h2>
      <p>CoreCare: 1 centre. Standard: up to 3. Professional: up to 10. Enterprise: unlimited. To add more centres, upgrade your plan or purchase an Additional Centre Slot add-on (₦180,000/centre/year, available on Professional).</p>
    `},
    {id:'ad-4', title:'Tenant profile and branding', read:'3 min', body:`
      <h2>What's on your profile</h2>
      <p>From <code>Tenant profile</code>, manage: legal name, trading name, TIN, NHIS code, MLSCN registration, contact details, banking details for settlements, primary brand colour, logo (PNG or SVG).</p>
      <h2>Branding scope</h2>
      <p>Your brand appears on: patient-facing reports, the patient portal, invoices, the sidebar when staff are signed in as your tenant. The LabOS attribution remains on every page as "Powered by LabOS · AgoroX".</p>
      <h2>White-label (Enterprise)</h2>
      <p>Enterprise customers can remove the LabOS attribution and present a fully-white-labelled experience. Request this from your customer success manager.</p>
    `},
    {id:'ad-5', title:'Custom test pricing per tenant', read:'5 min', body:`
      <h2>How pricing works</h2>
      <p>LabOS ships with a global price list for every catalogue test. As a tenant admin, you can override prices for your laboratory to reflect your costs, market position, and corporate contracts. The platform price stays the same; your customers see your overridden prices.</p>
      <h2>Bulk price changes</h2>
      <p>From the Pricing page, use <b>Bulk markup</b>: pick a category (or "all tests"), choose increase/decrease, enter a percentage, round to ₦100/500/1000. Preview the impact on revenue, then apply.</p>
      <h2>Per-test overrides</h2>
      <p>Click any test row to set an exact price. The override is highlighted in green and contributes to your delta-vs-platform indicator at the top.</p>
    `},
    {id:'ad-6', title:'The audit log', read:'3 min', body:`
      <h2>What's logged</h2>
      <p>Every action that changes data or accesses sensitive information is logged: who, what, when, from where (IP and device), and the before/after values. Read-only access to patient records is also logged.</p>
      <h2>Tamper-evidence</h2>
      <p>Audit log entries are hash-chained. Each new entry includes a hash of the previous entry. If anyone alters or deletes a past entry, the chain breaks and the audit log shows a tampering warning. Even tenant admins cannot edit the log.</p>
      <h2>Retention</h2>
      <p>Audit logs are retained for 7 years per NDPR. Older logs can be archived to long-term cold storage on request.</p>
    `},
    {id:'ad-7', title:'Backup and disaster recovery', read:'4 min', body:`
      <h2>What we back up</h2>
      <p>Full database snapshots are taken nightly at 03:00 WAT and stored encrypted in two regions (Lagos primary, Frankfurt secondary). Patient documents (uploaded forms, scans) are continuously replicated.</p>
      <h2>Point-in-time recovery</h2>
      <p>For the last 30 days, we can restore your tenant to any 5-minute interval. Useful for accidental bulk deletes, ransomware events, or data-import errors. Recovery requests go through customer success and require tenant-admin authorisation.</p>
      <h2>What you should do</h2>
      <p>Periodically export your data (Settings → Data &amp; Privacy → Full export) to keep a copy outside LabOS. This is your right under NDPR.</p>
    `},
    {id:'ad-8', title:'Configuring SMS and WhatsApp delivery', read:'4 min', body:`
      <h2>Termii (SMS)</h2>
      <p>LabOS uses Termii for transactional SMS to Nigerian phone numbers. From <code>Settings → Integrations → Termii</code>, connect your Termii account. You'll need: sender ID (must be pre-approved), and either pay-as-you-go or pre-purchased bundle.</p>
      <h2>WhatsApp Business</h2>
      <p>WhatsApp is preferred for report delivery — patients open it 7× more reliably than email. Connect your WhatsApp Business API account (via Meta or a BSP like Whogohost). LabOS uses pre-approved message templates so delivery doesn't require the patient to message first.</p>
      <h2>Delivery fallback</h2>
      <p>Default order: WhatsApp → SMS → Email. If WhatsApp delivery fails (number not on WhatsApp, message blocked), LabOS retries via SMS. Patients can choose their preferred channel at registration.</p>
    `},
    {id:'ad-9', title:'Holidays, hours, and on-call schedules', read:'3 min', body:`
      <h2>Operating hours</h2>
      <p>Set your laboratory's opening hours per centre, per day. Off-hours requests are accepted but won't start processing until the next working window.</p>
      <h2>Holidays</h2>
      <p>Nigerian public holidays are pre-loaded each year. You can add lab-specific closures (staff training days, public health emergencies). TAT calculations exclude holidays.</p>
      <h2>On-call schedule</h2>
      <p>For nights and weekends, designate one pathologist and one med-lab scientist per day as on-call. Critical-result protocols and STAT requests page the on-call team automatically.</p>
    `},
    {id:'ad-10', title:'Single Sign-On (SSO) for Enterprise', read:'3 min', body:`
      <h2>Supported identity providers</h2>
      <p>LabOS Enterprise supports SAML 2.0 SSO with: Microsoft Azure AD / Entra ID, Google Workspace, Okta, OneLogin, and Auth0. SCIM provisioning is supported with Azure AD and Okta for automatic user lifecycle management.</p>
      <h2>Setting up SSO</h2>
      <p>Contact your customer success manager. The technical setup takes 1–2 working days: exchange of metadata, attribute mapping (email, name, role group), test sign-in, then cutover. 2FA can either remain in LabOS or be delegated to your IdP.</p>
    `},
    {id:'ad-11', title:'API access and rate limits', read:'4 min', body:`
      <h2>Getting an API key</h2>
      <p>API access is available on Professional and Enterprise plans. From <code>Settings → API Keys</code>, generate a key, choose its scopes (read-only / read-write), and optionally restrict by IP range. Keys are shown once and never again — store them securely.</p>
      <h2>Rate limits</h2>
      <ul>
        <li><b>Professional</b> — 60 requests/minute, 10,000/day</li>
        <li><b>Enterprise</b> — 600 requests/minute, 1,000,000/day</li>
      </ul>
      <h2>Documentation</h2>
      <p>Full OpenAPI 3.1 spec at <code>https://docs.labos.africa/api</code>. Includes Python, JavaScript, and Postman client libraries.</p>
    `}
  ,
    {id:'ad-12', title:'Tenant Profile setup', read:'4 min', body:`<h2>What's on the profile</h2><p>Lab name, brand colour, logo, primary contact, postal and physical addresses, NHIA accreditation, ISO 15189 status, lab director's name and signature image (used on reports). Open <b>Administration → Tenant Profile</b>.</p><h2>Signature image</h2><p>Upload a PNG with a transparent background, max 300×100 pixels. This is rendered on all signed reports.</p><h2>Tenant-level vs platform-level</h2><p>Tenant Profile is what each lab manages itself. Platform-level configuration (tenancy onboarding, subscription tier, feature flags) lives in the platform admin console used by AgoroX support.</p>`},
    {id:'ad-13', title:'Branch Management', read:'4 min', body:`<h2>Branch types</h2><p>Main lab, satellite lab, collection centre, draw point. Each branch has its own code, address, manager, opening hours and (optionally) its own price list.</p><h2>Cross-branch operations</h2><p>Samples collected at a draw point are tracked through the parent lab's accession sequence. The collection-branch is recorded on the sample and report.</p><h2>Inventory per branch</h2><p>Each branch maintains its own stock (reagents, consumables, supplies). Reorder thresholds are per-branch — main lab may need 100 EDTA tubes/week, a draw point only 20.</p>`}
  ],

  'integrations': [
    {id:'in-1', title:'Termii for SMS', read:'3 min', body:`
      <h2>Why Termii</h2>
      <p>Termii is a Lagos-based SMS gateway with deep coverage of Nigerian networks (MTN, Airtel, Glo, 9mobile). Delivery rates exceed 95% on transactional traffic, including to remote areas.</p>
      <h2>Setting up</h2>
      <p>From <code>Settings → Integrations → Termii</code>, paste your API key. Pre-approve sender IDs through Termii's dashboard before they can be used in LabOS.</p>
      <h2>What gets sent via SMS</h2>
      <p>Critical result callbacks (fallback if WhatsApp fails), report-ready notifications, payment confirmations, appointment reminders, 2FA codes for users without authenticator apps.</p>
    `},
    {id:'in-2', title:'WhatsApp Business API', read:'4 min', body:`
      <h2>Why WhatsApp first</h2>
      <p>Nigerian patients open WhatsApp messages 7× more reliably than email and 3× more reliably than SMS. WhatsApp is the default delivery channel for reports and reminders.</p>
      <h2>Provider options</h2>
      <p>You can connect directly via Meta (slower onboarding, lower per-message cost) or via a Business Solution Provider like Whogohost, AiSensy, or Twilio. The setup involves: business verification, phone number provisioning, template message approval.</p>
      <h2>Template messages</h2>
      <p>WhatsApp requires pre-approved templates for transactional messages. LabOS ships with templates covering: report ready, payment receipt, appointment reminder, critical-result callback, sample-ready-for-collection. New templates take 24–48 hours to approve.</p>
    `},
    {id:'in-3', title:'Paystack — beyond the basics', read:'4 min', body:`
      <h2>Webhook events</h2>
      <p>Configure your webhook to listen for: <code>charge.success</code>, <code>charge.failed</code>, <code>refund.processed</code>, <code>transfer.success</code>. LabOS auto-reconciles invoices on receipt of each event.</p>
      <h2>Payment plans (mandates)</h2>
      <p>For installments, Paystack mandates capture a card once and re-charge automatically on schedule. The patient does not need to re-enter card details for each instalment.</p>
      <h2>Multi-currency</h2>
      <p>Paystack supports USD, GBP, and ZAR alongside NGN. Useful for diaspora patients paying from abroad. The Pricing page lets you set USD/GBP equivalents for high-value tests.</p>
    `},
    {id:'in-4', title:'HL7 v2 integration for hospitals', read:'5 min', body:`
      <h2>Supported message types</h2>
      <ul>
        <li><b>ADT^A01 / A04</b> — patient admit/registration from HIS</li>
        <li><b>ORM^O01</b> — order received from HIS → creates request in LabOS</li>
        <li><b>ORU^R01</b> — results sent from LabOS → HIS</li>
        <li><b>QBP / RSP</b> — order/result queries</li>
      </ul>
      <h2>Transport</h2>
      <p>MLLP over TLS for on-premise hospital systems; HTTPS POST for cloud-based EMRs. LabOS provides a downloadable HL7 simulator for testing.</p>
      <h2>FHIR alternative</h2>
      <p>For modern systems, LabOS exposes a FHIR R4 endpoint. Resources supported: Patient, ServiceRequest, Observation, DiagnosticReport, Specimen, Practitioner.</p>
    `},
    {id:'in-5', title:'Analyser interfaces (LIS↔Analyser)', read:'4 min', body:`
      <h2>Bi-directional interfacing</h2>
      <p>Most modern analysers (Sysmex, Roche cobas, Beckman Coulter, Mindray, Abbott Architect) support bidirectional ASTM or HL7 interfaces. LabOS sends the work-list and receives the results automatically, no manual typing.</p>
      <h2>Common analyser drivers in Nigeria</h2>
      <p>Pre-configured drivers: Sysmex XN-1000/XN-550, Roche cobas c311/c501, Beckman AU480/AU680, Mindray BS-240/BS-480, Abbott ARCHITECT i1000/c4000, BD MAX, GeneXpert, Helena V8.</p>
      <h2>Connecting an analyser</h2>
      <p>From <code>Settings → Integrations → Analysers</code>, click <b>+ Add analyser</b>. Choose the model, set the connection (serial, TCP/IP), test the link with a sample order, and go live. Median time from order to result in LabOS for analyser-interfaced tests is 11 seconds.</p>
    `},
    {id:'in-6', title:'API keys, webhooks, and developer access', read:'5 min', body:`
      <h2>API basics</h2>
      <p>The LabOS API is REST, JSON over HTTPS. Authentication is via bearer token (your API key). All write endpoints are idempotent via an <code>Idempotency-Key</code> header.</p>
      <h2>Outbound webhooks</h2>
      <p>Subscribe to events: <code>patient.registered</code>, <code>request.created</code>, <code>result.released</code>, <code>invoice.paid</code>, <code>critical.result</code>. Each delivery includes a signature header you should verify with your shared secret.</p>
      <h2>Sandbox</h2>
      <p>Every tenant gets a free sandbox environment with seeded test data. Build and test your integration here before flipping to production. Sandbox webhooks fire instantly so you can iterate quickly.</p>
    `}
  ,
    {id:'in-7', title:'Setting up Termii (SMS + WhatsApp)', read:'4 min', body:`<h2>Step-by-step</h2><ol><li>Create a Termii account at <code>termii.com</code> and verify your business.</li><li>Top up your wallet — Termii charges per message; budget ₦5 / SMS for Nigerian networks, more for WhatsApp.</li><li>Register an SMS Sender ID (max 11 characters, all caps, no spaces). Approval takes 24–48h.</li><li>For WhatsApp, link a verified WhatsApp Business number.</li><li>Copy your API key from Termii's dashboard.</li><li>In LabOS, open <b>Integrations → Termii</b>, paste the API key, sender ID and WhatsApp number, click Save.</li></ol><h2>Testing</h2><p>Click <b>Test connection</b> on the Termii card. The server-side dispatcher performs a balance-check call; success means credentials are valid.</p>`},
    {id:'in-8', title:'Setting up Paystack', read:'4 min', body:`<h2>Test vs live mode</h2><p>Paystack issues both test and live keys. <b>Always start in test mode</b> with cards from <code>paystack.com/docs/payments/test-payments</code>. Switch to live only when integration is verified.</p><h2>Step-by-step</h2><ol><li>Create a Paystack account; complete KYC verification (CAC, BVN, bank account).</li><li>From the dashboard, copy your public key (<code>pk_test_...</code>) and secret key (<code>sk_test_...</code>).</li><li>In LabOS <b>Integrations → Paystack</b>, paste both keys.</li><li>Set the callback URL — Paystack calls this after payment. Default: <code>https://yourlab.labos.africa/paystack/callback</code>. Configure this URL in the Paystack dashboard too.</li></ol><h2>Webhook security</h2><p>Paystack signs every callback with HMAC-SHA512 of your secret key. LabOS server validates the signature; never trust an unsigned callback.</p>`},
    {id:'in-9', title:'NHIS Portal integration', read:'5 min', body:`<h2>Prerequisites</h2><p>Your lab must be NHIA-accredited; you'll have a Provider ID (e.g. <code>NHIA/LAGOS/000000</code>). Each contracted HMO issues a separate code.</p><h2>What LabOS submits</h2><p>Eligibility checks (real-time), pre-authorisation requests, claim submissions, and claim-status polling. Required fields: encounter date, NHIS card number, ICD-10 diagnosis, test codes, charges.</p><h2>Common pitfalls</h2><ul><li>Card numbers must match the format the HMO expects — some use spaces, others don't.</li><li>Authorisation codes have a short validity window (often 24h); plan the visit accordingly.</li><li>Reconciliation is manual — HMOs pay in batches; match payments to claims weekly.</li></ul>`},
    {id:'in-10', title:'HL7 bridge for auto-analysers', read:'5 min', body:`<h2>What HL7 does</h2><p>Automatic transfer of results from analyser to LIS. Without HL7, scientists transcribe manually — slower, error-prone, and a source of transcription disputes.</p><h2>The plumbing</h2><p>Most analysers act as HL7 senders: they push ORU^R01 (observation result) messages over a TCP socket using MLLP framing. LabOS listens on the host:port you configure, parses the message, matches it to the order by accession number, and writes the result.</p><h2>Configuration</h2><p>In <b>Integrations → HL7</b>, set the listener host (typically <code>0.0.0.0</code> to accept connections from any analyser), port (commonly 2575), ACK mode (<code>AL</code> = always send ACK), and encoding (UTF-8 is safe).</p><h2>Mapping test codes</h2><p>Each analyser has its own test codes (e.g. "HGB" on Sysmex). LabOS keeps a code-mapping table per analyser; if an unmapped code arrives, the result is logged for manual review.</p><div class="warn">Never expose the HL7 listener to the public internet. Analyser networks are flat and unauthenticated — keep this on a private VLAN.</div>`},
    {id:'in-11', title:'SMTP outbound email', read:'4 min', body:`<h2>Provider choices</h2><ul><li><b>Gmail</b> (Google Workspace) — easy to start; requires app-specific password; daily send limit ~2,000.</li><li><b>SendGrid</b> — transactional-email focused; reliable; pay per email.</li><li><b>Mailgun</b> — similar to SendGrid; African-friendly pricing.</li><li><b>Amazon SES</b> — cheapest at scale; requires moving out of the sandbox.</li><li><b>Self-hosted</b> — only if you have an experienced sysadmin and properly configured DNS.</li></ul><h2>DNS records</h2><p>Set up SPF (<code>v=spf1 include:_spf.google.com ~all</code> for Gmail), DKIM (provider gives you the public key to publish), and DMARC (<code>v=DMARC1; p=quarantine; rua=mailto:dmarc@yourlab.ng</code>). Without these, your emails go to spam.</p>`}
  ],

  'qc': [
    {id:'qc-1', title:'What is Quality Control in a clinical lab?', read:'4 min', body:`
      <h2>Why QC matters</h2>
      <p>Quality control (QC) confirms your instruments are performing correctly before releasing patient results. A QC failure means the instrument was out of specification — any patient results produced during that run must be held until the root cause is resolved.</p>
      <h2>How LabOS implements QC</h2>
      <p>LabOS uses <b>Levey-Jennings charts</b> with <b>Westgard multi-rules</b> — the international standard for clinical chemistry QC. For each analyte (Glucose, Creatinine, Haemoglobin, etc.) the system tracks the last 30 runs and evaluates all Westgard rules simultaneously.</p>
      <h2>Westgard rules enforced</h2>
      <ul>
        <li><b>1₂s</b> — Warning: one point outside ±2 SD. Proceed with caution.</li>
        <li><b>1₃s</b> — Reject: one point outside ±3 SD.</li>
        <li><b>2₂s</b> — Reject: two consecutive points on the same side, both outside 2 SD.</li>
        <li><b>R₄s</b> — Reject: range between two consecutive points exceeds 4 SD.</li>
        <li><b>4₁s</b> — Reject: four consecutive points outside 1 SD on the same side.</li>
        <li><b>10ₓ</b> — Reject: ten consecutive points all on the same side of the mean.</li>
        <li><b>7T</b> — Warning: seven consecutive points trending in one direction.</li>
      </ul>
      <div class="tip"><b>ISO 15189:</b> Documented QC procedures, Levey-Jennings charts, and corrective action records are mandatory for ISO 15189 accreditation. LabOS maintains this audit trail automatically.</div>
    `},
    {id:'qc-2', title:'Logging a QC run in LabOS', read:'3 min', body:`
      <h2>When to run QC</h2>
      <p>At the start of every shift, after a reagent lot change, after instrument maintenance or recalibration, and whenever a patient result seems implausible. Most labs run QC every 8 hours.</p>
      <h2>How to log a run</h2>
      <ol>
        <li>Navigate to <b>Quality Control</b> from the sidebar (Core Services)</li>
        <li>Click <b>+ Log QC run</b></li>
        <li>Select the analyte and instrument</li>
        <li>Enter the measured value — the z-score and Westgard status appear instantly as you type</li>
        <li>Select the operator and click <b>Log run</b></li>
      </ol>
      <p>If any rule is violated, a rejection banner appears and the affected analyte is flagged until you resolve it and log a passing run.</p>
    `},
    {id:'qc-3', title:'Reading a Levey-Jennings chart', read:'4 min', body:`
      <h2>Chart anatomy</h2>
      <p>The Y-axis shows the measured QC value; the X-axis shows run sequence. Horizontal lines mark the target mean and ±1, ±2, and ±3 SD.</p>
      <h2>Point colours</h2>
      <ul>
        <li><span style="color:#1F7A4D;font-weight:600">Green</span> — within ±2 SD: in control</li>
        <li><span style="color:#C77B14;font-weight:600">Amber</span> — ±2 to ±3 SD: warning</li>
        <li><span style="color:#9A1F1F;font-weight:600">Red</span> — beyond ±3 SD: reject</li>
      </ul>
      <h2>Patterns to spot</h2>
      <p><b>Trends</b> (7 points drifting one way) — usually reagent degradation or calibration drift. <b>Shifts</b> (10 points on the same side) — likely recalibration needed. <b>Runs</b> (2 consecutive outside 2 SD same side) — systematic error.</p>
      <h2>%CV and bias</h2>
      <p>%CV (coefficient of variation) measures precision — under 5% is generally acceptable for routine chemistry. Bias measures how far your mean sits from the target — above ±3% warrants investigation.</p>
    `},
    {id:'qc-4', title:'Responding to a QC rejection', read:'5 min', body:`
      <h2>Immediate steps</h2>
      <ol>
        <li><b>Stop releasing patient results</b> for the affected analyte</li>
        <li><b>Check the QC material</b> — stored correctly? Expired? Well mixed?</li>
        <li><b>Check the reagent</b> — within open-vial stability? Correct lot?</li>
        <li><b>Re-run QC</b> on a fresh aliquot before touching anything else</li>
        <li>If the re-run passes, the failure may have been a QC material issue — document and proceed</li>
        <li>If the re-run fails, <b>recalibrate the instrument</b> and run QC again</li>
        <li>If failure persists, escalate to the lab director and the instrument engineer</li>
      </ol>
      <h2>Documenting corrective action</h2>
      <p>ISO 15189 requires documented corrective action for every QC failure. Open the failing run on the QC detail screen and use <b>Log corrective action</b>.</p>
      <div class="warn"><b>Do not release patient results</b> from the failed batch until you have a passing QC run covering the same period.</div>
    `},
    {id:'qc-5', title:'Setting QC targets and changing lots', read:'3 min', body:`
      <h2>Where targets come from</h2>
      <p>From your QC material manufacturer's insert, or from your own lab's historical data (calculated from 20+ runs over at least 20 days). Your own performance data gives tighter, more meaningful limits.</p>
      <h2>Changing QC lot</h2>
      <p>Run both the old and new material in parallel for at least 5 days to verify your targets before retiring the old lot. LabOS supports parallel lot tracking during this transition.</p>
    `}
  ],

  'compliance': [
    {id:'cp-1', title:'NDPR compliance: what LabOS does and what you must do', read:'6 min', body:`
      <h2>What LabOS handles for you</h2>
      <ul>
        <li>AES-256 encryption at rest for all patient records and reports</li>
        <li>TLS 1.3 for all data in transit</li>
        <li>Tamper-evident audit logging (hash-chained) for all access to patient data</li>
        <li>Automated 90-day data retention after subscription cancellation</li>
        <li>Right-to-access, right-to-erasure, and data-portability endpoints — your patients can request their data via your portal</li>
        <li>Annual NDPR audit reports for download by your designated DPO</li>
      </ul>
      <h2>What you must do</h2>
      <ul>
        <li>Designate a Data Protection Officer (DPO) for your laboratory — record in <code>Settings → Compliance</code></li>
        <li>Display a privacy notice in your reception (template available in Help → Compliance)</li>
        <li>Train staff annually on NDPR — LabOS provides a free e-learning module under Help</li>
        <li>Respond to patient data requests within 30 days (LabOS automates 90% of this)</li>
        <li>Report any data breach to the NDPC within 72 hours — LabOS provides a guided incident-report workflow</li>
      </ul>
      <div class="warn"><b>Warning:</b> NDPR fines for non-compliance start at 2% of annual gross revenue. The annual compliance audit, included in your plan, helps you stay ahead.</div>
    `},
    {id:'cp-2', title:'MLSCN registration and CPD tracking', read:'4 min', body:`
      <h2>Why this matters</h2>
      <p>The Medical Laboratory Science Council of Nigeria (MLSCN) regulates laboratory practice. Every practising med-lab scientist must hold a current MLSCN licence, and each accredited laboratory must employ a registered scientist as its quality manager.</p>
      <h2>Recording credentials</h2>
      <p>On each staff member's profile, capture: MLSCN number, registration date, current licence expiry, area of practice. LabOS warns 60 days before expiry.</p>
      <h2>CPD points</h2>
      <p>MLSCN requires 30 CPD points every 3 years. LabOS tracks CPD points earned from in-app training modules, external courses (you upload certificates), and conference attendance. The CPD report exports as PDF for your MLSCN renewal.</p>
    `},
    {id:'cp-3', title:'The audit log — using it for investigations', read:'4 min', body:`
      <h2>When to consult the audit log</h2>
      <ul>
        <li>Patient reports a missing or altered result</li>
        <li>Insurance company queries a claim</li>
        <li>Court summons or police investigation</li>
        <li>Internal review after a critical incident</li>
        <li>Staff misconduct allegation</li>
      </ul>
      <h2>Filtering and export</h2>
      <p>From the Audit log page, filter by: date range, user, action type, patient ID, request ID. Export the filtered set as CSV (analysis) or PDF (court-ready, including the hash-chain verification certificate).</p>
    `},
    {id:'cp-4', title:'Data subject access requests (DSARs)', read:'4 min', body:`
      <h2>What a patient can request</h2>
      <p>Under NDPR, patients have rights to: access (see what you hold about them), portability (machine-readable export), rectification (correct errors), erasure (delete data, with clinical retention exceptions), restriction (limit processing).</p>
      <h2>Handling a request in LabOS</h2>
      <ol>
        <li>Verify the requester's identity (in-person ID or video call recorded)</li>
        <li>From the patient record, click <b>Privacy actions → DSAR</b></li>
        <li>Choose request type and any specific date range</li>
        <li>LabOS generates the response within 60 seconds: complete record bundle, formatted PDF + machine-readable JSON</li>
        <li>Hand over (or email with link) within 30 days of receipt</li>
      </ol>
      <p>Clinical records have a 6-year minimum retention even after erasure requests (NDPR exception for medical records). LabOS automatically pseudonymises erased records to balance both requirements.</p>
    `},
    {id:'cp-5', title:'Incident response and breach notification', read:'5 min', body:`
      <h2>What counts as a breach</h2>
      <p>Any unauthorised access, disclosure, alteration, or destruction of patient data. Examples: a staff laptop is stolen, a phishing attack succeeds, results are emailed to the wrong patient, the audit log shows access from an unexpected location.</p>
      <h2>The 72-hour clock</h2>
      <p>From the moment you become aware of a breach, you have 72 hours to notify the NDPC (Nigeria Data Protection Commission). LabOS's guided incident form pre-fills most of the notification.</p>
      <h2>Patient notification</h2>
      <p>If the breach is likely to result in high risk to patients (e.g. sensitive results disclosed), you must also notify the affected patients without undue delay. LabOS bulk-messages affected patients with a template you customise.</p>
    `}
  ,
    {id:'cp-6', title:'Security Center posture', read:'4 min', body:`<h2>What it surfaces</h2><p>Active sessions, recent failed logins, 2FA enrolment rate, password-age distribution, devices registered, recent permission changes. Open <b>Administration → Security Center</b>.</p><h2>What to act on weekly</h2><ul><li>Sessions older than 12 hours — review and revoke if not the user.</li><li>Failed-login spikes — possible brute-force; consider tightening rate limits or enabling CAPTCHA.</li><li>Users without 2FA — encourage or mandate.</li></ul><h2>Permission audits</h2><p>Run a permission audit quarterly: every staff member's role should match their current job. Departing staff should be deactivated within hours, not days.</p>`},
    {id:'cp-7', title:'Backup and recovery scheduling', read:'5 min', body:`<h2>What's backed up</h2><p>Patient records, test results, audit log, documents (referrals, reports, consent), configuration. Not backed up locally: external integration credentials (these are encrypted in the platform vault).</p><h2>Schedule</h2><p>Hourly transaction-log backups, nightly full-database backup, weekly off-site replication. Production deployments typically use managed Postgres with point-in-time recovery.</p><h2>Testing recovery</h2><p>Monthly: restore the latest backup to a staging instance and verify integrity. An untested backup is not a backup.</p><div class="warn">Never test recovery by restoring over the production database. Always restore to a separate instance.</div>`},
    {id:'cp-8', title:'Audit log deep dive', read:'5 min', body:`<h2>What the audit log captures</h2><p>Every login, logout, password change, patient/record view, edit, delete, release, export, billing action, configuration change. Each entry has: timestamp, user, action, target record, IP address, device fingerprint, and (for changes) before/after values.</p><h2>Searching and filtering</h2><p>By user, action type, date range, free-text search across action description. Export filtered results to CSV for evidence packs.</p><h2>Retention</h2><p>Audit logs are retained 7 years minimum (NDPR), 10 years recommended. Old entries are archived but never deleted.</p>`},
    {id:'cp-9', title:'Hash-chain verification', read:'4 min', body:`<h2>What it is</h2><p>Each audit entry includes the hash of the previous entry in a Merkle-style chain. Tampering with any entry breaks the chain — the verifier catches the break immediately.</p><h2>How to verify</h2><p>Run <b>Verify chain integrity</b> from the platform audit page. The verifier walks the chain and reports any breaks with timestamps. A clean run says "X entries, 0 breaks".</p><h2>If verification fails</h2><p>Treat it as a security incident. Take the system offline, preserve forensic evidence, contact AgoroX support immediately. Hash-chain breaks are usually attempted tampering, occasionally hardware corruption.</p>`},
    {id:'cp-10', title:'Data retention under NDPR', read:'4 min', body:`<h2>What NDPR requires</h2><p>Personal data should not be kept longer than necessary for the purpose collected. For clinical labs, that's typically: patient records 7 years (adults), to age of majority + 7 years (paediatric), 10 years (radiology), 20 years (oncology), 30 years (genetic testing).</p><h2>Patient rights</h2><p>Patients can request a copy of their data, correction of inaccuracies, and (for non-clinical data) deletion. Some data — like statutory disease notifications — cannot be deleted on request.</p><h2>LabOS configuration</h2><p>Retention periods are configured per data type in <b>Administration → Settings → Retention</b>. The nightly archival job moves records past their retention window to deep archive (encrypted, restricted access) or destroys them per policy.</p>`},
    {id:'cp-11', title:'Two-factor authentication enforcement', read:'3 min', body:`<h2>Who must use 2FA</h2><p>All users with access to patient data should use 2FA. For users with permission to release results or modify pricing, 2FA is mandatory and cannot be disabled.</p><h2>2FA methods supported</h2><ul><li>TOTP (Google Authenticator, Authy, 1Password) — recommended.</li><li>SMS OTP — supported but weakest; SIM-swap attacks exist.</li><li>Hardware key (FIDO2/WebAuthn) — strongest; recommended for admins.</li></ul><h2>Enrolment</h2><p>Users enrol from their profile page. The QR code is shown once; if the user loses access to their TOTP device, only an admin can reset.</p>`}
  ],
  'diagnostics': [
    {id:'dx-1', title:'Hematology workflow: from sample to validated CBC', read:'6 min', body:`<h2>What this covers</h2><p>The hematology screen handles complete blood counts, peripheral film reviews, ESR, reticulocyte counts and platelet morphology. This article walks through the full workflow from accessioning to validation.</p><h2>Sample acceptance</h2><p>EDTA tubes only — never serum or heparin for full blood counts. Reject samples that are clotted, haemolysed, lipaemic enough to interfere with optical counts, or older than 6 hours at room temperature. Sample-reject reasons are logged in the audit trail.</p><h2>Running the analyser</h2><p>Most labs use a Sysmex XN, Mindray BC-6800 or similar 5-part differential analyser. LabOS receives results via the HL7 bridge if you've configured one in Integrations. Otherwise enter the WBC, RBC, Hb, Hct, MCV, MCH, MCHC, platelets and 5-part differential manually under <b>Diagnostics → Hematology → New entry</b>.</p><h2>Flags and review rules</h2><p>The analyser sets flags for blasts, atypical lymphocytes, nucleated RBCs, platelet clumps and so on. Any flagged sample drops to <b>Pending review</b> and must be looked at on a stained film before release. LabOS surfaces the flagged samples in the worklist with an amber pill.</p><h2>Validation and release</h2><p>A medical laboratory scientist enters/reviews the numbers; a senior scientist or pathologist validates. Critical values (Hb &lt; 7, platelets &lt; 50, WBC &lt; 2 or &gt; 30) trigger a critical-value call workflow before release. The case is signed and routed to the patient report.</p><div class="warn">Don't release results that contradict the clinical picture without a film review — analyser-only platelet counts can miss clumps and report falsely low.</div>`},
    {id:'dx-2', title:'Interpreting and reporting full blood count results', read:'7 min', body:`<h2>Anaemia patterns</h2><p>Use MCV first: microcytic (&lt;80 fL) suggests iron deficiency or thalassaemia; normocytic (80–100) suggests anaemia of chronic disease, acute blood loss or renal anaemia; macrocytic (&gt;100) suggests B12/folate deficiency, alcohol, hypothyroidism or marrow disease.</p><h2>Leukocyte patterns</h2><p>Neutrophilia with left shift and toxic granulation: bacterial infection. Lymphocytosis with atypical cells: viral. Eosinophilia: parasitic, allergic, drug reaction. Pancytopenia: aplastic anaemia, marrow infiltration, hypersplenism — always refer for haematology review.</p><h2>Platelet considerations</h2><p>Thrombocytopenia: confirm with a fresh sample (clumps are common in EDTA). Thrombocytosis: reactive vs essential — look for inflammation markers.</p><h2>Writing the report</h2><p>The report should include the numeric panel, the reference ranges, any flags raised, and a free-text interpretation if abnormal. LabOS auto-generates the standard layout; you only add the interpretation.</p>`},
    {id:'dx-3', title:'Microbiology: culture, identification and antibiogram', read:'8 min', body:`<h2>Specimens accepted</h2><p>Urine, blood culture bottles, sputum, stool, wound swabs, CSF, body fluids, high vaginal and endocervical swabs. Each has a specific collection protocol and a maximum delay to plating — refer to the inline protocol card in <b>Diagnostics → Microbiology → New sample</b>.</p><h2>The culture workflow</h2><ol><li><b>Day 0</b> — Plate on appropriate media (CLED + blood + MacConkey for urine; chocolate + blood + MacConkey for sputum; Sabouraud for fungi). Set the LabOS stage to <i>incubating</i>.</li><li><b>Day 1</b> — Read plates. No growth → release "no growth at 24h". Mixed growth → assess significance. Pure growth → proceed to ID.</li><li><b>Identification</b> — Gram stain, biochemical tests, or send isolate to MALDI-TOF if available. Record the organism in LabOS.</li><li><b>Antibiogram</b> — Set up sensitivity testing (disc diffusion or VITEK). Record zone diameters or MICs. LabOS interprets against CLSI breakpoints.</li><li><b>Release</b> — Pathologist reviews the antibiogram, removes inappropriate antibiotics for the source (e.g. cefuroxime for UTI), and signs off.</li></ol><h2>Critical isolates</h2><p>MRSA, VRE, carbapenem-resistant Enterobacteriaceae, MDR-TB, Vibrio cholerae and Yersinia pestis trigger an automatic notifiable-disease alert. Don't release without infection-prevention notification.</p>`},
    {id:'dx-4', title:'Building and interpreting an antibiogram', read:'5 min', body:`<h2>What goes on the antibiogram</h2><p>Only antibiotics that are clinically appropriate for the source — gentamicin for UTI is misleading; nitrofurantoin for bacteraemia is dangerous. LabOS uses a source-aware panel: select urine, blood, sputum, wound or sterile site and the right discs are pre-populated.</p><h2>S, I, R interpretation</h2><p>LabOS reads zone diameters against the current CLSI breakpoint table. <b>S</b> (susceptible) — therapy likely to succeed at standard doses. <b>I</b> (intermediate) — therapy may succeed at high doses or in tissues where the drug concentrates. <b>R</b> (resistant) — therapy likely to fail.</p><h2>Common pitfalls</h2><ul><li>ESBL-producing E. coli may appear susceptible to cephalosporins on disc diffusion — confirm with ESBL screen.</li><li>Vancomycin susceptibility for staph aureus is unreliable by disc — use MIC.</li><li>Don't report inducible clindamycin resistance without a D-test on erythromycin-resistant staph.</li></ul>`},
    {id:'dx-5', title:'Immunology and serology panels', read:'6 min', body:`<h2>Common serology workflows</h2><p>HIV (rapid + Western blot for confirmation), Hepatitis B and C (HBsAg, anti-HCV, with follow-up viral load), Syphilis (RPR + TPHA), TB (IGRA or sputum AFB), H. pylori (stool antigen or serology).</p><h2>Autoimmune panels</h2><p>ANA, anti-dsDNA, RF, anti-CCP, ANCA — LabOS supports panel ordering so the right tests are bundled (e.g. "Lupus screen" pulls ANA + dsDNA + complement + urinalysis).</p><h2>Hormone and tumour markers</h2><p>Thyroid (TSH, T3, T4, anti-TPO), reproductive (LH, FSH, oestradiol, testosterone, prolactin, beta-HCG), tumour markers (PSA, CEA, AFP, CA-125, CA 19-9, CA 15-3). All are panel-buildable.</p><div class="warn">Tumour markers should not be used as screening tests in asymptomatic patients — they have poor specificity. LabOS shows a clinical-use warning when one is ordered without an oncology indication.</div>`},
    {id:'dx-6', title:'Toxicology drug screens', read:'5 min', body:`<h2>What LabOS supports</h2><p>Urine drug screens (cannabis, opiates, amphetamines, cocaine, benzodiazepines, methadone, MDMA), heavy metals (lead, mercury, arsenic — usually send-out), therapeutic drug monitoring (digoxin, vancomycin, valproate, phenytoin, lithium).</p><h2>Pre-employment vs medical-legal screens</h2><p>Medical-legal screens require chain-of-custody documentation. LabOS enforces sealed-collection, witness sign-off and a tamper-evident barcode label for any sample marked <i>medical-legal</i>.</p><h2>Confirmatory testing</h2><p>Immunoassay screens are sensitive but not specific. A positive screen result for a medical-legal case must be confirmed by GC-MS or LC-MS/MS at an accredited reference lab — order this via Send-outs.</p><h2>Interpreting cut-offs</h2><p>SAMHSA cut-offs are different from clinical cut-offs. LabOS shows both on the report; the requesting clinician chooses which to apply.</p>`},
    {id:'dx-7', title:'Critical-value handling across diagnostics', read:'4 min', body:`<h2>What triggers a critical-value alert</h2><p>LabOS ships with a default critical-value list, configurable per lab in <b>Administration → Settings → Critical values</b>. Defaults include: glucose &lt;2.8 or &gt;25 mmol/L, sodium &lt;120 or &gt;160, potassium &lt;2.5 or &gt;6.5, calcium &lt;1.6 or &gt;3.5, Hb &lt;7, platelets &lt;50, WBC &lt;2 or &gt;30, positive blood culture, positive CSF Gram stain.</p><h2>The call workflow</h2><p>When a critical value is entered, LabOS:</p><ol><li>Blocks auto-release of the report.</li><li>Drops the case into the <i>Critical-value queue</i>.</li><li>Prompts the lab scientist to call the requesting clinician.</li><li>Records who was called, when, the read-back confirmation, and the call duration.</li></ol><p>The call record is appended to the report and the audit log. The clinician's name is required.</p><div class="warn">Read-back is non-negotiable. The recipient must repeat the result; the scientist must record the read-back time. This is an ISO 15189 requirement and protects the lab in disputes.</div>`},
    {id:'dx-8', title:'Reflex testing rules', read:'4 min', body:`<h2>What is reflex testing</h2><p>Automatic follow-on tests triggered by a primary result. Examples: HBsAg positive → reflex to HBeAg and HBV DNA viral load; TSH abnormal → reflex to FT4 and FT3; positive blood culture → reflex to ID + sensitivity.</p><h2>Configuring rules</h2><p>Rules live in <b>Administration → Settings → Reflex rules</b>. Each rule has a trigger (test + condition), an action (additional tests to order), and a sponsor (who pays — the patient, the requester or the lab).</p><h2>Patient consent and cost</h2><p>If reflex tests have an additional charge, LabOS will prompt the patient at registration to consent. For NHIS / HMO patients, reflex tests may be pre-authorised under the payer's standing protocol.</p>`}
  ],
  'imaging': [
    {id:'im-1', title:'Ordering an imaging study', read:'4 min', body:`<h2>From request to scheduling</h2><p>Open <b>Imaging &amp; Diagnostic → [modality] → + New order</b>. Pick the patient, the requesting clinician, the body part, the clinical indication, and any contrast requirements. LabOS auto-suggests the right CPT/NHIS billing code based on the body part and modality.</p><h2>Pre-imaging checks</h2><p>For contrast studies, LabOS requires creatinine within 30 days, allergy history, and pregnancy status for women of reproductive age. The order can't be scheduled until these are documented.</p><h2>Scheduling</h2><p>Pick a slot from the modality calendar. LabOS shows technologist availability and avoids double-booking the scanner. Patients receive an automatic appointment reminder via SMS/WhatsApp if Termii is configured.</p><h2>Stages of an imaging order</h2><p>Scheduled → Awaiting payment → Patient arrived → Images acquired → With radiologist → Reported → Released. Each stage records a timestamp and the staff member responsible.</p>`},
    {id:'im-2', title:'CT and MRI workflow including contrast', read:'6 min', body:`<h2>CT workflow</h2><p>For non-contrast CT, the patient can be scanned immediately after arrival. For contrast-enhanced CT, follow this sequence:</p><ol><li>Confirm creatinine &lt; 1.5 mg/dL (or eGFR &gt; 30) within 30 days.</li><li>Confirm no prior severe reaction to iodinated contrast.</li><li>Confirm metformin held 48h prior if eGFR borderline.</li><li>IV access — 18G in antecubital fossa is standard.</li><li>Inject power injector at the protocol rate (3–5 mL/s depending on study).</li><li>Acquire scans at the protocol delays (arterial, portal, delayed).</li></ol><h2>MRI workflow</h2><p>MRI safety screening is mandatory before every scan — pacemakers, cochlear implants, ferromagnetic foreign bodies, recent vascular stents (&lt;6 weeks) and pregnancy in the first trimester are absolute or relative contraindications.</p><h2>Contrast (gadolinium)</h2><p>Document eGFR — avoid gadolinium-based agents if eGFR &lt; 30 (risk of nephrogenic systemic fibrosis). Use macrocyclic agents preferentially.</p><div class="warn">Gadolinium and iodinated contrast are not interchangeable. Selecting the wrong one in LabOS will trigger a hard-stop validation error.</div>`},
    {id:'im-3', title:'Ultrasound: organising the worklist', read:'4 min', body:`<h2>Common US studies in LabOS</h2><p>Abdominal (liver, gallbladder, kidneys, pancreas, spleen, aorta), pelvic (transabdominal vs transvaginal — patient consent matters), obstetric (1st/2nd/3rd trimester have different protocols), thyroid, breast (with or without elastography), Doppler (venous, arterial, renal).</p><h2>Reporting templates</h2><p>Each study has a structured template under <b>Imaging → Templates</b>. The template auto-populates the relevant anatomy headings; the sonographer fills measurements and impressions.</p><h2>Saving images</h2><p>In production, images stream to the DICOM viewer. In LabOS's preview build the images are represented by their metadata only — the integration with Cornerstone or OHIF lives in the production backend.</p>`},
    {id:'im-4', title:'ECG and Holter workflow', read:'5 min', body:`<h2>Resting 12-lead ECG</h2><p>Open the patient's order, attach the leads using the standard placement, capture 10 seconds at 25 mm/s. LabOS supports import of standard SCP-ECG, FDA-XML and PDF outputs from common machines (Schiller, GE, Philips).</p><h2>Holter (24h or 48h)</h2><p>Fit the device, give patient instructions about activity diary, schedule a 24-hour return. On return, upload the recording — LabOS shows the rhythm summary, total beats, ventricular ectopy burden and any pauses &gt; 2.5 seconds.</p><h2>Interpretation</h2><p>The cardiologist annotates rhythm strips, gives an impression and signs off. The signed report includes a representative rhythm strip (12-lead reduced) for clinical reference.</p>`},
    {id:'im-5', title:'Echocardiography', read:'5 min', body:`<h2>Standard transthoracic echo</h2><p>Parasternal long axis, short axis (multiple levels), apical 4/5/2/3 chamber, subcostal and suprasternal views. LabOS's template captures LV size and function, RV size and function, all four valves, pericardium and great vessels.</p><h2>Measurements that matter</h2><ul><li><b>LV ejection fraction</b> — biplane Simpson's preferred; eyeball estimate acceptable for normal hearts.</li><li><b>LA volume index</b> — &gt;34 mL/m² indicates remodelling.</li><li><b>E/A ratio and E/e'</b> — diastolic function.</li><li><b>Aortic root and ascending aorta</b> — measure in diastole.</li></ul><h2>Stress echo and TOE</h2><p>Both supported as separate study types in LabOS with their own structured templates. TOE consent and sedation documentation are required before release.</p>`},
    {id:'im-6', title:'Diagnostic Reporting — cross-modality sign-off', read:'4 min', body:`<h2>What this screen is for</h2><p>The Diagnostic Reporting worklist gathers all imaging studies awaiting radiologist review across CT, MRI, US, ECG and echo. It's where radiologists work — not the per-modality screens, which are for technologists.</p><h2>Review and sign-off</h2><p>Each line shows the patient, modality, indication, urgency and time-since-acquisition. Click into a study to open the structured template pre-populated with technologist findings; the radiologist annotates, adds impressions, and signs.</p><h2>Critical findings</h2><p>Marking a study "critical" triggers the same call workflow as lab critical values — clinician must be contacted within 30 minutes, with read-back recorded.</p>`},
    {id:'im-7', title:'DICOM viewer integration', read:'3 min', body:`<h2>What ships with LabOS</h2><p>The frontend has placeholders for the DICOM viewer; the actual viewer (Cornerstone or OHIF) integrates server-side. In production, clicking an imaging study opens the viewer in a side panel with windowing controls, measurements and annotation.</p><h2>What you can do today</h2><p>Browse study metadata, view structured templates, attach external image files, and sign off reports. Full image rendering plugs in when your PACS endpoint is configured under <b>Integrations</b>.</p>`},
    {id:'im-8', title:'Image storage and retention', read:'3 min', body:`<h2>Storage</h2><p>Images are stored on your PACS server (production) or as attached PDFs/JPEGs (preview build). LabOS stores the study metadata, report and DICOM SOP instance UIDs; the pixel data lives on PACS.</p><h2>Retention</h2><p>NHA guideline: 10 years for adult imaging, until age of majority + 7 years for paediatric. Mammography 10 years, oncology 20 years. LabOS records the retention policy per modality; the archival job runs nightly and moves studies older than the policy to deep archive (configurable).</p><h2>Patient request for images</h2><p>Patients can request a copy of their images on a USB or CD. LabOS records the request, charges the configured fee, and burns/uploads the de-identified study.</p>`}
  ],
  'packages': [
    {id:'pk-1', title:'Health package overview', read:'3 min', body:`<h2>What's in Clinical Packages</h2><p>Pre-defined bundles of tests sold as a single product: Pre-Employment Medical, Annual Wellness, Executive Health, Antenatal package, Fertility workup, STI screen, Travel health, Vaccination, Occupational health, Chronic disease monitoring and Insurance medical.</p><h2>Why use packages</h2><p>Single-price billing, single appointment slot, one consolidated report. Patients understand a "package" better than a list of individual tests. The lab gets a predictable margin.</p><h2>Setting up a package</h2><p>Define the tests included, the price (bundled discount), the sample-collection schedule and the report template under <b>Administration → Pricing → Packages</b>.</p>`},
    {id:'pk-2', title:'Pre-employment medical workflow', read:'5 min', body:`<h2>What's typically included</h2><p>FBC, urinalysis, fasting glucose, lipid profile, LFTs, U&amp;Es, HIV, Hepatitis B + C, chest X-ray, ECG (if &gt; 40 years), eye check, vital signs and a medical history form completed by an in-house doctor.</p><h2>Workflow</h2><ol><li>Register the candidate (corporate sponsor identified).</li><li>Take sample(s) and perform tests in parallel.</li><li>Doctor performs the physical exam and ECG review.</li><li>Compile results into the standard pre-employment certificate.</li><li>Stamp "Fit / Fit with restrictions / Unfit" and release to the sponsoring HR.</li></ol><h2>Confidentiality</h2><p>The candidate has a right to their own results. The HR sponsor receives the fit/unfit outcome and any work-related restrictions — not the individual test values, unless the candidate consents.</p><div class="warn">Don't release HIV status to the employer. NDPR + ILO guidance is clear: HIV is not a fitness-to-work issue except for specific safety-sensitive roles.</div>`},
    {id:'pk-3', title:'Antenatal package', read:'5 min', body:`<h2>Tests typically included</h2><p>Booking visit: FBC, blood group + Rh, HIV, Hepatitis B + C, syphilis (RPR), urinalysis, fasting/random glucose, dating ultrasound. Subsequent visits add OGTT (24–28 weeks), repeat FBC and a third-trimester ultrasound.</p><h2>Linking to obstetrician</h2><p>The package can be linked to an external OB-GYN partner. Results are pushed to the partner via secure email or HL7 if configured, and a copy is given to the patient.</p><h2>Special cases</h2><ul><li><b>Rh-negative patients</b> — LabOS flags for anti-D prophylaxis discussion at 28 weeks and after any sensitising event.</li><li><b>Glycosuria</b> — auto-reflex to OGTT.</li><li><b>Positive syphilis</b> — confirmatory TPHA and partner notification per public health policy.</li></ul>`},
    {id:'pk-4', title:'Executive wellness package', read:'3 min', body:`<h2>Typical content</h2><p>Comprehensive haematology + chemistry panel, full lipid + cardiac risk, thyroid, prostate (men &gt;45) or breast/cervical screen (women), tumour markers (used judiciously), abdominal + pelvic ultrasound, ECG + echo, treadmill stress test, chest X-ray and a face-to-face consultation with an internal medicine consultant.</p><h2>Half-day vs full-day</h2><p>Most labs run an executive package as a half-day visit. Schedule the consultation last so the doctor reviews all results in one sitting.</p>`},
    {id:'pk-5', title:'Insurance / HMO sponsored package', read:'5 min', body:`<h2>HMO authorisation</h2><p>Before commencing the package, capture the HMO authorisation code in LabOS. Without it, the bill defaults to self-pay. The patient may be required to pay the gap (any test outside the HMO schedule).</p><h2>Claim submission</h2><p>After the package completes, LabOS generates a claim package: encounter ID, list of tests, total amount, supporting reports. This is submitted to the NHIS Portal (if integrated) or exported as a PDF for manual upload.</p><h2>Reconciliation</h2><p>Track outstanding HMO claims in <b>Billing → Outstanding</b>. LabOS shows ageing buckets (0–30, 31–60, 61–90, 90+ days) so the lab can chase HMOs that don't pay on time.</p>`},
    {id:'pk-6', title:'Generating the package certificate', read:'3 min', body:`<h2>Standard certificate format</h2><p>The package certificate combines all results into a single PDF: cover page (patient name, package, date, conclusion), per-test results pages, normal range references, physician sign-off and lab letterhead.</p><h2>Customising</h2><p>Each package can have a custom certificate template under <b>Administration → Pricing → Packages → [package] → Certificate</b>. You can include the corporate sponsor logo, a fitness statement and a follow-up recommendation.</p><h2>Distribution</h2><p>The certificate is automatically emailed to the patient (and HR sponsor for pre-employment) once signed. The original is filed in the patient record and the audit trail.</p>`}
  ],
  'biobank': [
    {id:'bb-1', title:'Specimen accession and barcode labelling', read:'5 min', body:`<h2>What goes into BiobankOS</h2><p>Long-term storage specimens: serum, plasma, DNA, RNA, FFPE blocks, fresh-frozen tissue, urine, stool, swabs. Anything that will be retained beyond the standard clinical retention period for research or chain-of-custody reasons.</p><h2>Accession workflow</h2><ol><li>Open <b>BiobankOS → Specimen Repository → + Accession</b>.</li><li>Link to the patient and parent study (or mark as clinical retention).</li><li>Capture specimen type, volume, container, collection date/time, freeze cycles.</li><li>Print the barcode label — affix to the cryovial before storing.</li><li>Assign storage location (freezer, rack, box, position).</li></ol><h2>Barcode standard</h2><p>LabOS uses Code-128 by default. Consider Data Matrix for very small cryovials where a longer linear barcode won't fit on the lid.</p>`},
    {id:'bb-2', title:'Cryostorage management and temperature monitoring', read:'5 min', body:`<h2>Storage tiers</h2><p>+4°C (short-term holding), -20°C (intermediate, weeks to months), -80°C (long-term, years), liquid nitrogen vapour phase (decades — viable cells). Each location in BiobankOS is tagged with its target temperature and an alarm threshold.</p><h2>Temperature logging</h2><p>For accredited biobanks, continuous temperature logging is required. Most modern freezers expose a serial or Ethernet feed; in production, LabOS reads this hourly and writes excursions to a log. In the preview build, log excursions manually.</p><h2>Excursion response</h2><p>An excursion is any temperature outside the alarm window for &gt; 15 minutes. The biobank manager is alerted; affected specimens are flagged for impact assessment. Some assays tolerate one excursion, others don't.</p><div class="warn">Don't move specimens between tiers unnecessarily — every freeze-thaw cycle degrades nucleic acids and proteins. Aliquot at accession so individual aliquots can be used without thawing the whole sample.</div>`},
    {id:'bb-3', title:'Consent capture and withdrawal', read:'5 min', body:`<h2>What consent must cover</h2><p>The consent form documents who may access the specimen, for what purposes (specific studies vs broad research consent), retention period, withdrawal rights, return-of-results policy, and any commercial use.</p><h2>Capturing in LabOS</h2><p>Upload the signed consent PDF to the specimen record under <b>Consent</b>. Capture the consent version, signing date and witness. Set the consent expiry if applicable.</p><h2>Withdrawal cascade</h2><p>If a participant withdraws consent, LabOS triggers a cascade: flag every specimen from that participant, freeze further research use, and (per the participant's choice) destroy the specimens or anonymise them irreversibly. The destruction is logged with date and the staff member responsible.</p>`},
    {id:'bb-4', title:'Setting up a research study', read:'4 min', body:`<h2>Study record</h2><p>A study in BiobankOS has a PI, an IRB/ethics-committee approval number, an end date, a list of authorised users, and access rules (full data vs de-identified vs aggregate only).</p><h2>Linking specimens</h2><p>Specimens are linked to studies at accession or later. A specimen can be linked to multiple studies if the consent covers them.</p><h2>Audit</h2><p>Every access (specimen pull, data export, result return) is logged with timestamp, user and reason. This is essential for IRB compliance.</p>`},
    {id:'bb-5', title:'Chain of custody', read:'4 min', body:`<h2>When chain of custody matters</h2><p>Medico-legal cases, drug-screening for medical-legal use, forensic specimens, and any specimen that may be evidence. Chain of custody documents every transfer of the specimen.</p><h2>What LabOS records</h2><p>For each transfer: who released, who received, when, the seal numbers (intact/broken), the transport conditions and the receipt confirmation. A broken seal renders the chain compromised; the specimen may be inadmissible as evidence.</p><h2>Reporting</h2><p>The chain-of-custody report is available as a PDF showing every transfer in order. This is what's presented in court if needed.</p>`},
    {id:'bb-6', title:'Biobank reporting and inventory', read:'3 min', body:`<h2>Inventory reports</h2><p>Total specimens by type, by storage location, by study, by participant demographics. Run from <b>BiobankOS → Reports → Inventory</b>.</p><h2>Utilisation</h2><p>Tracks how many specimens have been used (consumed) vs remain. Useful for grant renewals and PI accountability.</p><h2>Capacity planning</h2><p>Free-position counts per freezer and rack. Once a freezer is &gt; 90% full, BiobankOS alerts the manager to procure additional storage.</p>`}
  ],
  'research': [
    {id:'rs-1', title:'Sequencing run workflow', read:'6 min', body:`<h2>Supported platforms</h2><p>Illumina (MiSeq, NextSeq, NovaSeq), Oxford Nanopore (MinION, PromethION), and Ion Torrent. Each platform's run metadata is captured in LabOS — read length, paired-end vs single-end, flowcell/chip ID, library prep kit and chemistry version.</p><h2>From library to results</h2><ol><li><b>Library prep</b> — record the protocol, kit lot, input quantity, QC metrics (Bioanalyzer/TapeStation traces).</li><li><b>Pooling</b> — for multiplexed runs, capture the index sequences and expected proportions.</li><li><b>Run</b> — start in LabOS so the timer captures expected duration; attach the sequencer's run folder when complete.</li><li><b>Demultiplexing</b> — bcl2fastq or equivalent generates per-sample FASTQ files. Record the demux QC.</li><li><b>Hand-off</b> — pass to Bioinformatics for analysis.</li></ol>`},
    {id:'rs-2', title:'Bioinformatics pipelines', read:'5 min', body:`<h2>What LabOS tracks</h2><p>The bioinformatics workflow records inputs (which FASTQ files), the pipeline used (with version pinned to a commit hash or container tag), the reference genome (e.g. GRCh38 / GRCh37), and outputs (BAM, VCF, MultiQC reports).</p><h2>Why version pinning matters</h2><p>Variant calls change between pipeline versions. For clinical or publication use, the pipeline version must be reproducible. LabOS stores the container hash so a re-run years later produces the same calls.</p><h2>Standard pipelines</h2><p>WGS/WES: BWA-MEM → GATK HaplotypeCaller → annotation (VEP or ANNOVAR). RNA-seq: STAR → featureCounts / Salmon → DESeq2. Targeted panels: vendor-supplied pipelines often preferred for regulatory clarity.</p>`},
    {id:'rs-3', title:'Clinical trial setup', read:'5 min', body:`<h2>Trial record</h2><p>A trial in LabOS has a sponsor, protocol number, ethics approval, list of sites, target enrolment, primary endpoint and a list of required visits with scheduled tests.</p><h2>Participant enrolment</h2><p>Participants are registered as patients but tagged with the trial ID and arm. The visit schedule generates appointment slots automatically.</p><h2>Source data verification</h2><p>Monitors visit periodically to verify that source documents match the eCRF. LabOS exports the source data as PDFs for review — the audit log proves which user entered each value and when.</p>`},
    {id:'rs-4', title:'Cohort management', read:'4 min', body:`<h2>Defining a cohort</h2><p>A cohort is a queryable group of patients meeting specific criteria — e.g. "all type 2 diabetes patients with HbA1c &gt; 9% in the last 12 months". Cohorts are dynamic: as new patients meet the criteria, they're added automatically.</p><h2>Use cases</h2><p>Quality improvement studies, recall campaigns, retrospective research (with IRB approval), audit of clinical pathways.</p><h2>De-identification</h2><p>Cohorts can be exported in de-identified form — direct identifiers removed, dates shifted by a random per-patient offset, free-text scrubbed for names.</p>`},
    {id:'rs-5', title:'Genomic findings and return of results', read:'5 min', body:`<h2>Categorising findings</h2><p>ACMG classification: Pathogenic, Likely pathogenic, Variant of uncertain significance, Likely benign, Benign. Only the first two are normally returned to patients in clinical reports.</p><h2>Secondary findings</h2><p>If the patient consented to it, ACMG's secondary-findings list (currently 78 genes) is screened on every WES/WGS. Findings are returned through a genetic counsellor — not in the routine lab report.</p><h2>Re-analysis</h2><p>Variants reclassified over time. Plan for periodic re-analysis of stored VCFs — variants currently VUS may become pathogenic as evidence accumulates. LabOS notifies the responsible clinician.</p>`},
    {id:'rs-6', title:'Linking research to BiobankOS', read:'3 min', body:`<h2>Connected systems</h2><p>Sequencing runs reference the source DNA/RNA aliquot's BiobankOS specimen ID. This means every dataset is traceable back to a consent-documented physical specimen.</p><h2>Withdrawal cascade</h2><p>If a participant withdraws consent for research, the cascade reaches sequencing data: VCFs are tagged restricted, removed from active studies, and either destroyed or fully anonymised per the participant's choice.</p>`}
  ],
  'notifications': [
    {id:'nt-1', title:'Compose a notification', read:'3 min', body:`<h2>From the Notifications Engine</h2><p>Click <b>+ Compose</b> on the Notifications page. Pick a recipient (patient search), a channel (SMS, WhatsApp, Email, In-app), a template, and adjust the body. Submit to queue.</p><h2>What 'queued' means</h2><p>The message lives in the delivery queue with status <code>queued</code>. In production, the LabOS dispatcher polls the queue and calls the configured provider — Termii for SMS/WhatsApp, your SMTP for email. If the provider isn't configured for that channel, the queue entry stays queued.</p><h2>Manual vs automatic</h2><p>Compose is for ad-hoc messages. Automatic notifications (appointment reminders, result-ready alerts) are configured under <b>Notifications → Rules</b> and fire on workflow events.</p>`},
    {id:'nt-2', title:'Template variables', read:'3 min', body:`<h2>Substitutions LabOS fills</h2><p>At send time the dispatcher replaces these tokens in the message body:</p><ul><li><code>{{name}}</code> — patient's full name</li><li><code>{{lab}}</code> — current laboratory name</li><li><code>{{date}}</code> — current date (YYYY-MM-DD)</li><li><code>{{time}}</code> — current time (HH:MM)</li><li><code>{{amount}}</code> — invoice amount (where applicable)</li><li><code>{{ref}}</code> — reference number</li><li><code>{{link}}</code> — patient portal link to the report</li><li><code>{{phone}}</code> — lab's primary phone number</li></ul><h2>Where to add custom variables</h2><p>Custom variables can be added per template in <b>Notifications → Templates → [template]</b>. The dispatcher pulls the matching field from the record being notified about.</p>`},
    {id:'nt-3', title:'SMS and WhatsApp via Termii', read:'4 min', body:`<h2>Why Termii</h2><p>Termii is a Nigerian provider with good local network coverage and competitive WhatsApp Business pricing. Other African providers (Africa's Talking, Hubtel) work similarly — point the dispatcher at their endpoint server-side.</p><h2>Sender IDs</h2><p>For SMS, register a sender ID with Termii (e.g. "YOURLAB", max 11 characters). Without registration, messages fall back to a numeric short code.</p><h2>WhatsApp Business</h2><p>WhatsApp Business requires a verified business number. Termii facilitates verification. Template messages must be pre-approved by Meta; free-form is only allowed within 24 hours of a customer-initiated message.</p><h2>Delivery confirmation</h2><p>Termii returns delivery status; LabOS updates the queue entry to <code>sent</code> or <code>failed</code>. Failed messages can be retried automatically up to 3 times.</p>`},
    {id:'nt-4', title:'Email dispatch via SMTP', read:'4 min', body:`<h2>What SMTP we support</h2><p>Any standard SMTP server: Gmail (with app-specific password), Sendgrid, Mailgun, Amazon SES, your own corporate mail server. Configure under <b>Integrations → Email (SMTP)</b>.</p><h2>From-address considerations</h2><p>Use an address on your domain (e.g. <code>noreply@yourlab.ng</code>) with a valid SPF + DKIM + DMARC record. Without these, deliverability suffers — patients' emails will land in spam.</p><h2>Attachments</h2><p>LabOS attaches the patient's PDF report to the email automatically when the trigger is "Result ready". For privacy, the email body never includes the actual results — just a confirmation that they're available.</p><div class="warn">PHI in email is a NDPR compliance risk. Even with SMTP encryption, the recipient's mailbox may not be secure. Prefer SMS-with-portal-link or in-app delivery for sensitive results.</div>`},
    {id:'nt-5', title:'Queue retry behaviour', read:'3 min', body:`<h2>Retry policy</h2><p>The dispatcher retries failed messages: 1 minute, 5 minutes, 30 minutes, 2 hours, 12 hours. After 5 retries (24h total), the message moves to <code>dead-letter</code> status and the lab admin is notified.</p><h2>Common failure reasons</h2><ul><li><b>Invalid phone format</b> — phone numbers must be in E.164 (e.g. +2348012345678). LabOS auto-formats on patient registration but legacy data may need cleanup.</li><li><b>Provider downtime</b> — transient; retries usually resolve.</li><li><b>Insufficient credit</b> — Termii returns a specific error; top up the account.</li><li><b>Recipient opted out</b> — patient unsubscribed; respect this.</li></ul><h2>Manual retry</h2><p>Open the queue entry and click Retry. The dispatcher re-queues with retry-count reset.</p>`}
  ]
};


const HELP_FAQS = [
  {q:'How do I add a new test not in the catalogue?', a:'The test catalogue is platform-managed to ensure standardisation and pricing consistency. Contact support at support@agorox.africa — most additions are made within 48 hours. Enterprise customers can request custom in-house tests added to their tenant-only catalogue.'},
  {q:'Can patients see their own reports online?', a:'Yes. Each released report includes a unique link and QR code. Patients can view the PDF on their phone — no app needed. Reports remain available for 6 months by default, configurable under Settings.'},
  {q:'What is the difference between the 4 plans?', a:'CoreCare (₦180k/yr) covers 1 centre, 10 staff, and includes core diagnostics (Hematology, Microbiology, Immunology). Standard (₦540k) adds Renal, Histopathology and Toxicology. Professional (₦1.08m) adds Molecular, Imaging, BiobankOS and API access across up to 10 centres. Enterprise (₦2.88m) is fully unlimited and includes DNA & Genetics, CT/MRI, Research, white-label branding and a dedicated database.'},
  {q:'Does LabOS work offline?', a:'Yes — the offline core queues all actions (patient registration, requests, result entry) when connectivity drops. Changes sync automatically when the connection returns. Releasing reports and Paystack transactions require an active connection.'},
  {q:'How do I respond to a patient data request (DSAR) under NDPR?', a:'Go to Privacy & Data Rights → + New data request. Log the patient\'s request type and details. For access or portability requests, click Process — LabOS generates a JSON export of all their data for you to send securely. You have 30 days to respond under NDPR; LabOS tracks the deadline automatically.'},
  {q:'How is data backed up?', a:'Full snapshots are taken daily at 03:00 WAT and stored encrypted in two regions. Point-in-time recovery covers the last 30 days. Professional and Enterprise customers can add the Disaster Recovery add-on (₦180,000/year) for hourly backups and a 4-hour RTO SLA.'},
  {q:'What happens if we exceed our plan\'s patient limit?', a:'You are warned at 80% of the limit. At 100%, adding new patients is blocked and you\'ll see an upgrade prompt. You can purchase the Patient Volume Overage add-on (₦150 per patient above your cap) or upgrade your plan.'},
  {q:'How do I set up Quality Control for my instruments?', a:'Navigate to Quality Control in the sidebar. Click + Log QC run to add your first run for any analyte. LabOS evaluates all Westgard rules automatically and shows a Levey-Jennings chart. QC targets and lot details are updated from the analyte detail screen.'},
  {q:'Can I export all my data?', a:'Yes — from Settings → Backup & Recovery, request a full export. You\'ll receive a download link within 24 hours with all your data as JSON, CSV (tabular data), and PDF (reports). This is your right under NDPR and it\'s free and unlimited.'},
  {q:'How do I migrate from another LIMS?', a:'Our migration team handles this on Professional and Enterprise plans at no extra cost. We have proven import paths from MS Excel, Helium Health, Sokomed, and most legacy LIS systems. Typical timeline is 2 weeks for data import plus 1 week of parallel running.'},
  {q:'What languages does LabOS support?', a:'The interface supports English (default), Hausa, Yoruba, and Igbo. Switch language using the EN / HA / YO / IG buttons at the bottom of the sidebar. Hausa has the most complete translation — further translations are ongoing.'},
  {q:'How does the referral doctor portal work?', a:'Referring clinicians can access a secure read-only portal showing released results for their patients. They log in with their MDCN number and a one-time code. They can view results and download PDF reports — they cannot modify any data. Enable it from Administration → Settings → Referral Access.'},
  {q:'What is the Instrument Gateway and do I need it?', a:'The LabOS Instrument Gateway is a Windows desktop app that connects your laboratory analyzers directly to LabOS, automatically importing results without manual re-typing. You need it if you want to eliminate manual result entry. Without it, scientists type results by hand. With it, results appear automatically the moment the analyzer completes a run. It supports RS-232 serial, TCP/IP, ASTM, and HL7 protocols — covering Mindray, Sysmex, Roche Cobas, and most other analyzers used in Nigeria.'},
  {q:'Which analyzers does the Instrument Gateway support?', a:'The Gateway supports any analyzer that uses ASTM E1381/E1394 or HL7 v2.x protocols — which covers the vast majority of analyzers in Nigerian labs. This includes Mindray BC-series (hematology) and BS-series (chemistry), Sysmex KX-21 and XP-300, Roche Cobas c-series, Erba XL-series, and Dirui CS-series. A Generic ASTM Driver covers any ASTM-compliant analyzer not specifically listed.'}
];

/* ==========================================================
   TEST PRICING (per-tenant overrides on the global catalogue)
   ========================================================== */

window.PRICING_STATE = window.PRICING_STATE || {search:'', categoryFilter:'all', showOverridesOnly:false};

function saveTenantPricing(){
  if(!requireLicensed('save pricing')) return;
  const t = currentTenant();
  const overrides = (APP_STATE.tenantPricing && APP_STATE.tenantPricing[t.id]) || {};
  const n = Object.keys(overrides).length;
  // Prices already persist live to APP_STATE.tenantPricing as each cell is
  // edited; this records the save to the offline outbox and confirms.
  OfflineCore.record('pricing.save', {tenantId:t.id, overrides:n}, `Pricing saved — ${n} custom price${n===1?'':'s'}`);
  OfflineCore.schedulePersist();
  toast(`Pricing saved — ${n} custom price${n===1?'':'s'} in effect. New prices apply to all new test requests.`, {type:'success', title:'Saved', duration:4500});
}

function renderPricing(root){
  const t = currentTenant();
  const st = PRICING_STATE;
  const overrides = (APP_STATE.tenantPricing && APP_STATE.tenantPricing[t.id]) || {};
  const overrideCount = Object.keys(overrides).length;
  const cats = Object.keys(APP_STATE.testCatalog);

  // Compute revenue impact summary
  let totalDefault = 0, totalCustom = 0;
  for(const tests of Object.values(APP_STATE.testCatalog)){
    for(const test of tests){
      totalDefault += test.price;
      totalCustom += getPrice(test.code);
    }
  }
  const deltaPct = ((totalCustom - totalDefault) / totalDefault) * 100;

  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title" style="display:flex;align-items:center;gap:10px">${sectionIcon('pricing', 24)} Test pricing</div>
        <div class="page-subtitle">Set your laboratory's prices for any of the ${Object.values(APP_STATE.testCatalog).reduce((s,a)=>s+a.length,0)} catalogue tests. Untouched tests use the platform default.</div>
      </div>
      <div class="actions">
        <button class="btn" onclick="openBulkMarkup()">Bulk markup…</button>
        <button class="btn" onclick="openResetAllPrices()" ${overrideCount===0?'disabled':''}>Reset all</button>
        <button class="btn primary" onclick="saveTenantPricing()">Save changes</button>
      </div>
    </div>

    <div class="stats-grid" style="margin-bottom:20px">
      <div class="stat-card"><div class="stat-label">Custom prices set</div><div class="stat-value">${overrideCount}</div><div class="stat-trend">of ${Object.values(APP_STATE.testCatalog).reduce((s,a)=>s+a.length,0)} tests</div></div>
      <div class="stat-card"><div class="stat-label">Catalogue value (defaults)</div><div class="stat-value">${naira(totalDefault)}</div><div class="stat-trend">Sum of all 267 prices</div></div>
      <div class="stat-card"><div class="stat-label">Your catalogue value</div><div class="stat-value">${naira(totalCustom)}</div><div class="stat-trend" style="color:${deltaPct>=0?'#1B6B3A':'#9A1F1F'}">${deltaPct>=0?'+':''}${deltaPct.toFixed(1)}% vs default</div></div>
      <div class="stat-card"><div class="stat-label">Currency</div><div class="stat-value">NGN</div><div class="stat-trend">₦ Nigerian Naira</div></div>
    </div>

    <div class="card" style="padding:14px 16px;margin-bottom:14px;display:flex;gap:12px;align-items:center;flex-wrap:wrap">
      <div class="rx-searchbar" style="flex:1;min-width:240px;margin:0">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
        <input type="text" placeholder="Search by test name or code…" value="${st.search}" oninput="PRICING_STATE.search=this.value.toLowerCase();updatePricingTable()">
      </div>
      <select class="input" style="width:200px;margin:0" onchange="PRICING_STATE.categoryFilter=this.value;updatePricingTable()">
        <option value="all">All categories</option>
        ${cats.map(c=>`<option value="${c}" ${c===st.categoryFilter?'selected':''}>${c}</option>`).join('')}
      </select>
      <label style="display:flex;align-items:center;gap:6px;font-size:13px;cursor:pointer">
        <input type="checkbox" ${st.showOverridesOnly?'checked':''} onchange="PRICING_STATE.showOverridesOnly=this.checked;updatePricingTable()">
        Show only my custom prices
      </label>
    </div>

    <div id="pricing-table-wrap">${renderPricingTable()}</div>
  `;
}

// Update only the pricing table (and count) without re-rendering the page —
// keeps the search box focused and the cursor in place while typing.
function updatePricingTable(){
  const wrap = document.getElementById('pricing-table-wrap');
  if(wrap) wrap.innerHTML = renderPricingTable();
}

function renderPricingTable(){
  const st = PRICING_STATE;
  const t = currentTenant();
  let totalRows = 0;
  let html = '';

  for(const [cat, tests] of Object.entries(APP_STATE.testCatalog)){
    if(st.categoryFilter !== 'all' && st.categoryFilter !== cat) continue;
    let visible = tests;
    if(st.search) visible = visible.filter(x => x.name.toLowerCase().includes(st.search) || x.code.toLowerCase().includes(st.search));
    if(st.showOverridesOnly) visible = visible.filter(x => hasPriceOverride(x.code));
    if(visible.length === 0) continue;
    totalRows += visible.length;

    html += `
      <div class="card" style="margin-bottom:14px;padding:0;overflow:hidden">
        <div style="padding:12px 18px;background:var(--bg-soft);border-bottom:1px solid var(--line-soft);font-size:13px;font-weight:600;color:var(--ink);display:flex;justify-content:space-between;align-items:center">
          <span>${cat} <span class="muted-sm" style="font-weight:400;margin-left:4px">${visible.length} tests</span></span>
          <span class="muted-sm">${visible.filter(x=>hasPriceOverride(x.code)).length} custom</span>
        </div>
        <table class="table" style="font-size:12.5px;margin:0">
          <thead>
            <tr><th style="width:80px">Code</th><th>Test name</th><th style="width:100px">Specimen</th><th style="width:80px">TAT</th><th style="width:120px;text-align:right">Default (₦)</th><th style="width:170px;text-align:right">Your price (₦)</th><th style="width:60px"></th></tr>
          </thead>
          <tbody>
            ${visible.map(x=>{
              const eff = getPrice(x.code);
              const custom = hasPriceOverride(x.code);
              const delta = eff - x.price;
              return `<tr style="${custom?'background:#FAFBFD':''}">
                <td style="font-family:monospace;font-size:11.5px;color:var(--ink-soft)">${x.code}</td>
                <td><div style="font-weight:500">${x.name}</div>
                  ${x.sendOut?'<span class="rx-flag sendout" style="margin-top:3px;display:inline-block">Send-out</span>':''}
                  ${x.criticalCallback?'<span class="rx-flag critical" style="margin-top:3px;display:inline-block">Critical</span>':''}
                </td>
                <td class="muted-sm">${x.specimen}</td>
                <td class="muted-sm">${x.turnaround}</td>
                <td style="text-align:right;font-variant-numeric:tabular-nums;color:var(--ink-soft)">${x.price.toLocaleString()}</td>
                <td style="text-align:right">
                  <input type="number" min="0" step="100" value="${eff}" data-code="${x.code}" data-default="${x.price}"
                    style="width:130px;text-align:right;padding:5px 8px;border:1px solid ${custom?'#2F4A6D':'var(--line)'};border-radius:4px;font-variant-numeric:tabular-nums;font-weight:${custom?'600':'400'};color:var(--ink);background:white;font-family:inherit;font-size:12.5px"
                    onchange="onPriceChange(this)"
                    title="${custom?'Custom price · '+(delta>0?'+':'')+naira(delta)+' vs default':'Default catalogue price'}"
                    />
                </td>
                <td style="text-align:center">
                  ${custom ? `<button class="btn-sm" onclick="resetTestPrice('${x.code}')" title="Reset to default" style="background:#F8DADA;border-color:#D89999;color:#7A1414">↺</button>` : ''}
                </td>
              </tr>`;
            }).join('')}
          </tbody>
        </table>
      </div>
    `;
  }

  if(totalRows === 0){
    html = '<div class="card"><div style="padding:30px;text-align:center;color:var(--ink-soft);font-size:13px">No tests match your filters.</div></div>';
  }

  return html;
}

function onPriceChange(input){
  const code = input.dataset.code;
  const defaultPrice = parseInt(input.dataset.default);
  const newVal = parseInt(input.value);
  if(isNaN(newVal) || newVal < 0){
    input.value = getPrice(code);
    return;
  }
  if(newVal === defaultPrice){
    // Resetting to default — clear the override
    setTenantPrice(code, null);
  } else {
    setTenantPrice(code, newVal);
  }
  renderPricing(document.getElementById('content'));
}

function resetTestPrice(code){
  setTenantPrice(code, null);
  renderPricing(document.getElementById('content'));
}

function openResetAllPrices(){
  document.getElementById('modal-root').innerHTML = `
    <div class="modal-overlay" onclick="if(event.target===this)closeModal()">
      <div class="modal" style="max-width:440px">
        <div class="modal-header">
          <div class="modal-title">Reset all custom prices?</div>
          <button class="modal-close" onclick="closeModal()">×</button>
        </div>
        <div class="modal-body">
          <div class="alert-banner warn"><span class="icon">⚠</span><div>This will remove every custom price you have set and revert to the platform catalogue defaults.</div></div>
          <div class="muted-sm">New test requests created after this change will use the default prices. Existing invoices are not affected.</div>
        </div>
        <div class="modal-footer">
          <button class="btn" onclick="closeModal()">Cancel</button>
          <button class="btn primary" onclick="confirmResetAll()" style="background:#9A1F1F;border-color:#7A1414">Reset all prices</button>
        </div>
      </div>
    </div>
  `;
  _modalA11y();
}

function confirmResetAll(){
  const tid = S().activeTenantId;
  if(APP_STATE.tenantPricing) APP_STATE.tenantPricing[tid] = {};
  closeModal();
  renderPricing(document.getElementById('content'));
}

function openBulkMarkup(){
  document.getElementById('modal-root').innerHTML = `
    <div class="modal-overlay" onclick="if(event.target===this)closeModal()">
      <div class="modal" style="max-width:520px">
        <div class="modal-header">
          <div>
            <div class="modal-title">Bulk markup</div>
            <div class="muted-sm">Apply a percentage adjustment across categories.</div>
          </div>
          <button class="modal-close" onclick="closeModal()">×</button>
        </div>
        <div class="modal-body">
          <div class="field">
            <label class="label">Scope</label>
            <select class="input" id="bm-scope">
              <option value="all">All tests in catalogue</option>
              ${Object.keys(APP_STATE.testCatalog).map(c=>`<option value="${c}">${c} only</option>`).join('')}
            </select>
          </div>
          <div class="field" style="margin-top:12px">
            <label class="label">Adjustment</label>
            <div style="display:flex;gap:8px;align-items:center">
              <select class="input" id="bm-op" style="width:140px">
                <option value="increase">Increase by</option>
                <option value="decrease">Decrease by</option>
              </select>
              <input type="number" id="bm-pct" min="0" max="500" step="1" value="10" class="input" style="width:100px"/>
              <span style="font-size:13px;color:var(--ink-soft)">%</span>
            </div>
          </div>
          <div class="field" style="margin-top:12px">
            <label class="label">Rounding</label>
            <select class="input" id="bm-round">
              <option value="100">Nearest ₦100</option>
              <option value="500" selected>Nearest ₦500</option>
              <option value="1000">Nearest ₦1,000</option>
              <option value="1">No rounding</option>
            </select>
          </div>
          <div class="alert-banner info" style="margin-top:14px"><span class="icon">💡</span><div>Markup is applied to the <b>catalogue default</b> for each test, not to your existing custom prices. Tests you have not customised will get a new custom price after this.</div></div>
        </div>
        <div class="modal-footer">
          <button class="btn" onclick="closeModal()">Cancel</button>
          <button class="btn primary" onclick="applyBulkMarkup()">Apply markup</button>
        </div>
      </div>
    </div>
  `;
  _modalA11y();
}

function applyBulkMarkup(){
  const scope = document.getElementById('bm-scope').value;
  const op = document.getElementById('bm-op').value;
  const pct = parseFloat(document.getElementById('bm-pct').value) || 0;
  const round = parseInt(document.getElementById('bm-round').value) || 1;
  const factor = op === 'increase' ? (1 + pct/100) : (1 - pct/100);

  let touched = 0;
  for(const [cat, tests] of Object.entries(APP_STATE.testCatalog)){
    if(scope !== 'all' && scope !== cat) continue;
    for(const x of tests){
      let newPrice = x.price * factor;
      newPrice = Math.max(0, Math.round(newPrice / round) * round);
      setTenantPrice(x.code, newPrice);
      touched++;
    }
  }
  closeModal();
  renderPricing(document.getElementById('content'));
  toast(`Applied ${op==='increase'?'+':'-'}${pct}% to ${touched} test${touched===1?'':'s'}, rounded to nearest ₦${round.toLocaleString()}.`, {type:'success', title:'Prices updated', duration:4500});
}


