function submitImagingOrder(key){
  const cfg = IMG_MODALITY_VIEWS[key];
  if(!requireLicensed('create an imaging order')) return;
  if(pcRequire('img-patient','patient')) return;
  const patientId = pcPatient('img-patient')?.id;
  const patient = (APP_STATE.patients||[]).find(p=>p.id===patientId);
  if(!patient){ toast('Select a patient', {type:'error', title:'Required'}); return; }
  const study    = $v('img-study')    || cfg.studies[0];
  const priority = $v('img-priority') || 'Routine';
  const preferredDate = $v('img-pref-date') || null;
  const preferredTime = $v('img-pref-time') || null;
  const orders = APP_STATE.imagingOrders || (APP_STATE.imagingOrders = []);
  const n = orders.length + 4423;
  const id = `IMG-2026-${String(n).padStart(5,'0')}`;
  const order = {
    id, patient:patient.name, patientId:patient.id, study,
    code:'IMG-NEW', modality:cfg.modalities[0],
    status: priority==='Critical'?'scheduled':'awaiting_payment',
    priority, requestedBy:S().userName||'Clinician',
    preferredDate, preferredTime,
    requestedAt:new Date().toISOString().slice(0,16).replace('T',' '),
    scheduledAt:null, acquiredAt:null, radiologist:null, reportedAt:null,
    amount:0, paid:'unpaid', clinical:$v('img-clinical')||'',
    criticalCallback: priority==='Critical'
  };
  orders.unshift(order);
  OfflineCore.record('imaging.order', {id, modality:order.modality}, `${id} ${cfg.title} order — ${study}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`${cfg.title} order created — ${study}.`, {type:'success', title:id, duration:4500});
  if(IMG_MODALITY_VIEWS[APP_STATE.currentRoute]) navigate(APP_STATE.currentRoute);
}

