              <td><div style="display:flex;align-items:center;gap:8px"><div style="flex:1;height:4px;background:#E2EAF7;border-radius:2px;min-width:60px;max-width:80px"><div style="width:${pctDone}%;height:100%;background:${pctDone===100?'#1B6B3A':'#2F4A6D'};border-radius:2px"></div></div><span class="muted-sm" style="white-space:nowrap">${o.completedItems}/${o.totalItems}</span></div></td>
