/* ==========================================================
   MODAL FOCUS TRAP — keeps keyboard focus inside open modals.
   Called automatically by openModal() / openAppointment() etc.
   ========================================================== */
function trapFocusInModal(){
  const modal = document.querySelector('#modal-root [role="dialog"]');
  if(!modal) return;
  const FOCUSABLE = 'a[href],button:not([disabled]),input:not([disabled]),select:not([disabled]),textarea:not([disabled]),[tabindex]:not([tabindex="-1"])';
  const elements = () => [...modal.querySelectorAll(FOCUSABLE)].filter(el => {
    return !!(el.offsetWidth || el.offsetHeight || el.getClientRects().length);
  });
  // Focus the first element
  const first = elements()[0];
  if(first) setTimeout(() => first.focus(), 50);

  const handler = (e) => {
    if(e.key !== 'Tab') return;
    const els = elements();
    if(!els.length) return;
    const firstEl = els[0], lastEl = els[els.length - 1];
    if(e.shiftKey){
      if(document.activeElement === firstEl){ e.preventDefault(); lastEl.focus(); }
    } else {
      if(document.activeElement === lastEl){ e.preventDefault(); firstEl.focus(); }
    }
  };
  modal.addEventListener('keydown', handler);
  modal._trapHandler = handler;
}

function releaseFocusTrap(){
  const modal = document.querySelector('#modal-root [role="dialog"]');
  if(modal && modal._trapHandler) modal.removeEventListener('keydown', modal._trapHandler);
}

function closeModal(){
  releaseFocusTrap();
  document.getElementById('modal-root').innerHTML = '';
  window.MODAL_CTX = null;
  // Return focus to the element that opened the modal (if tracked)
  if(window._modalOpener && window._modalOpener.focus) window._modalOpener.focus();
  window._modalOpener = null;
}

/* Helper: after injecting any modal HTML, upgrade it with ARIA and focus trap */
function _modalA11y(titleSelector){
  const mr = document.getElementById('modal-root');
  if(!mr) return;
  // Find the inner modal div (not the backdrop)
  const modal = mr.querySelector('.modal,.new-request-modal');
  if(!modal) return;
  if(!modal.getAttribute('role')){
    modal.setAttribute('role','dialog');
    modal.setAttribute('aria-modal','true');
  }
  if(!modal.getAttribute('aria-labelledby')){
    // Try to find a title element and give it an ID
    const titleEl = modal.querySelector('.modal-title,h1,h2,[id$="-title"]');
    if(titleEl){
      if(!titleEl.id) titleEl.id = 'modal-title-' + Date.now();
      modal.setAttribute('aria-labelledby', titleEl.id);
    }
  }
  trapFocusInModal();
}

