function doSwitchToReal(){
  const v = $v('dm-confirm');
  if(v !== 'SWITCH'){
    toast('Type SWITCH exactly to confirm', {type:'error', title:'Confirmation required'});
    return;
  }
  DataMode.clearDemoData();
  closeModal();
  toast('Real data mode active. Demo records cleared. You can restore them anytime from Settings.', {type:'success', title:'Switched to real data', duration:6000});
  if(APP_STATE.currentRoute === 'settings'){ navigate('settings'); } else { navigate('dashboard'); }
  if(typeof renderDataModeBanner === 'function') renderDataModeBanner();
}

