// Show a thin amber banner across the top of every page when in demo mode.
// Hidden once the user switches to real data.
function renderDataModeBanner(){
  let banner = document.getElementById('data-mode-banner');
  if(DataMode.isDemo){
    if(!banner){
      banner = document.createElement('div');
      banner.id = 'data-mode-banner';
      banner.className = 'data-mode-banner';
      // Insert at the top of <body> so it's above the app shell
      document.body.insertBefore(banner, document.body.firstChild);
    }
    banner.innerHTML = `<span class="dmb-dot"></span><b>Demo data</b> — seeded records for evaluation. <a onclick="navigate('settings')">Switch to real data</a> in Settings when ready.`;
    banner.style.display = '';
  } else if(banner){
    banner.style.display = 'none';
  }
}

/* ==========================================================
   FORM HELPERS & STATE-MUTATING SUBMIT HANDLERS
   ========================================================== */
function $v(id){ const el = document.getElementById(id); return el ? el.value.trim() : ''; }

// HTML-escape a string for safe insertion via template literals.
// Use anywhere user-controlled text is interpolated into innerHTML.
function esc(s){
  return String(s == null ? '' : s)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#39;');
}

// Render a friendly empty-state block. Use when a list/table has no rows.
//   opts.icon  — emoji or single char (default '📭')
//   opts.title — main message
//   opts.msg   — secondary explainer
//   opts.cta   — { label, onclick } — optional call-to-action button
function emptyState(opts){
  opts = opts || {};
  const icon = opts.icon || '📭';
  const title = esc(opts.title || 'Nothing here yet');
  const msg = esc(opts.msg || '');
  const cta = opts.cta ? `<button class="btn primary" style="min-height:38px" onclick="${opts.cta.onclick}">${esc(opts.cta.label)}</button>` : '';
  return `<div class="empty-state">
    <div class="empty-state-icon">${icon}</div>
    <div class="empty-state-title">${title}</div>
    ${msg ? `<div class="empty-state-msg">${msg}</div>` : ''}
    ${cta}
  </div>`;
}

// Render a small inline indicator showing the offline-sync status of a record.
// Renders nothing if the record has been fully synced (the default expected state).
// Hover shows a tooltip with the status. Used in list views next to record IDs.
function syncDot(entityId){
  if(!entityId || typeof OfflineCore === 'undefined') return '';
  const status = OfflineCore.statusOf(entityId);
  if(!status || status === 'synced') return '';
  const cfg = {
    pending: {colour:'#1F4B86', label:'Pending sync', anim:false},
    queued:  {colour:'#C77B14', label:'Queued — offline', anim:false},
    syncing: {colour:'#1F4B86', label:'Syncing now…', anim:true},
    failed:  {colour:'#9A1F1F', label:'Sync failed — will retry', anim:false}
  }[status] || {colour:'#8DA1BD', label:status, anim:false};
  return `<span class="sync-dot" style="background:${cfg.colour};${cfg.anim?'animation:pulseDot 1s infinite':''}" title="${esc(cfg.label)}" aria-label="${esc(cfg.label)}"></span>`;
}

// Wrap a server-required action (e.g. release report, run a Paystack charge)
// with an offline check. If offline, show a clear warning and return false.
// Returns true if the action should proceed.
// Usage:
//   if(!requireOnline('release this report')) return;
function requireOnline(action){
  if(typeof OfflineCore === 'undefined' || OfflineCore.state.online) return true;
  if(typeof toast === 'function'){
    toast(`Can't ${action || 'do that'} while offline. Your changes are saved locally and will sync when you reconnect.`,
          {type:'warn', title:'Offline', duration:7000});
  }
  return false;
}

// Block a mutation if the licence isn't in 'valid' state. Returns true if
// the action should proceed.
//
// In 'grace' mode the device is read-only — existing in-flight work can be
// completed (form drafts already open, results already entered) but no NEW
// resources can be created. This matches what most SaaS apps do when a
// subscription lapses and keeps patient safety intact (existing data still
// readable).
//
// In 'lockout' the overlay covers the UI and submits shouldn't even get a
// chance to run, but this guard catches anything that slips through.
function requireLicensed(action){
  if(typeof LicenseCore === 'undefined') return true;
  const s = LicenseCore.state;
  // TESTING: only a hard lockout blocks mutations. 'grace' is allowed so the
  // read-only restriction never interrupts testing. For production, also block
  // on 'grace' (revert to: status === 'valid' || 'unknown').
  if(s.status !== 'lockout') return true;
  if(typeof toast === 'function'){
    toast(`Locked: this device's licence is not valid. Contact support.`, {type:'error', title:'Licence locked', duration:7000});
  }
  return false;
}

// Quote a cell for CSV output. Wraps in quotes if it contains , " or newline,
// and escapes embedded quotes by doubling them (RFC 4180).
function csvCell(v){
  if(v == null) return '';
  const s = String(v);
  if(/[,"\n\r]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
}

// Build a CSV string from an array of rows and a column definition.
// columns is an array of {key, header, fmt?} objects.
function buildCsv(rows, columns){
  const lines = [columns.map(c => csvCell(c.header || c.key)).join(',')];
  for(const r of rows){
    lines.push(columns.map(c => csvCell(c.fmt ? c.fmt(r) : r[c.key])).join(','));
  }
  return lines.join('\r\n');
}

// Trigger a browser download of arbitrary text content. Used for CSV exports.
// No server needed — Blob URLs work entirely client-side.
function downloadText(filename, content, mimeType){
  try {
    const blob = new Blob([content], {type: mimeType || 'text/plain;charset=utf-8'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    // Revoke after a tick so the download has time to start
    setTimeout(() => URL.revokeObjectURL(url), 1000);
    return true;
  } catch(e){
    console.warn('[downloadText] failed', e);
    if(typeof toast === 'function') toast('Download failed: '+ e.message, {type:'error'});
    return false;
  }
}

// Open the OS file picker programmatically. accept = MIME or extension filter
// (e.g. '.csv,text/csv' or 'image/*'). onFile is called with the File object.
function pickFile(accept, onFile){
  const input = document.createElement('input');
  input.type = 'file';
  if(accept) input.accept = accept;
  input.style.display = 'none';
  document.body.appendChild(input);
  input.addEventListener('change', (e) => {
    const file = e.target.files && e.target.files[0];
    document.body.removeChild(input);
    if(file && typeof onFile === 'function') onFile(file);
  });
  // Detect cancel (no change event fires) so we can clean up
  input.addEventListener('cancel', () => {
    try { document.body.removeChild(input); } catch(_){}
  });
  input.click();
}

// Read a file as text using FileReader. Returns a Promise.
function readFileAsText(file){
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => resolve(r.result);
    r.onerror = () => reject(r.error || new Error('Read failed'));
    r.readAsText(file);
  });
}

// Parse a CSV string into an array of row objects keyed by header.
// Handles quoted fields with embedded commas and doubled quotes (RFC 4180).
function parseCsv(text){
  if(!text || !text.trim()) return [];
  const rows = [];
  let row = [];
  let cur = '';
  let inQuotes = false;
  let i = 0;
  while(i < text.length){
    const c = text[i];
    if(inQuotes){
      if(c === '"'){
        if(text[i+1] === '"'){ cur += '"'; i += 2; continue; }
        inQuotes = false; i++; continue;
      }
      cur += c; i++; continue;
    }
    if(c === '"'){ inQuotes = true; i++; continue; }
    if(c === ','){ row.push(cur); cur = ''; i++; continue; }
    if(c === '\n' || c === '\r'){
      row.push(cur); cur = '';
      // Only push non-empty rows
      if(row.length > 1 || row[0] !== '') rows.push(row);
      row = [];
      // Skip the \n in \r\n pairs
      if(c === '\r' && text[i+1] === '\n') i++;
      i++;
      continue;
    }
    cur += c; i++;
  }
  // Trailing row
  if(cur !== '' || row.length){
    row.push(cur);
    if(row.length > 1 || row[0] !== '') rows.push(row);
  }
  if(rows.length === 0) return [];
  const headers = rows[0].map(h => h.trim());
  return rows.slice(1).map(r => {
    const obj = {};
    headers.forEach((h, idx) => { obj[h] = (r[idx] || '').trim(); });
    return obj;
  });
}

function $req(id, label){
  const v = $v(id);
  if(!v){
    const el = document.getElementById(id);
    if(el){
      el.style.borderColor = '#9A1F1F';
      el.style.background = '#FDF5F5';
      el.scrollIntoView({block:'center', behavior:'smooth'});
      el.focus();
    }
    toast(`${label} is required`, {type:'error', title:'Missing field'});
    return null;
  }
  return v;
}

