// Live-calculate age as the user sets the date of birth, and display it as
// "34 yrs", "8 mos", etc. in the disabled read-only age field.
function rpCalcAge(){
  const dob = document.getElementById('rp-dob');
  const age = document.getElementById('rp-age');
  if(!dob || !age) return;
  const val = dob.value;
  if(!val){ age.value = ''; return; }
  const now = new Date();
  const birth = new Date(val);
  if(isNaN(birth) || birth > now){ age.value = ''; return; }
  const diffMs = now - birth;
  const yrs = Math.floor(diffMs / 31557600000);
  if(yrs >= 1){
    age.value = yrs + (yrs === 1 ? ' yr' : ' yrs');
  } else {
    const mos = Math.floor(diffMs / 2629800000);
    age.value = mos <= 0 ? '< 1 mo' : mos + (mos === 1 ? ' mo' : ' mos');
  }
}

// Cascade: when the state changes, repopulate the LGA dropdown with that
// state's LGAs (from NIGERIA_GEO) and reset the selection.
function rpUpdateLgas(){
  const stateSel = document.getElementById('rp-state');
  const lgaSel   = document.getElementById('rp-lga');
  if(!stateSel || !lgaSel) return;
  const stateVal = stateSel.value;
  const entry = (window.NIGERIA_GEO || []).find(s => s.state === stateVal);
  const lgas = entry ? entry.lgas : [];
  lgaSel.innerHTML = lgas.length
    ? '<option value="">— Select LGA —</option>' + lgas.map(l => `<option value="${esc(l)}">${esc(l)}</option>`).join('')
    : '<option value="">— Select state first —</option>';
}

