window.PENDING_UPLOAD = window.PENDING_UPLOAD || null;


// and creates a pending invite record per address. In production this would
// hit your auth provider (Auth0 / Clerk / etc.) to issue one-time links.
function submitInviteStaff(){
  if(!requireLicensed('invite staff')) return;
  const rawEmails = $v('inv-emails') || '';
  const role = $v('inv-role') || 'Med Lab Scientist';
  const branch = $v('inv-branch') || 'Ikeja Main';
  const emails = rawEmails.split(/[\n,;]/).map(s => s.trim()).filter(Boolean);
  if(emails.length === 0){
    const el = document.getElementById('inv-emails');
    if(el){ el.style.borderColor = '#9A1F1F'; el.style.background = '#FDF5F5'; el.focus(); }
    if(typeof toast === 'function') toast('Add at least one email address.', {type:'error', title:'No recipients'});
    return;
  }
  // Validate
  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const invalid = emails.filter(e => !emailRe.test(e));
  if(invalid.length){
    if(typeof toast === 'function') toast('Invalid email(s): ' + invalid.slice(0,3).join(', ') + (invalid.length > 3 ? '…' : ''), {type:'error', title:'Bad email format'});
    return;
  }
  // Record each as an outbox event (in production: POST /invites)
  for(const email of emails){
    if(typeof OfflineCore !== 'undefined'){
      OfflineCore.record('staff.invite', {email, role, branch}, 'Invite ' + email + ' as ' + role);
    }
  }
  closeModal();
  if(typeof toast === 'function'){
    toast(`${emails.length} invite${emails.length===1?'':'s'} sent. Invitees have 14 days to set up their account.`,
          {type:'success', title:'Invites queued'});
  }
}

// Add a staff member to the directory. Persists locally and records the
// mutation in the offline outbox so it syncs.
function submitAddStaff(){
  if(!requireLicensed('add staff')) return;
  if(enforceStaffLimit()) return; // plan hard limit (also shows warning at 80%)
  const name = $req('st-name', 'Full name'); if(!name) return;
  const email = $req('st-email', 'Email'); if(!email) return;
  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if(!emailRe.test(email)){
    const el = document.getElementById('st-email');
    if(el){ el.style.borderColor = '#9A1F1F'; el.style.background = '#FDF5F5'; el.focus(); }
    if(typeof toast === 'function') toast('That email address doesn\'t look right.', {type:'error', title:'Bad email format'});
    return;
  }
  const role = $v('st-role') || 'Med Lab Scientist';
  const branch = $v('st-branch') || 'Ikeja Main';
  const phone = $v('st-phone') || '';
  const licence = $v('st-licence') || '';
  const sendInvite = !!(document.getElementById('st-invite') && document.getElementById('st-invite').classList && document.getElementById('st-invite').classList.contains('checked')) || (document.getElementById('st-invite') && document.getElementById('st-invite').checked);
  const newStaff = {
    id: 'usr_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2,6),
    name, email, role, branch, phone, licence,
    active: true,
    invited: sendInvite,
    createdAt: new Date().toISOString().slice(0,10)
  };
  APP_STATE.staff = APP_STATE.staff || [];
  APP_STATE.staff.unshift(newStaff);
  if(typeof OfflineCore !== 'undefined'){
    OfflineCore.record('staff.add', {id:newStaff.id, name, email, role}, 'Added ' + name + ' as ' + role);
    OfflineCore.schedulePersist();
    if(sendInvite){
      OfflineCore.record('staff.invite', {email, role, branch}, 'Invite for ' + email);
    }
  }
  closeModal();
  if(APP_STATE.currentRoute === 'staff' && typeof rerenderCurrentRoute === 'function') rerenderCurrentRoute();
  if(typeof toast === 'function'){
    const inviteNote = sendInvite ? ' Invite email sent.' : ' User created in deactivated state.';
    toast(`${name} added as ${role}.${inviteNote}`, {type:'success', title:'Staff added'});
  }
}

/* ==========================================================
   TOAST NOTIFICATIONS (replace alert())
   ========================================================== */
let TOAST_ID = 0;
function toast(message, opts){
  opts = opts || {};
  const type = opts.type || 'info';
  const title = opts.title || ({success:'Success', warn:'Warning', error:'Error', info:'Notice'})[type];
  const duration = opts.duration === 0 ? 0 : (opts.duration || 4000);
  const icon = opts.icon || ({success:'✓', warn:'⚠', error:'⛔', info:'ℹ'})[type];
  const id = 'toast-'+(++TOAST_ID);
  const el = document.createElement('div');
  el.className = 'toast '+type;
  el.id = id;
  el.innerHTML = `
    <span class="toast-icon">${icon}</span>
    <div class="toast-body">
      <div class="toast-title">${title}</div>
      <div class="toast-msg">${message}</div>
    </div>
    <button class="toast-close" onclick="dismissToast('${id}')">×</button>
  `;
  _modalA11y();
  document.getElementById('toast-root').appendChild(el);
  if(duration > 0){
    setTimeout(()=>dismissToast(id), duration);
  }
  return id;
}
function dismissToast(id){
  const el = document.getElementById(id);
  if(!el) return;
  el.classList.add('closing');
  setTimeout(()=>el.remove(), 180);
}

/* ==========================================================
   GLOBAL KEYBOARD SHORTCUTS
   ========================================================== */
document.addEventListener('keydown', function(e){
  // Escape — close modal, command palette, tenant menu, sidebar drawer
  if(e.key === 'Escape'){
    const modal = document.getElementById('modal-root');
    if(modal && modal.innerHTML){ closeModal(); e.preventDefault(); return; }
    const cmdk = document.getElementById('cmdk-root');
    if(cmdk && cmdk.innerHTML){ cmdk.innerHTML=''; e.preventDefault(); return; }
    const tm = document.getElementById('tenant-menu');
    if(tm){ tm.remove(); e.preventDefault(); return; }
    const sb = document.querySelector('.sidebar.open');
    if(sb){ closeSidebar(); e.preventDefault(); return; }
  }
  // Ctrl/Cmd+K — open command palette
  if((e.ctrlKey || e.metaKey) && e.key === 'k'){
    e.preventDefault();
    openCommandPalette();
  }
  // / — focus topbar search (if no modal open and not typing in a field)
  if(e.key === '/' && !document.getElementById('modal-root').innerHTML){
    const tag = e.target.tagName;
    if(tag !== 'INPUT' && tag !== 'TEXTAREA' && tag !== 'SELECT'){
      e.preventDefault();
      openCommandPalette();
    }
  }
});

/* ==========================================================
   COMMAND PALETTE (Ctrl+K)
   ========================================================== */
window.CMDK_STATE = {query:'', activeIndex:0};

function openCommandPalette(){
  let root = document.getElementById('cmdk-root');
  if(!root){
    root = document.createElement('div');
    root.id = 'cmdk-root';
    document.body.appendChild(root);
  }
  CMDK_STATE.query = '';
  CMDK_STATE.activeIndex = 0;
  renderCommandPalette();
  setTimeout(()=>{
    const i = document.getElementById('cmdk-input');
    if(i) i.focus();
  }, 30);
}

function commandPaletteItems(){
  const q = CMDK_STATE.query.toLowerCase();
  const items = [];

  // Routes
  for(const [k, r] of Object.entries(ROUTES)){
    if(r.scope === S().mode){
      items.push({kind:'page', icon:'→', title:r.title, meta:r.sub, action:()=>{closeCommandPalette();navigate(k);}});
    }
  }
  // Patients
  for(const p of (APP_STATE.patients||[])){
    items.push({kind:'patient', icon:'👤', title:p.name, meta:p.id+' · '+p.phone, action:()=>{closeCommandPalette();openPatientDetail(p.id);}});
  }
  // Test requests
  for(const r of (APP_STATE.requests||[])){
    items.push({kind:'request', icon:'🧪', title:r.id, meta:r.patient+' · '+r.tests.slice(0,2).join(', '), action:()=>{closeCommandPalette();navigate('requests');}});
  }
  // Imaging orders
  for(const o of (APP_STATE.imagingOrders||[])){
    items.push({kind:'imaging', icon:'📷', title:o.id, meta:o.patient+' · '+o.study, action:()=>{closeCommandPalette();navigate('imaging');}});
  }

  // Lab test catalogue (only show when there's a query — too many otherwise)
  if(q){
    for(const [cat, tests] of Object.entries(APP_STATE.testCatalog || {})){
      for(const t of tests){
        items.push({kind:'lab-test', icon:'🧫', title:t.name, meta:`${t.code} · ${cat} · ${naira(getPrice(t.code))} · TAT ${t.turnaround}`, action:()=>{closeCommandPalette();addToNewRequestAndOpen(t.code);}});
      }
    }
    // Imaging catalogue
    for(const [cat, studies] of Object.entries(APP_STATE.imagingCatalog || {})){
      for(const s of studies){
        items.push({kind:'imaging-study', icon:'📷', title:s.name, meta:`${s.code} · ${cat} · ${naira(s.price)} · ${s.duration}`, action:()=>{closeCommandPalette();openModal('new-imaging-order');}});
      }
    }
    // DNA catalogue
    for(const [cat, tests] of Object.entries(APP_STATE.dnaCatalog || {})){
      for(const t of tests){
        items.push({kind:'dna-test', icon:'🧬', title:t.name, meta:`${t.code} · ${cat} · ${naira(t.price)} · ${t.duration}`, action:()=>{closeCommandPalette();openModal('new-dna-order');}});
      }
    }
    // Health Packages catalogue
    for(const [cat, pkgs] of Object.entries(APP_STATE.packagesCatalog || {})){
      for(const p of pkgs){
        items.push({kind:'package', icon:'📦', title:p.name, meta:`${p.code} · ${cat} · ${naira(p.price)} · ${p.duration} · ${p.includes ? p.includes.length+' items' : ''}`, action:()=>{closeCommandPalette();openModal('new-package-order');}});
      }
    }
  }

  // Actions
  const actions = [
    {kind:'action', icon:'+', title:'New test request',     meta:'Create a lab test order',        action:()=>{closeCommandPalette();openModal('new-request');}},
    {kind:'action', icon:'+', title:'Register patient',      meta:'Add a new patient record',       action:()=>{closeCommandPalette();openModal('register-patient');}},
    {kind:'action', icon:'+', title:'New invoice',           meta:'Bill a patient',                  action:()=>{closeCommandPalette();openModal('new-invoice');}},
    {kind:'action', icon:'+', title:'New imaging order',     meta:'Schedule imaging or diagnostic', action:()=>{closeCommandPalette();openModal('new-imaging-order');}},
    {kind:'action', icon:'+', title:'New DNA order',         meta:'Genetic / paternity / panel',     action:()=>{closeCommandPalette();openModal('new-dna-order');}},
    {kind:'action', icon:'+', title:'New health package',    meta:'Pre-employment / travel / wellness', action:()=>{closeCommandPalette();openModal('new-package-order');}},
    {kind:'action', icon:'+', title:'Log new sample',        meta:'Record a collected specimen',    action:()=>{closeCommandPalette();openModal('log-sample');}},
    {kind:'action', icon:'+', title:'Capture vitals',        meta:'Record patient vital signs',     action:()=>{closeCommandPalette();openModalWith('capture-vitals',{patientId:null});}},
    {kind:'action', icon:'+', title:'Start dialysis session',meta:'Begin renal session',            action:()=>{closeCommandPalette();openModal('dialysis-session');}},
    {kind:'action', icon:'+', title:'Add inventory item',    meta:'Register a new SKU',             action:()=>{closeCommandPalette();openModal('add-inventory');}},
    {kind:'action', icon:'⌨', title:'Switch tenant',         meta:'Open tenant switcher',           action:()=>{closeCommandPalette();openTenantSwitcher();}}
  ];
  items.push(...actions);

  if(!q) return items.slice(0,20);
  return items.filter(it => (it.title+' '+it.meta+' '+it.kind).toLowerCase().includes(q)).slice(0,50);
}

// Add a test by code to a new request and open the modal
function addToNewRequestAndOpen(code){
  if(!window.RX_STATE) window.RX_STATE = {selected:new Set(), search:'', priority:'Routine', expanded:new Set()};
  RX_STATE.selected.add(code);
  // Expand the category that contains this test so the user sees it ticked
  for(const [cat, tests] of Object.entries(APP_STATE.testCatalog || {})){
    if(tests.some(t=>t.code===code)){ RX_STATE.expanded.add(cat); break; }
  }
  openModal('new-request');
}

/* ==========================================================
   DASHBOARD CATALOGUE SEARCH
   ========================================================== */
function searchCatalogue(query){
  const q = (query||'').toLowerCase().trim();
  const root = document.getElementById('csh-results');
  if(!root) return;

  if(!q){
    root.style.display = 'none';
    root.innerHTML = '';
    return;
  }

  // Common-language aliases — map what people search for to the formal test code.
  // E.g. someone types "sickle cell" expecting to find haemoglobin electrophoresis.
  const ALIASES = {
    'sickle cell': ['HBE'],
    'sickle':      ['HBE'],
    'genotype':    ['HBE'],
    'sugar':       ['FBS','RBS','HBA','OGTT'],
    'diabetes':    ['FBS','HBA','OGTT'],
    'hba1c':       ['HBA'],
    'cholesterol': ['LIPP'],
    'lipids':      ['LIPP'],
    'kidney':      ['KFT','URI','CREAT','URECREAT'],
    'liver':       ['LFT','ALP','BIL'],
    'thyroid':     ['TSH','FT3','FT4'],
    'pregnancy':   ['HCG','BHCG'],
    'malaria':     ['MP','MPS','MRDT'],
    'hiv':         ['HIV','HIVCD4','VL'],
    'hepatitis':   ['HBSAG','HCV','HBVDNA'],
    'covid':       ['COVPCR','COVRAT','COVAB'],
    'allergy':     ['IGE','PHADIA'],
    'pap':         ['PAPS','LBC'],
    'urinalysis':  ['URINAL','URI']
  };

  function score(haystack, q){
    const h = haystack.toLowerCase();
    if(h === q) return 100;
    if(h.startsWith(q)) return 80;
    if(h.includes(q)) return 50;
    return 0;
  }

  function aliasMatch(code, q){
    // If the query has an alias mapping that includes this code, give it a moderate boost
    for(const [alias, codes] of Object.entries(ALIASES)){
      if(q.includes(alias) && codes.includes(code)) return 60;
    }
    return 0;
  }

  const matches = {lab:[], img:[], dna:[], pkg:[]};

  for(const [cat, tests] of Object.entries(APP_STATE.testCatalog||{})){
    for(const t of tests){
      const s = Math.max(
        score(t.code, q)*1.2,
        score(t.name, q),
        score(cat, q)*0.7,
        aliasMatch(t.code, q)
      );
      if(s > 0) matches.lab.push({...t, category:cat, score:s, kind:'lab'});
    }
  }
  for(const [cat, studies] of Object.entries(APP_STATE.imagingCatalog||{})){
    for(const t of studies){
      const s = Math.max(score(t.code, q)*1.2, score(t.name, q), score(cat, q)*0.7);
      if(s > 0) matches.img.push({...t, category:cat, score:s, kind:'img'});
    }
  }
  for(const [cat, tests] of Object.entries(APP_STATE.dnaCatalog||{})){
    for(const t of tests){
      const s = Math.max(score(t.code, q)*1.2, score(t.name, q), score(cat, q)*0.7, score(t.description||'', q)*0.4);
      if(s > 0) matches.dna.push({...t, category:cat, score:s, kind:'dna'});
    }
  }
  for(const [cat, pkgs] of Object.entries(APP_STATE.packagesCatalog||{})){
    for(const t of pkgs){
      const s = Math.max(
        score(t.code, q)*1.2,
        score(t.name, q),
        score(cat, q)*0.7,
        score(t.target||'', q)*0.5,
        score((t.includes||[]).join(' '), q)*0.4
      );
      if(s > 0) matches.pkg.push({...t, category:cat, score:s, kind:'pkg'});
    }
  }

  // Sort each bucket by score
  for(const k of Object.keys(matches)){
    matches[k].sort((a,b)=>b.score-a.score);
  }

  const totalCount = matches.lab.length + matches.img.length + matches.dna.length + matches.pkg.length;

  if(totalCount === 0){
    root.style.display = 'block';
    root.innerHTML = `<div class="csh-empty">No tests, studies, packages or DNA panels match <span class="csh-empty-q">"${escapeHtml(q)}"</span><br><span class="muted-sm">Try a different keyword, the test code, or a category name.</span></div>`;
    return;
  }

  // Limit each bucket to 10 results to keep the panel scannable
  const cap = 10;
  let body = '';

  if(matches.lab.length){
    body += `<div class="csh-result-header"><span>Lab tests</span><span>${matches.lab.length} match${matches.lab.length===1?'':'es'}${matches.lab.length>cap?` (showing ${cap})`:''}</span></div>`;
    body += matches.lab.slice(0,cap).map(t=>renderSearchResult(t,'lab')).join('');
  }
  if(matches.img.length){
    body += `<div class="csh-result-header"><span>Imaging &amp; diagnostics</span><span>${matches.img.length} match${matches.img.length===1?'':'es'}${matches.img.length>cap?` (showing ${cap})`:''}</span></div>`;
    body += matches.img.slice(0,cap).map(t=>renderSearchResult(t,'img')).join('');
  }
  if(matches.pkg.length){
    body += `<div class="csh-result-header"><span>Health packages</span><span>${matches.pkg.length} match${matches.pkg.length===1?'':'es'}${matches.pkg.length>cap?` (showing ${cap})`:''}</span></div>`;
    body += matches.pkg.slice(0,cap).map(t=>renderSearchResult(t,'pkg')).join('');
  }
  if(matches.dna.length){
    body += `<div class="csh-result-header"><span>DNA &amp; Genetics</span><span>${matches.dna.length} match${matches.dna.length===1?'':'es'}${matches.dna.length>cap?` (showing ${cap})`:''}</span></div>`;
    body += matches.dna.slice(0,cap).map(t=>renderSearchResult(t,'dna')).join('');
  }

  root.style.display = 'block';
  root.innerHTML = body;
}

function renderSearchResult(t, kind){
  let icon, addLabel, addAction, meta;
  if(kind === 'lab'){
    icon = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 2v6.5L3 17a4 4 0 0 0 3.5 6h11a4 4 0 0 0 3.5-6L15 8.5V2"/><line x1="9" y1="2" x2="15" y2="2"/></svg>';
    addLabel = '+ Add to request';
    addAction = `addToNewRequestAndOpen('${t.code}')`;
    meta = `<b>${t.code}</b> · ${t.category} · TAT ${t.turnaround} · ${t.specimen}${t.fasting?' · fasting required':''}${t.criticalCallback?' · <span style="color:#9A1F1F">critical-callback</span>':''}`;
  } else if(kind === 'img'){
    icon = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="8"/><circle cx="12" cy="12" r="3"/></svg>';
    addLabel = '+ New imaging order';
    addAction = `openModal('new-imaging-order')`;
    meta = `<b>${t.code}</b> · ${t.category} · ${t.duration} · prep: ${t.prep}`;
  } else if(kind === 'pkg'){
    icon = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="8" width="18" height="13" rx="2"/><path d="M8 8V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v4"/></svg>';
    addLabel = '+ Book package';
    addAction = `openModal('new-package-order')`;
    meta = `<b>${t.code}</b> · ${t.category} · ${t.duration} · ${t.includes.length} items${t.chainOfCustody?' · CoC':''}${t.confidential?' · confidential':''}`;
  } else {
    icon = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 4c4 0 4 16 8 16M12 4c4 0 4 16 8 16M4 8h16M4 12h16M4 16h16"/></svg>';
    addLabel = '+ New DNA order';
    addAction = `openModal('new-dna-order')`;
    const grade = t.legalGrade ? ' · <span style="color:#9A1F1F;font-weight:600">Legal grade</span>' : t.chainOfCustody ? ' · <span style="color:#7A5410;font-weight:600">Chain-of-custody</span>' : '';
    meta = `<b>${t.code}</b> · ${t.category} · ${t.duration}${grade}`;
  }
  const price = (kind === 'lab') ? getPrice(t.code) : t.price;
  const unit = kind==='lab'?'lab fee':kind==='img'?'study':kind==='pkg'?'bundle':'panel';
  return `<div class="csh-result-item" onclick="${addAction}">
    <div class="csh-result-icon ${kind}">${icon}</div>
    <div class="csh-result-info">
      <div class="csh-result-title">${escapeHtml(t.name)}</div>
      <div class="csh-result-meta">${meta}</div>
    </div>
    <div class="csh-result-price">
      <div class="amt">${naira(price)}</div>
      <div class="unit">${unit}</div>
    </div>
    <div class="csh-result-actions">
      <button class="csh-add-btn" onclick="event.stopPropagation();${addAction}">${addLabel}</button>
    </div>
  </div>`;
}

function closeCatalogueSearch(){
  const root = document.getElementById('csh-results');
  if(root){ root.style.display = 'none'; root.innerHTML = ''; }
}

function escapeHtml(s){
  return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
}

function renderCommandPalette(){
  // Build the results + footer HTML for the current query/selection.
  // Split out so typing updates ONLY the results — never the input — which
  // keeps the cursor in place and avoids the palette flicker.
  function buildCmdkBody(){
    const items = commandPaletteItems();
    const idx = Math.min(CMDK_STATE.activeIndex, Math.max(0, items.length-1));
    CMDK_STATE.activeIndex = idx;
    const groups = {};
    items.forEach((it,i)=>{ if(!groups[it.kind]) groups[it.kind] = []; groups[it.kind].push({it, i}); });
    const labels = {page:'Pages', patient:'Patients', request:'Test requests', imaging:'Imaging orders', 'lab-test':'Lab tests', 'imaging-study':'Imaging studies', 'dna-test':'DNA &amp; Genetics', 'package':'Health packages', action:'Actions'};
    let body = '';
    for(const [kind, list] of Object.entries(groups)){
      body += `<div class="cmdk-section">${labels[kind]||kind}</div>`;
      for(const {it, i} of list){
        body += `<div class="cmdk-item ${i===idx?'active':''}" data-cmdk-index="${i}" onmouseenter="cmdkSetActive(${i})" onclick="commandPaletteItems()[${i}].action()">
          <div class="cmdk-item-icon">${it.icon}</div>
          <div class="cmdk-item-info">
            <div class="cmdk-item-title">${it.title}</div>
            <div class="cmdk-item-meta">${it.meta||''}</div>
          </div>
        </div>`;
      }
    }
    if(items.length===0){
      body = '<div style="padding:30px;text-align:center;color:var(--ink-soft);font-size:13px">No matches for "<b>'+esc(CMDK_STATE.query)+'</b>"</div>';
    }
    return {body, count: items.length};
  }

  const root = document.getElementById('cmdk-root');
  const existingInput = document.getElementById('cmdk-input');
  const { body, count } = buildCmdkBody();

  // If the palette is already open, update ONLY the results + footer count so
  // the input element (and its cursor) is left untouched.
  if(existingInput){
    const results = root.querySelector('.cmdk-results');
    if(results) results.innerHTML = body;
    const footerCount = root.querySelector('.cmdk-footer-count');
    if(footerCount) footerCount.textContent = `${count} result${count===1?'':'s'}`;
    return;
  }

  // First open: build the full shell (input created exactly once).
  root.innerHTML = `
    <div class="cmdk-backdrop" onclick="if(event.target===this)closeCommandPalette()">
      <div class="cmdk">
        <input class="cmdk-input" id="cmdk-input" placeholder="Search patients, requests, pages, actions…" value="${esc(CMDK_STATE.query)}"
               oninput="cmdkOnInput(this.value)"
               onkeydown="cmdkKeyHandler(event)">
        <div class="cmdk-results">${body}</div>
        <div class="cmdk-footer">
          <span><span class="cmdk-item-kbd">↑↓</span> navigate &nbsp; <span class="cmdk-item-kbd">⏎</span> select &nbsp; <span class="cmdk-item-kbd">esc</span> close</span>
          <span class="cmdk-footer-count">${count} result${count===1?'':'s'}</span>
        </div>
      </div>
    </div>
  `;
}

// Typing in the palette: update query + results only (input stays put).
function cmdkOnInput(value){
  CMDK_STATE.query = value;
  CMDK_STATE.activeIndex = 0;
  renderCommandPalette();
}

// Hover/selection change: just move the 'active' highlight between existing
// nodes — do NOT re-render the results, or we'd destroy the very item the user
// is about to click (which was swallowing clicks on patients/results/actions).
function cmdkSetActive(i){
  CMDK_STATE.activeIndex = i;
  const root = document.getElementById('cmdk-root');
  if(!root) return;
  root.querySelectorAll('.cmdk-item').forEach(el=>{
    el.classList.toggle('active', Number(el.dataset.cmdkIndex) === i);
  });
}


function cmdkKeyHandler(e){
  const items = commandPaletteItems();
  if(e.key === 'ArrowDown'){
    e.preventDefault();
    CMDK_STATE.activeIndex = Math.min(items.length-1, CMDK_STATE.activeIndex+1);
    renderCommandPalette();
  } else if(e.key === 'ArrowUp'){
    e.preventDefault();
    CMDK_STATE.activeIndex = Math.max(0, CMDK_STATE.activeIndex-1);
    renderCommandPalette();
  } else if(e.key === 'Enter'){
    e.preventDefault();
    const item = items[CMDK_STATE.activeIndex];
    if(item) item.action();
  }
}

function closeCommandPalette(){
  const r = document.getElementById('cmdk-root');
  if(r) r.innerHTML = '';
}

/* ==========================================================
   MOBILE SIDEBAR DRAWER
   ========================================================== */
function toggleSidebar(){
  const sb = document.querySelector('.sidebar');
  const bd = document.getElementById('sidebar-backdrop');
  if(!sb || !bd) return;
  const isOpen = sb.classList.contains('open');
  if(isOpen){
    sb.classList.remove('open');
    bd.classList.remove('active');
    document.body.style.overflow = '';
  } else {
    sb.classList.add('open');
    bd.classList.add('active');
    document.body.style.overflow = 'hidden';
  }
}
function closeSidebar(){
  const sb = document.querySelector('.sidebar');
  const bd = document.getElementById('sidebar-backdrop');
  if(sb) sb.classList.remove('open');
  if(bd) bd.classList.remove('active');
  document.body.style.overflow = '';
}
// On nav click, close the sidebar on mobile so the page change is visible.
// (Navigation itself is wired via inline onclick in renderShell.)
document.addEventListener('click', function(e){
  const navItem = e.target.closest('.nav-item');
  if(navItem && window.innerWidth <= 640){
    setTimeout(closeSidebar, 100);
  }
});
// Detect platform for kbd-hint display
(function(){
  const ua = (navigator.userAgent || '').toLowerCase();
  const isMac = /mac|iphone|ipad|ipod/.test(ua);
  if(!isMac){
    // Replace ⌘ symbols in the topbar hint with "Ctrl"
    document.addEventListener('DOMContentLoaded', function(){
      document.querySelectorAll('.top-search input').forEach(i => {
        if(i.placeholder.includes('⌘K')) i.placeholder = i.placeholder.replace('⌘K', 'Ctrl+K');
      });
    });
  }
})();

