const STATUS_META = {
  live:    { label:'Live',        cls:'mod-live',    note:'This module is fully implemented and in use.' },
  partial: { label:'In progress', cls:'mod-partial', note:'Core capability exists; the items below are being completed.' },
  planned: { label:'Planned',     cls:'mod-planned', note:'Designed and on the roadmap. The capabilities below describe the intended scope.' }
};

function renderModuleScaffold(root, key){
  const m = MODULE_SCAFFOLDS[key];
  const route = ROUTES[key] || {};
  if(!m){
    root.innerHTML = `<div class="page-header"><div><div class="page-title">${esc(route.title||key)}</div></div></div><div class="card"><div class="empty-state">Module not found.</div></div>`;
    return;
  }
  const st = STATUS_META[m.status] || STATUS_META.planned;
  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title" style="display:flex;align-items:center;gap:10px">${sectionIcon(m.icon, 24)} ${esc(route.title||key)}</div>
        <div class="page-subtitle">${esc(route.sub||m.purpose)}</div>
      </div>
      <div class="actions">
        <span class="mod-status ${st.cls}">${st.label}</span>
      </div>
    </div>

    <div class="card mod-hero">
      <div class="mod-hero-icon">${sectionIcon(m.icon, 30)}</div>
      <div>
        <div class="mod-hero-domain">${esc(m.domain)}</div>
        <p class="mod-hero-purpose">${esc(m.purpose)}</p>
        <div class="mod-status-note">${esc(st.note)}</div>
      </div>
    </div>

    <div class="card">
      <div class="card-section-title">Capabilities</div>
      <div class="mod-cap-grid">
        ${m.capabilities.map(c=>`
          <div class="mod-cap">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
            <span>${esc(c)}</span>
          </div>
        `).join('')}
      </div>
    </div>

    ${m.api ? `
    <div class="card">
      <div class="card-section-title">Backend</div>
      <p class="muted-sm" style="margin:0 0 8px">This module is backed by a live API endpoint. When LabOS is connected to its backend, this screen will load real data from:</p>
      <code class="mod-api">${esc(m.api)}</code>
    </div>` : ''}

    <div class="card mod-cta">
      <div>
        <b>Want this prioritised?</b>
        <div class="muted-sm">Module roadmap is driven by lab demand. Flag this to your account manager.</div>
      </div>
      <button class="btn" onclick="toast('Noted — interest recorded.', {type:'info', title:'Thanks'})">Request priority</button>
    </div>
  `;
}

// Helper that returns a render function bound to a scaffold key.
function scaffold(key){ return (root)=>renderModuleScaffold(root, key); }

// ===========================================================================
// REUSABLE DIAGNOSTICS-DOMAIN PATTERN
// One renderer + create-flow factory, instantiated for Hematology,
// Microbiology, Immunology & Serology, and Toxicology. Each domain supplies a
// config (data array, columns, stats, status map, create-modal fields). This
// is the shared Core Services foundation applied to four domains at once,
// rather than four bespoke screens.
// ===========================================================================

const DX_STATUS_CLS = {
  received:'pending', incubating:'progress', screening:'progress', in_analysis:'progress',
  identification:'progress', sensitivities:'progress', confirmation:'progress',
  review:'review', resulted:'completed', verified:'completed', reported:'completed', released:'released',
  // research & genomics
  queued:'pending', library_prep:'progress', sequencing:'progress', basecalling:'progress',
  qc:'review', alignment:'progress', variant_calling:'progress', annotation:'review',
  complete:'completed', recruiting:'progress', active:'progress', closed:'released'
};
function dxStatusChip(s){
  const label = String(s||'').replace(/_/g,' ').replace(/\b\w/g, c=>c.toUpperCase());
  return `<span class="status ${DX_STATUS_CLS[s]||'pending'}">${esc(label)}</span>`;
}

// Render a generic diagnostics domain list+stats screen from a config.
function renderDxDomain(root, cfg){
  const rows = (APP_STATE[cfg.store] || []);
  const statCards = cfg.stats(rows).map(s=>`
    <div class="stat-card"><div class="stat-label">${esc(s.label)}</div>
      <div class="stat-value"${s.danger?' style="color:#9A1F1F"':''}>${esc(String(s.value))}</div>
      ${s.trend?`<div class="stat-trend">${esc(s.trend)}</div>`:''}</div>
  `).join('');
  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title" style="display:flex;align-items:center;gap:10px">${sectionIcon(cfg.icon, 24)} ${esc(cfg.title)}</div>
        <div class="page-subtitle">${esc(cfg.subtitle)}</div>
      </div>
      <div class="actions">
        <button class="btn primary" onclick="openDxOrder('${cfg.key}')">+ ${esc(cfg.createLabel)}</button>
      </div>
    </div>
    <div class="stats-grid">${statCards}</div>
    <div class="panel" style="margin-top:16px">
      <div class="panel-header"><div class="panel-title">${esc(cfg.listTitle)}</div><span class="pill">${rows.length} on record</span></div>
      <div class="panel-body flush">
        ${rows.length === 0 ? emptyState({icon:cfg.emptyIcon||'🧫', title:'Nothing here yet', msg:cfg.emptyMsg||'Orders will appear here once created.'}) : `
        <table>
          <thead><tr>${cfg.columns.map(c=>`<th>${esc(c.label)}</th>`).join('')}</tr></thead>
          <tbody>
            ${rows.map(r=>`<tr>${cfg.columns.map(c=>`<td>${c.cell(r)}</td>`).join('')}</tr>`).join('')}
          </tbody>
        </table>`}
      </div>
    </div>
  `;
}

