function submitRgCreate(key){
  const cfg = RG_DOMAINS[key];
  if(!requireLicensed('create a '+cfg.title+' record')) return;
  const rows = APP_STATE[cfg.store] || (APP_STATE[cfg.store] = []);
  const seqStart = {sequencing:15, bioinformatics:32, clinicalTrials:5, cohorts:8, genomicResearch:23}[key] || 1;
  const pad = (key==='clinicalTrials'||key==='cohorts'||key==='genomicResearch') ? 4 : 4;
  const id = `${cfg.idPrefix}-2026-${String(rows.length+seqStart).padStart(pad,'0')}`;
  const now = new Date().toISOString().slice(0,16).replace('T',' ');
  let rec, label;
  if(key==='sequencing'){
    rec = {id, sample:$v('rg-sample')||'—', assay:$v('rg-assay'), platform:$v('rg-platform'), status:'library_prep', requestedBy:S().userName||'Researcher', startedAt:now, reads:null, study:$v('rg-study')||null};
    label = rec.assay;
  } else if(key==='bioinformatics'){
    rec = {id, run:$v('rg-run')||'—', pipeline:$v('rg-pipeline'), reference:$v('rg-reference'), status:'queued', variants:null, startedAt:null, annotated:false};
    label = rec.pipeline;
  } else if(key==='clinicalTrials'){
    const title=($v('rg-title')||'').trim(); if(!title){ toast('Enter a trial title',{type:'error',title:'Required'}); return; }
    rec = {id, title, phase:$v('rg-phase'), sponsor:$v('rg-sponsor')||'—', irb:$v('rg-irb')||'pending', status:'recruiting', enrolled:0, target:parseInt($v('rg-target'),10)||100, study:$v('rg-study')||null};
    label = title;
  } else if(key==='cohorts'){
    const name=($v('rg-name')||'').trim(); if(!name){ toast('Enter a cohort name',{type:'error',title:'Required'}); return; }
    rec = {id, name, criteria:$v('rg-criteria')||'—', members:parseInt($v('rg-members'),10)||0, linkedStudy:$v('rg-study')||null, updatedAt:new Date().toISOString().slice(0,10)};
    label = name;
  } else {
    const variant=($v('rg-variant')||'').trim(); if(!variant){ toast('Enter the variant',{type:'error',title:'Required'}); return; }
    const rgPat = pcPatient('rg-patient');
    rec = {id, patient: rgPat ? rgPat.name : '', patientId: rgPat ? rgPat.id : null, gene:$v('rg-gene'), variant, classification:$v('rg-classification'), zygosity:$v('rg-zygosity'), cohort:null, reported:false};
    label = `${rec.gene} ${variant}`;
  }
  rows.unshift(rec);
  OfflineCore.record('research.'+key, {id}, `${id} ${cfg.title} — ${label}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`${cfg.title} record created.`, {type:'success', title:id, duration:4500});
  if(RG_DOMAINS[APP_STATE.currentRoute]) navigate(APP_STATE.currentRoute);
}


