function submitDxOrder(key){
  const cfg = DX_DOMAINS[key];
  if(!cfg) return;
  if(!requireLicensed('create a '+cfg.title+' order')) return;
  if(pcRequire('dx-patient','patient')) return;
  const patientId = pcPatient('dx-patient')?.id;
  const patient = (APP_STATE.patients||[]).find(p=>p.id===patientId);
  if(!patient){ toast('Select a patient', {type:'error', title:'Required'}); return; }
  const test = $v('dx-test') || cfg.panels[0];
  const priority = $v('dx-priority') || 'Routine';
  const rows = APP_STATE[cfg.store] || (APP_STATE[cfg.store] = []);
  const n = rows.length + (key==='toxicology'?20:(key==='immunology'?62:(key==='microbiology'?35:52)));
  const id = `${cfg.idPrefix}-2026-${String(n).padStart(4,'0')}`;
  const now = new Date().toISOString().slice(0,16).replace('T',' ');
  const base = { id, patient:patient.name, patientId:patient.id, received:now, priority, status:'received' };
  let rec;
  if(key==='hematology')      rec = {...base, panel:test, category:'fbc', flags:[], analyser:'Sysmex XN-1000'};
  else if(key==='microbiology') rec = {...base, specimen:$v('dx-specimen')||'Urine (MSU)', test:'Culture & sensitivity', organism:null, growth:null, resistance:null, gram:null};
  else if(key==='immunology') rec = {...base, test, group:'Infectious serology', result:null, method:'CLIA'};
  else                        rec = {...base, test, kind:'doa', custody: !!document.getElementById('dx-custody')?.checked, result:null};
  rows.unshift(rec);
  OfflineCore.record(key+'.order', {id, patientId:patient.id}, `${id} ${cfg.title} order — ${test}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`${cfg.title} order created.`, {type:'success', title:id, duration:4500});
  if(APP_STATE.currentRoute === key) navigate(key);
}



