const SPEC_TYPE_LABEL = {whole_blood:'Whole blood', serum:'Serum', plasma:'Plasma', buffy_coat:'Buffy coat', dna:'DNA', rna:'RNA', tissue_ffpe:'Tissue (FFPE)', tissue_frozen:'Tissue (frozen)', urine:'Urine', saliva:'Saliva', csf:'CSF', stool:'Stool', swab:'Swab', cell_line:'Cell line', other:'Other'};
const SPEC_STATUS_LABEL = {collected:'Collected', in_transit:'In transit', received:'Received', processing:'Processing', stored:'Stored', checked_out:'Checked out', depleted:'Depleted', discarded:'Discarded', transferred:'Transferred'};

function biobankStatusChip(s){
  const map = {stored:'ok', received:'info', collected:'info', in_transit:'warn', processing:'warn', checked_out:'warn', depleted:'muted', discarded:'danger', transferred:'muted'};
  return `<span class="chip chip-${map[s]||'muted'}">${esc(SPEC_STATUS_LABEL[s]||s)}</span>`;
}

// ===========================================================================
// BIOBANKOS — real action flows (deepening the existing screens)
// These persist to APP_STATE.biobank and record to the offline outbox. When the
// backend is connected they map to POST /biobank/* endpoints. The consent
// withdrawal genuinely propagates to the donor's specimens — the safety-critical
// behaviour the database trigger enforces server-side.
// ===========================================================================

function biobankNextId(prefix, arr, pad){
  const n = (arr||[]).length + 1;
  return `${prefix}-2026-${String(n).padStart(pad, '0')}`;
}

