function submitBiobankConsent(){
  if(!requireLicensed('record consent')) return;
  const bb = biobankSeed();
  if(pcRequire('bbc-patient','donor')) return;
  const patientObj = pcPatient('bbc-patient');
  const patient = patientObj ? patientObj.name : null;
  const study = $v('bbc-study') || null;
  const scopes = [...document.querySelectorAll('.bbc-scope:checked')].map(c=>c.value);
  if(scopes.length===0){ toast('Select at least one consent scope', {type:'error', title:'Required'}); return; }
  const id = biobankNextId('CON', bb.consents, 4);
  bb.consents.unshift({id, patient, study, version:'v1', status:'active', scope:scopes.join(', '), signedAt:new Date().toISOString().slice(0,10)});
  OfflineCore.record('biobank.consent.record', {id}, `Consent ${id} recorded — ${patient}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`Consent ${id} recorded for ${patient}.`, {type:'success', title:id, duration:4500});
  if(APP_STATE.currentRoute==='biobankConsent') navigate('biobankConsent');
}

// ---- New study ----
function openBiobankStudy(){
  document.getElementById('modal-root').innerHTML = `
    <div class="modal-backdrop" onclick="closeModal()"></div>
    <div class="modal" style="max-width:540px">
      <div class="modal-header">
        <div><div class="modal-title">New research study</div><div class="muted-sm">Specimens enrol into this protocol</div></div>
        <button class="modal-close" onclick="closeModal()">×</button>
      </div>
      <div class="modal-body">
        <label class="label">Study title</label>
        <input class="input" id="bbs-title" placeholder="e.g. Type 2 Diabetes Biomarker Cohort"/>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:14px">
          <div><label class="label">Principal investigator</label><input class="input" id="bbs-pi" placeholder="Prof. / Dr."/></div>
          <div><label class="label">IRB / ethics number</label><input class="input" id="bbs-irb" placeholder="NHREC/2026/…"/></div>
        </div>
        <label class="label" style="margin-top:14px">Status</label>
        <select class="input" id="bbs-status"><option value="recruiting">Recruiting</option><option value="active">Active</option><option value="closed">Closed</option></select>
      </div>
      <div class="modal-footer">
        <button class="btn" onclick="closeModal()">Cancel</button>
        <button class="btn primary" onclick="submitBiobankStudy()">Create study</button>
      </div>
    </div>
  `;
  _modalA11y();
}

function submitBiobankStudy(){
  if(!requireLicensed('create a study')) return;
  const bb = biobankSeed();
  const title = ($v('bbs-title')||'').trim();
  if(!title){ toast('Enter a study title', {type:'error', title:'Required'}); return; }
  const id = biobankNextId('STD', bb.studies, 4);
  bb.studies.unshift({id, title, pi:$v('bbs-pi')||'—', irb:$v('bbs-irb')||'pending', status:$v('bbs-status')||'recruiting', specimens:0});
  OfflineCore.record('biobank.study', {id}, `Study ${id} created — ${title}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`Study ${id} created.`, {type:'success', title:id, duration:4500});
  if(APP_STATE.currentRoute==='biobankStudies') navigate('biobankStudies');
}

// ---- Add storage unit ----
function openBiobankStorage(){
  document.getElementById('modal-root').innerHTML = `
    <div class="modal-backdrop" onclick="closeModal()"></div>
    <div class="modal" style="max-width:520px">
      <div class="modal-header">
        <div><div class="modal-title">Add storage unit</div><div class="muted-sm">Freezer or LN₂ tank</div></div>
        <button class="modal-close" onclick="closeModal()">×</button>
      </div>
      <div class="modal-body">
        <label class="label">Unit name</label>
        <input class="input" id="bbu-name" placeholder="e.g. Secondary −80 Freezer"/>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:14px">
          <div><label class="label">Type</label>
            <select class="input" id="bbu-kind" onchange="bbuSyncTemp(this.value)">
              <option value="freezer_minus80" data-temp="-80">−80 °C Freezer</option>
              <option value="freezer_minus20" data-temp="-20">−20 °C Freezer</option>
              <option value="ln2_tank" data-temp="-196">LN₂ Vapour Tank</option>
              <option value="fridge" data-temp="4">4 °C Fridge</option>
            </select>
          </div>
          <div><label class="label">Capacity (slots)</label><input class="input" id="bbu-capacity" type="number" value="6561"/></div>
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn" onclick="closeModal()">Cancel</button>
        <button class="btn primary" onclick="submitBiobankStorage()">Add unit</button>
      </div>
    </div>
  `;
  _modalA11y();
}

function submitBiobankStorage(){
  if(!requireLicensed('add a storage unit')) return;
  const bb = biobankSeed();
  const name = ($v('bbu-name')||'').trim();
  if(!name){ toast('Enter a unit name', {type:'error', title:'Required'}); return; }
  const kindSel = document.getElementById('bbu-kind');
  const kind = kindSel ? kindSel.value : 'freezer_minus80';
  const tempC = kindSel ? Number(kindSel.selectedOptions[0].dataset.temp) : -80;
  const capacity = parseInt($v('bbu-capacity'),10) || 1000;
  const seq = bb.units.length + 1;
  const prefix = kind==='ln2_tank' ? 'LN2' : 'FRZ';
  const id = `${prefix}-${String(seq).padStart(3,'0')}`;
  bb.units.unshift({id, name, kind, tempC, capacity, occupied:0, status:'online'});
  OfflineCore.record('biobank.storage', {id}, `Storage unit ${id} added — ${name}`);
  OfflineCore.schedulePersist();
  closeModal();
  toast(`Storage unit ${id} added.`, {type:'success', title:id, duration:4500});
  if(APP_STATE.currentRoute==='biobankStorage') navigate('biobankStorage');
}


