function biobankResolveBarcode(){
  const bb = biobankSeed();
  const code = (document.getElementById('bb-scan').value||'').trim();
  const el = document.getElementById('bb-scan-result');
  if(!code){ el.innerHTML = '<div class="muted-sm">Enter a barcode above.</div>'; return; }
  const s = bb.specimens.find(x=>x.barcode.toLowerCase()===code.toLowerCase());
  if(!s){ el.innerHTML = `<div class="alert-banner warn">No specimen found for <b>${esc(code)}</b>.</div>`; return; }
  el.innerHTML = `
    <div class="card" style="margin:0;background:var(--bg-soft)">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div><b>${esc(s.id)}</b> · ${esc(SPEC_TYPE_LABEL[s.type]||s.type)}</div>
        ${biobankStatusChip(s.status)}
      </div>
      <div class="kv-grid" style="margin-top:10px">
        <div class="kv"><div class="k">Donor</div><div class="v">${esc(s.patient)}</div></div>
        <div class="kv"><div class="k">Position</div><div class="v">${esc(s.position)}</div></div>
        <div class="kv"><div class="k">Volume</div><div class="v">${s.remainingMl!=null?`${s.remainingMl}/${s.volumeMl} mL`:'—'}</div></div>
      </div>
    </div>`;
}

