// Platform → Module map. Surfaces the LABOS_MODULES manifest (which mirrors
// labos-api/src/platform/modules.js) as a real screen so super-admins can see
// platform build coverage at a glance: which modules are live, partially built,
// or still planned, and which backing tables each owns. Live/partial modules
// with a tenant route are click-through (they jump into the tenant screen).
function moduleStatusMeta(status){
  switch(status){
    case 'live':    return {label:'Live',    color:'#1F7A4D', bg:'rgba(31,122,77,0.10)'};
    case 'partial': return {label:'Partial', color:'#C77B14', bg:'rgba(199,123,20,0.12)'};
    case 'planned': return {label:'Planned', color:'#6B7787', bg:'rgba(107,119,135,0.12)'};
    default:        return {label:status||'—', color:'#6B7787', bg:'rgba(107,119,135,0.12)'};
  }
}

// Manifest module routes look like '/patients'; tenant ROUTES keys are bare
// ('patients'). Resolve a manifest route to a navigable ROUTES key, if any.
function moduleRouteKey(route){
  if(!route) return null;
  const key = String(route).replace(/^\//, '');
  return ROUTES[key] ? key : null;
}

function renderPlatformModules(root){
  const groups = (typeof window !== 'undefined' && window.LABOS_MODULES) || [];
  const cov = (typeof window !== 'undefined' && window.LABOS_COVERAGE) || null;
  const total = cov ? cov.total : groups.reduce((n,g)=>n+(g.modules?g.modules.length:0),0);
  const live = cov ? cov.live : 0;
  const partial = cov ? cov.partial : 0;
  const planned = cov ? cov.planned : 0;
  const pct = cov ? cov.pctLiveOrPartial : (total ? Math.round(((live+partial)/total)*100) : 0);

  const groupCards = groups.map(g=>{
    const counts = (g.modules||[]).reduce((c,m)=>{ c[m.status]=(c[m.status]||0)+1; return c; }, {});
    const summary = ['live','partial','planned']
      .filter(s=>counts[s])
      .map(s=>`${counts[s]} ${moduleStatusMeta(s).label.toLowerCase()}`)
      .join(' · ');
    const rows = (g.modules||[]).map(m=>{
      const meta = moduleStatusMeta(m.status);
      const navKey = (m.status==='live'||m.status==='partial') ? moduleRouteKey(m.route) : null;
      const tables = (m.tables||[]).length
        ? (m.tables||[]).map(t=>`<code class="mod-table">${esc(t)}</code>`).join(' ')
        : '<span class="muted-sm">—</span>';
      const clickAttr = navKey
        ? ` style="cursor:pointer" onclick="navigate('${navKey}')" title="Open ${esc(m.name)}"`
        : '';
      return `
        <tr${clickAttr}>
          <td>
            <strong>${esc(m.name)}</strong>
            ${navKey?'<span class="muted-sm" style="margin-left:6px">↗</span>':''}
            <div class="muted-sm">${esc(m.route||'')}</div>
          </td>
          <td><span class="status-pill" style="color:${meta.color};background:${meta.bg}">${meta.label}</span></td>
          <td>${tables}</td>
        </tr>`;
    }).join('');
    return `
      <div class="card" style="margin-top:16px">
        <div class="card-section-title" style="display:flex;justify-content:space-between;align-items:baseline">
          <span>${esc(g.name)}</span>
          <span class="muted-sm" style="font-weight:500">${summary}</span>
        </div>
        <table class="table" style="font-size:12px">
          <thead><tr><th style="width:42%">Module</th><th style="width:14%">Status</th><th>Backing tables</th></tr></thead>
          <tbody>${rows}</tbody>
        </table>
      </div>`;
  }).join('');

  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title">Module map</div>
        <div class="page-subtitle">${total} modules across ${groups.length} domains · ${pct}% live or partial</div>
      </div>
      <div class="actions">
        <button class="btn" onclick="exportModuleMapCsv()">Export CSV</button>
      </div>
    </div>

    <div class="stats-grid">
      <div class="stat-card"><div class="stat-label">Total modules</div><div class="stat-value">${total}</div><div class="stat-trend">${groups.length} domains</div></div>
      <div class="stat-card"><div class="stat-label">Live</div><div class="stat-value" style="color:#1F7A4D">${live}</div><div class="stat-trend">Shipped & tested</div></div>
      <div class="stat-card"><div class="stat-label">Partial</div><div class="stat-value" style="color:#C77B14">${partial}</div><div class="stat-trend">Usable, in progress</div></div>
      <div class="stat-card"><div class="stat-label">Planned</div><div class="stat-value" style="color:#6B7787">${planned}</div><div class="stat-trend">On the roadmap</div></div>
      <div class="stat-card"><div class="stat-label">Coverage</div><div class="stat-value">${pct}%</div><div class="stat-trend">Live + partial</div></div>
    </div>

    <div class="card" style="margin-top:24px">
      <div class="muted-sm">This map mirrors the platform module manifest shared with the backend (<code>labos-api/src/platform/modules.js</code>). Live and partial modules with a tenant route are click-through.</div>
    </div>

    ${groupCards}
  `;
}

// Flatten the module manifest to a CSV the same way the inventory/PO exporters do.
function exportModuleMapCsv(){
  const groups = (typeof window !== 'undefined' && window.LABOS_MODULES) || [];
  const rows = [['Domain','Module','Key','Status','Route','Tables']];
  groups.forEach(g=>(g.modules||[]).forEach(m=>{
    rows.push([g.name, m.name, m.key, m.status, m.route||'', (m.tables||[]).join('; ')]);
  }));
  const csv = rows.map(r=>r.map(c=>{
    const s = String(c==null?'':c);
    return /[",\n]/.test(s) ? '"'+s.replace(/"/g,'""')+'"' : s;
  }).join(',')).join('\n');
  const blob = new Blob([csv], {type:'text/csv;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = 'labos-module-map.csv';
  document.body.appendChild(a); a.click(); a.remove();
  setTimeout(()=>URL.revokeObjectURL(url), 1000);
  if(typeof toast === 'function'){
    const n = rows.length - 1;
    toast(`Exported ${n} module${n===1?'':'s'} to CSV.`, {type:'success', title:'Export', duration:4000});
  }
}

