// ---- Tenant provisioning (platform super-admin) ----
// Invite-only access starts here: the operator provisions a laboratory, which
// creates the tenant record AND mints a one-time activation code. The operator
// hands that code to the lab admin, who redeems it at the onboarding gate.
function openProvisionTenant(){
  document.getElementById('modal-root').innerHTML = `
    <div class="modal-backdrop" onclick="closeModal()"></div>
    <div class="modal" style="max-width:560px">
      <div class="modal-header">
        <div><div class="modal-title">Provision a laboratory</div><div class="muted-sm">Creates the tenant and issues a one-time activation code</div></div>
        <button class="modal-close" onclick="closeModal()">×</button>
      </div>
      <div class="modal-body">
        <div class="alert-banner info" style="margin-bottom:16px">
          <span class="icon">🔑</span>
          <div>LabOS is invite-only. Fill in the laboratory's details, then share the generated activation code with the lab administrator so they can complete setup.</div>
        </div>
        <div id="prov-form">
          <div><label class="label">Laboratory name<span class="req">*</span></label><input class="input" id="prov-name" placeholder="e.g. Sunrise Diagnostics"/><div class="onb-field-err" id="prov-name-err" style="display:none"></div></div>
          <div style="margin-top:12px"><label class="label">Official email<span class="req">*</span></label><input class="input" id="prov-email" type="email" placeholder="admin@laboratory.com"/><div class="onb-field-err" id="prov-email-err" style="display:none"></div></div>
          <div style="margin-top:12px"><label class="label">Country</label><input class="input" id="prov-country" value="Nigeria"/></div>
          <div style="margin-top:12px">
            <label class="label">Plan</label>
            <select class="input" id="prov-plan">
              ${(APP_STATE.plans||[]).map(p=>`<option value="${p.code}" ${p.code==='professional'?'selected':''}>${p.name} — ${naira(p.annualPrice)}/yr</option>`).join('')}
            </select>
          </div>
        </div>
        <div id="prov-result" style="display:none"></div>
      </div>
      <div class="modal-footer" id="prov-footer">
        <button class="btn" onclick="closeModal()">Cancel</button>
        <button class="btn primary" onclick="submitProvisionTenant()">Provision & generate code →</button>
      </div>
    </div>`;
  setTimeout(()=>{ const el=document.getElementById('prov-name'); if(el) el.focus(); }, 50);
}

function submitProvisionTenant(){
  const name = (document.getElementById('prov-name').value||'').trim();
  const email = (document.getElementById('prov-email').value||'').trim();
  const country = (document.getElementById('prov-country').value||'').trim() || 'Nigeria';
  const plan = document.getElementById('prov-plan').value || 'professional';

  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  let valid = true;
  const nameErr = document.getElementById('prov-name-err');
  const emailErr = document.getElementById('prov-email-err');
  if(nameErr){ nameErr.style.display='none'; }
  if(emailErr){ emailErr.style.display='none'; }
  if(name.length < 2){ if(nameErr){ nameErr.textContent='Laboratory name is required.'; nameErr.style.display='block'; } valid=false; }
  if(!emailRe.test(email)){ if(emailErr){ emailErr.textContent='Enter a valid official email.'; emailErr.style.display='block'; } valid=false; }
  if(!valid) return;

  const id = 'tnt_prov_' + Math.random().toString(36).slice(2,7);
  const code = LicenseCore.generateActivationCode(name);
  const logoMark = name.split(/\s+/).map(w=>w[0]).join('').slice(0,3).toUpperCase() || 'LB';
  const palette = ['#2F4A6D','#1A4D5E','#5B3A8E','#7A2E3F','#3F6B2E','#2C5F8D','#8B6914'];
  const colour = palette[Math.floor(Math.random()*palette.length)];
  const today = new Date().toISOString().slice(0,10);

  APP_STATE.tenants.push({
    id, name, parentOrg:null, rcNumber:'', tin:'',
    accreditation:{},
    description:'', website:'', officialEmail:email,
    phoneNumbers:[],
    logoMark, primaryColour:colour,
    headOffice:'', country,
    status:'TRIAL', createdAt:today,
    centresCount:0, staffCount:0, patientsMTD:0, annualValue:0,
    plan,
    // Invite-only provisioning: one-time code, not yet redeemed.
    activationCode:code, activationUsedAt:null, provisionedAt:new Date().toISOString()
  });
  if(typeof OfflineCore !== 'undefined') OfflineCore.schedulePersist();

  // Swap the modal body to a success state showing the code.
  const form = document.getElementById('prov-form');
  const footer = document.getElementById('prov-footer');
  const result = document.getElementById('prov-result');
  if(form) form.style.display='none';
  if(result){
    result.style.display='block';
    result.innerHTML = `
      <div class="alert-banner success" style="margin-bottom:16px">
        <span class="icon">✓</span>
        <div><b>${esc(name)}</b> has been provisioned. Share the activation code below with the lab administrator.</div>
      </div>
      <label class="label">Activation code</label>
      <div style="display:flex;gap:8px;align-items:center;margin-top:4px">
        <code id="prov-code" style="flex:1;font-size:18px;font-weight:700;letter-spacing:0.06em;padding:12px 16px;background:var(--bg-soft);border:1px dashed var(--line);border-radius:8px;text-align:center">${esc(code)}</code>
        <button class="btn" onclick="copyProvisionCode('${esc(code)}')">Copy</button>
      </div>
      <div class="muted-sm" style="margin-top:8px">This is a one-time code. It becomes invalid once the lab admin redeems it. You can see all provisioned labs and their codes in the tenants list.</div>`;
  }
  if(footer){
    footer.innerHTML = `<button class="btn" onclick="closeModal();navigate('platformTenants')">Done</button>`;
  }
  if(typeof toast === 'function') toast(`Provisioned ${name}. Activation code generated.`, {type:'success', title:'Tenant provisioned', duration:5000});
}

function copyProvisionCode(code){
  const done = ()=>{ if(typeof toast === 'function') toast('Activation code copied to clipboard.', {type:'success', duration:2500}); };
  if(navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(code).then(done).catch(()=>{
      const el=document.getElementById('prov-code'); if(el){ const r=document.createRange(); r.selectNode(el); const sel=getSelection(); sel.removeAllRanges(); sel.addRange(r); }
    });
  } else {
    const el=document.getElementById('prov-code'); if(el){ const r=document.createRange(); r.selectNode(el); const sel=getSelection(); sel.removeAllRanges(); sel.addRange(r); }
  }
}

