function renderPlatformPlans(root){
  const plans = APP_STATE.plans || [];
  const subs  = APP_STATE.subscriptions || [];
  const addOns = APP_STATE.planAddOns || [];

  const tierColors = {1:'#6B7787', 2:'#2F5F2F', 3:'#2F4A6D', 4:'#7A5410'};
  const tick = '<span style="color:#1B6B3A;font-weight:700">✓</span>';
  const cross = '<span style="color:#9A1F1F">✗</span>';

  // Module access matrix rows
  const moduleRows = [
    {label:'Core lab (requests, samples, results)',   key:'always'},
    {label:'Billing & Inventory',                     key:'always'},
    {label:'Appointment management',                  key:'always'},
    {label:'Hematology',                              key:'hematology'},
    {label:'Microbiology',                            key:'microbiology'},
    {label:'Immunology & Serology',                   key:'immunology'},
    {label:'Clinical health packages',                key:'packages'},
    {label:'Notifications (SMS/WhatsApp)',             key:'notifications'},
    {label:'Integrations (Termii / HL7)',              key:'integrations'},
    {label:'Renal & Dialysis',                        key:'renal'},
    {label:'Histopathology & Cytology',               key:'histopath'},
    {label:'Molecular Diagnostics',                   key:'molecular'},
    {label:'Toxicology',                              key:'toxicology'},
    {label:'Imaging — Ultrasound, ECG, Radiology, Echo', key:'imaging'},
    {label:'BiobankOS',                               key:'biobank'},
    {label:'Advanced analytics & reporting',          key:'advancedAnalytics'},
    {label:'API access (10k calls/month)',             key:'apiAccess'},
    {label:'CT Scan & MRI',                           key:'imagingAdvanced'},
    {label:'DNA & Genetics',                          key:'dna'},
    {label:'Research & Genomics',                     key:'research'},
    {label:'White-label branding',                    key:'whiteLabel'},
    {label:'Dedicated database',                      key:'dedicatedDatabase'},
  ];

  const matrixRows = moduleRows.map(row => {
    const cells = plans.map(p => {
      if(row.key === 'always') return `<td style="text-align:center">${tick}</td>`;
      const on = p.entitlements.modules[row.key] === true;
      return `<td style="text-align:center">${on ? tick : cross}</td>`;
    }).join('');
    return `<tr><td style="padding:5px 10px;font-size:12px;color:var(--ink-soft)">${row.label}</td>${cells}</tr>`;
  }).join('');

  const planHeaders = plans.map(p => {
    const count = subs.filter(s => s.planId === p.id && s.status !== 'CANCELLED').length;
    const col = tierColors[p.tier] || '#2F4A6D';
    const annualUSD = Math.round(p.annualPrice / 1600);
    return `<th style="text-align:center;padding:8px 12px;color:${col}">
      <div style="font-weight:700;font-size:13px">${esc(p.name)}</div>
      ${p.popular ? '<div style="font-size:10px;background:#2F4A6D;color:#fff;border-radius:3px;padding:1px 5px;display:inline-block;margin:2px 0">POPULAR</div>' : ''}
      <div style="font-size:11px;color:var(--ink-soft);margin-top:2px">${naira(p.annualPrice)}/yr</div>
      <div style="font-size:10px;color:var(--ink-faint)">≈ $${annualUSD}/yr · ${count} active</div>
    </th>`;
  }).join('');

  const planCards = plans.map(p => {
    const col = tierColors[p.tier] || '#2F4A6D';
    const count = subs.filter(s => s.planId === p.id && s.status !== 'CANCELLED').length;
    const ents = p.entitlements;
    const lim = v => v === 'unlimited' ? '∞' : v;
    return `
      <div class="card" style="border-top:3px solid ${col};position:relative">
        ${p.popular ? `<div style="position:absolute;top:-1px;right:12px;background:${col};color:#fff;font-size:10px;font-weight:700;letter-spacing:0.5px;padding:2px 8px;border-radius:0 0 4px 4px">POPULAR</div>` : ''}
        <div style="display:flex;justify-content:space-between;align-items:flex-start">
          <div>
            <div style="font-size:16px;font-weight:700;color:${col}">${esc(p.name)}</div>
            <div class="muted-sm">${esc(p.tagline)}</div>
          </div>
          <div style="text-align:right">
            <div style="font-size:18px;font-weight:700">${naira(p.annualPrice)}<span class="muted-sm" style="font-size:12px">/yr</span></div>
            <div class="muted-sm" style="font-size:11px">${naira(p.monthlyPrice||0)}/mo · ${p.trialDays}d trial</div>
          </div>
        </div>
        <div class="section-divider" style="margin:10px 0"><span class="label">Limits</span><div class="line"></div></div>
        <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;font-size:12px;text-align:center">
          <div style="background:var(--bg-soft);border-radius:6px;padding:6px"><div style="font-weight:700;font-size:15px">${lim(ents.maxCentres)}</div><div class="muted-sm">Centres</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:6px"><div style="font-weight:700;font-size:15px">${lim(ents.maxStaff)}</div><div class="muted-sm">Staff</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:6px"><div style="font-weight:700;font-size:15px">${lim(ents.maxPatientsPerMonth)}</div><div class="muted-sm">Patients/mo</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:6px"><div style="font-weight:700;font-size:15px">${lim(ents.maxDevices)}</div><div class="muted-sm">Devices</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:6px"><div style="font-weight:700;font-size:15px">${lim(ents.storageGb)}</div><div class="muted-sm">GB storage</div></div>
          <div style="background:var(--bg-soft);border-radius:6px;padding:6px"><div style="font-weight:700;font-size:15px">${lim(ents.apiCallsPerMonth)||'—'}</div><div class="muted-sm">API/mo</div></div>
        </div>
        <div class="section-divider" style="margin:10px 0"><span class="label">Fees</span><div class="line"></div></div>
        <div style="font-size:12px;display:flex;flex-direction:column;gap:4px">
          <div style="display:flex;justify-content:space-between"><span class="muted-sm">Annual billing</span><b>${naira(p.annualPrice)}</b></div>
          <div style="display:flex;justify-content:space-between"><span class="muted-sm">Monthly billing</span><b>${naira(p.monthlyPrice||0)}</b></div>
          <div style="display:flex;justify-content:space-between"><span class="muted-sm">One-time setup fee</span><b>${naira(p.setupFee||0)}</b></div>
          <div style="display:flex;justify-content:space-between"><span class="muted-sm">Support SLA</span><b>${ents.support.tier} (${ents.support.slaHours}h)</b></div>
        </div>
        <div class="muted-sm" style="margin-top:8px;font-size:11px">${count} active subscription${count===1?'':'s'}</div>
      </div>`;
  }).join('');

  const addOnRows = addOns.map(a => {
    const plans_str = a.applicablePlans.map(c=>{
      const pl = plans.find(p=>p.code===c);
      return pl ? `<span class="pill-soft" style="font-size:10px">${pl.name}</span>` : '';
    }).join(' ');
    const price = a.pricePerYear != null
      ? naira(a.pricePerYear) + '/yr'
      : a.pricePerUnit != null
        ? `${naira(a.pricePerUnit)} ${a.unit}`
        : '—';
    return `<tr>
      <td><b>${esc(a.name)}</b><div class="muted-sm" style="font-size:11px">${esc(a.description)}</div></td>
      <td>${plans_str}</td>
      <td style="white-space:nowrap;font-weight:600">${price}</td>
    </tr>`;
  }).join('');

  root.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title">Pricing plans</div>
        <div class="page-subtitle">${plans.length} plans · annual and monthly billing · all prices in NGN</div>
      </div>
    </div>

    <div style="display:grid;grid-template-columns:repeat(${plans.length},1fr);gap:14px;margin-bottom:24px">
      ${planCards}
    </div>

    <div class="card" style="margin-bottom:24px">
      <div class="card-section-title">Module access matrix</div>
      <div style="overflow-x:auto">
        <table class="table" style="font-size:12px">
          <thead><tr><th>Module / Feature</th>${planHeaders}</tr></thead>
          <tbody>${matrixRows}</tbody>
        </table>
      </div>
    </div>

    <div class="card">
      <div class="card-section-title">Add-on fees</div>
      <div class="muted-sm" style="margin-bottom:10px">Purchased on top of the base plan. Billing is handled through Paystack at the time of order.</div>
      <table class="table" style="font-size:12px">
        <thead><tr><th>Add-on</th><th>Applies to</th><th>Price</th></tr></thead>
        <tbody>${addOnRows}</tbody>
      </table>
    </div>
  `;
}

