// Direct sign-in using Supabase Auth REST API — no SDK, no modules.
// Works the moment the page loads because it is just a fetch() call.
async function onbSignInDirect(){
  const email    = (document.getElementById('onb-signin-email')    || {}).value || '';
  const password = (document.getElementById('onb-signin-password') || {}).value || '';
  const errDiv   = document.getElementById('onb-signin-error');
  const btn      = document.getElementById('onb-signin-btn');

  if(!email || !password){
    if(errDiv){ errDiv.style.display='block'; errDiv.textContent='Please enter your email and password.'; }
    return;
  }

  const cfg = window.LABOS_CONFIG || {};
  if(!cfg.supabaseUrl || !cfg.supabaseAnonKey){
    // No backend — go straight to demo platform view
    S().isPlatformAdmin = true;
    S().userName = 'Platform Admin';
    S().isDemoSession = false;
    enterPlatformMode();
    return;
  }

  if(btn){ btn.textContent = 'Signing in…'; btn.disabled = true; }
  if(errDiv) errDiv.style.display = 'none';

  try {
    // Step 1: Authenticate with Supabase Auth REST API directly
    const authRes = await fetch(cfg.supabaseUrl + '/auth/v1/token?grant_type=password', {
      method: 'POST',
      headers: {
        'Content-Type':  'application/json',
        'apikey':        cfg.supabaseAnonKey,
        'Authorization': 'Bearer ' + cfg.supabaseAnonKey
      },
      body: JSON.stringify({ email: email, password: password })
    });

    const authData = await authRes.json();

    if(!authRes.ok || authData.error){
      if(btn){ btn.textContent = 'Sign in →'; btn.disabled = false; }
      if(errDiv){
        errDiv.style.display = 'block';
        errDiv.textContent = authData.error_description || authData.error || 'Invalid email or password.';
      }
      return;
    }

    const accessToken  = authData.access_token;
    const refreshToken = authData.refresh_token;
    const userId       = authData.user && authData.user.id;

    // Step 2: Load the user's profile (tenant + role) from app_users
    const profRes = await fetch(
      cfg.supabaseUrl + '/rest/v1/app_users?id=eq.' + userId + '&select=*&limit=1', {
      headers: {
        'apikey':        cfg.supabaseAnonKey,
        'Authorization': 'Bearer ' + accessToken,
        'Accept':        'application/json'
      }
    });

    const profRows = await profRes.json();
    const profile  = Array.isArray(profRows) ? profRows[0] : null;

    // Step 3: Store the session for future API calls
    cfg.accessToken  = accessToken;
    cfg.refreshToken = refreshToken;
    cfg.userId       = userId;
    if(profile && profile.tenant_id) cfg.tenantId = profile.tenant_id;

    // Also update LabOSApi if the adapter is loaded
    if(window.LabOSSupabase && window.LabOSSupabase.init){
      window.LabOSSupabase.init().then(function(c){
        if(c && c.auth && c.auth.setSession){
          c.auth.setSession({ access_token: accessToken, refresh_token: refreshToken });
        }
      }).catch(function(){});
    }

    // Step 4: Route based on role
    const isPlat   = profile && profile.is_platform;
    const role     = (profile && profile.role) || 'TENANT_ADMIN';
    const tenantId = profile && profile.tenant_id;
    const name     = (profile && profile.full_name) || email;

    // Always set the real Supabase user ID — never leave a stale demo ID
    // (e.g. 'usr_lab_dir') behind from a previous demo or platform session.
    S().userId        = userId;
    S().userName       = name;
    S().userRole        = role;
    S().isDemoSession   = false;
    // Explicitly set isPlatformAdmin both ways — switching between a real
    // platform account and a real tenant account in the same browser
    // session must not leak the previous session's admin flag.
    S().isPlatformAdmin = !!isPlat;

    if(isPlat){
      enterPlatformMode();
      toast('Welcome back, ' + name + '. Signed in as platform administrator.', {type:'success', duration:4000});
    } else if(tenantId){
      enterTenantMode(tenantId);
      toast('Welcome back, ' + name + '.', {type:'success', duration:3500});
    } else {
      if(btn){ btn.textContent = 'Sign in →'; btn.disabled = false; }
      if(errDiv){ errDiv.style.display='block'; errDiv.textContent='Account exists but no laboratory is assigned. Contact your administrator.'; }
    }

  } catch(err){
    if(btn){ btn.textContent = 'Sign in →'; btn.disabled = false; }
    if(errDiv){ errDiv.style.display='block'; errDiv.textContent='Connection failed. Check your internet and try again.'; }
  }
}

function onbAdminSignIn(){
  // Legacy function — now handled by the inline form above.
  // Kept for backward compatibility.
  const cfg = window.LABOS_CONFIG || {};
  if(cfg.supabaseUrl && cfg.supabaseAnonKey){
    // Focus the email field on the inline sign-in form
    const el = document.getElementById('onb-signin-email');
    if(el){ el.focus(); }
    return;
  }
  S().isPlatformAdmin = true;
  S().userName = S().userName && S().userName !== 'Demo User' ? S().userName : 'Platform Admin';
  S().isDemoSession = false;
  enterPlatformMode();
}

function onbNext(){
  onbCollect();
  // Step 1 cannot advance until the invite-only activation has succeeded.
  if(ONB_STATE.step === 1 && !ONB_STATE.activated){
    ONB_STATE.activationError = 'Verify your activation code first, or choose “Explore the interactive demo”.';
    renderOnboarding();
    return;
  }
  // Validate the current step's fields before advancing.
  const e = onbValidateStep(ONB_STATE.step);
  ONB_STATE.errors = e;
  if(Object.keys(e).length){ renderOnboarding(); return; }
  if(ONB_STATE.step < 8){ ONB_STATE.step++; renderOnboarding(); }
}
function onbBack(){
  onbCollect();
  ONB_STATE.errors = {};
  if(ONB_STATE.step > 1){ ONB_STATE.step--; renderOnboarding(); }
}

function completeOnboarding(){
  const d = ONB_STATE.draft;
  // Invite-only: only an activated session may finish onboarding into a real
  // tenant. (Demo sessions enter via onbExploreDemo and never reach here.)
  if(!ONB_STATE.activated || !ONB_STATE.activatedTenantId){
    ONB_STATE.step = 1;
    ONB_STATE.activationError = 'Your session is not activated. Enter your activation code to continue.';
    renderOnboarding();
    return;
  }

  const tenantId = ONB_STATE.activatedTenantId;
  const tenant = APP_STATE.tenants.find(t => t.id === tenantId);
  if(!tenant){
    // Provisioned tenant vanished (shouldn't happen) — fail safe to the gate.
    ONB_STATE.step = 1;
    ONB_STATE.activated = false;
    ONB_STATE.activationError = 'Could not load your laboratory. Contact your administrator.';
    renderOnboarding();
    return;
  }

  // Apply the admin's confirmed details onto the provisioned tenant and mark
  // the one-time activation code as redeemed so it can't be reused.
  tenant.name = d.name || tenant.name;
  tenant.parentOrg = d.parentOrg || tenant.parentOrg;
  tenant.rcNumber = d.rcNumber || tenant.rcNumber;
  tenant.tin = d.tin || tenant.tin;
  tenant.accreditation = tenant.accreditation || {};
  if(d.mlscn) tenant.accreditation.mlscn = d.mlscn;
  if(d.iso15189) tenant.accreditation.iso15189 = d.iso15189;
  if(d.description) tenant.description = d.description;
  if(d.website) tenant.website = d.website;
  if(d.officialEmail) tenant.officialEmail = d.officialEmail;
  if(d.logoMark) tenant.logoMark = d.logoMark;
  if(d.primaryColour) tenant.primaryColour = d.primaryColour;
  if(d.plan) tenant.plan = d.plan;

  // Ensure the provisioned tenant has at least the head-office centre.
  if(!tenantCentres(tenantId).length){
    APP_STATE.centres.push({
      id:'ctr_new_'+Math.random().toString(36).slice(2,7), tenantId, code:d.centreCode||'HQ',
      name:d.centreName||'Head Office', address:d.centreAddress, phone:d.centrePhone,
      manager:d.fullName, status:'active', isHQ:true
    });
  }

  if(typeof LicenseCore !== 'undefined' && LicenseCore.markActivationUsed){
    LicenseCore.markActivationUsed(tenantId);
  }

  S().activeTenantId = tenantId;
  S().activeCentreId = (tenantCentres(tenantId)[0] || {}).id || null;
  S().userName = d.fullName || 'Lab Director';
  S().userRole = 'TENANT_ADMIN';
  S().isDemoSession = false;
  enterTenantMode(tenantId);
}

/* ==========================================================
   DEMO / REAL DATA MODE
   ----------------------------------------------------------
   When LabOS first runs, APP_STATE is seeded with rich demo
   transactional data (patients, requests, samples, etc.) so
   evaluators can explore the app immediately. A real laboratory
   going into production needs a way to clear that demo data
   while keeping the catalogues, plans, tenants, and prices.
   This module:
   - Snapshots the initial seed once, before any user mutation
   - Exposes clearDemoData() and restoreDemoData()
   - Persists APP_STATE.dataMode = 'demo' | 'real'
   ========================================================== */
